// Human-readable short labels for note names shown on-screen. Strips the octave
// number and renders sharps/flats as glyphs for a cleaner look.
function noteDisplayLabel(note) {
  const m = note.match(/^([A-G])([#b]?)\d$/);
  if (!m) return note;
  return m[1] + (m[2] === "#" ? "♯" : m[2] === "b" ? "♭" : "");
}

// Words that should always render with proper-noun capitalization on cards.
// Curriculum stores everything lowercase ("usa", "canada", "japan") for
// uniform downstream processing, but on the actual card display, country
// names and proper nouns should look correct ("USA", "Canada", "Japan").
// Special cases:
//   - usa → "USA" (all caps acronym)
//   - uk  → "UK"  (acronym)
//   - mlk → "MLK" (acronym, knowledge card)
// Everything else gets Title Case (first letter uppercase).
const ALL_CAPS_WORDS = new Set([
  "usa","uk","mlk","tv","suv",
]);
// Words that shouldn't be capitalized (common nouns that just happen to live
// in country sets, etc.). Currently empty — nothing to exclude.
const TITLE_CASE_WORDS = new Set([
  // North America (M3 Set 9)
  "usa","canada","mexico","cuba","guatemala",
  // Asia flags (knowledge M1 Set 7)
  "japan","china","korea","india","vietnam",
  // European countries (knowledge M1 Set 2)
  "italy","france","germany","spain",
  // South America (knowledge M2 Set 6)
  "brazil","argentina",
  // People — proper names
  "cleopatra","gandhi","mandela","einstein","mlk",
  // Superheroes (treat as proper nouns/character names)
  "superman","spiderman","batman","hulk","wonderwoman",
  "captainamerica","thor","blackwidow","ironman","flash",
  // Cities, regions, parks
  "europe","asia","africa",
]);

function displayCardWord(word) {
  if (!word || typeof word !== "string") return word;
  // If already has uppercase letters, trust the curriculum's choice
  if (/[A-Z]/.test(word)) return word;
  const lower = word.toLowerCase();
  if (ALL_CAPS_WORDS.has(lower)) return word.toUpperCase();
  if (TITLE_CASE_WORDS.has(lower)) {
    return word.charAt(0).toUpperCase() + word.slice(1);
  }
  return word;
}

// ── SCRIPT-AWARE FONT SELECTION ────────────────────────────────────────
// The Fredoka One / Baloo 2 fonts only have Latin glyphs. For non-Latin
// scripts (Cyrillic, Arabic, CJK, Devanagari, Thai, etc.), the browser
// falls through to the next font in the stack. The previous fallback
// chain ended in `cursive`, which on Cyrillic and other scripts caused
// the OS to substitute a script-style cursive font (terrible for kids
// learning to recognize letters). Now we detect the script of the
// displayed text and pick an appropriate sans-serif fallback per script.
function fontStackForText(text) {
  if (!text || typeof text !== "string") {
    return "'Fredoka One','Baloo 2',system-ui,sans-serif";
  }
  // Latin / extended Latin → use the playful display font
  // We test if the text contains *only* Latin and common punctuation
  if (/^[\u0020-\u024F\u1E00-\u1EFF\s\d.,!?'"()\-–—:;]*$/.test(text)) {
    return "'Fredoka One','Baloo 2',system-ui,sans-serif";
  }
  // CJK (Chinese, Japanese, Korean) — use system CJK fonts
  if (/[\u3040-\u30FF\u4E00-\u9FFF\u3400-\u4DBF\uAC00-\uD7AF]/.test(text)) {
    return "'PingFang SC','Hiragino Sans GB','Microsoft YaHei','Noto Sans CJK','Noto Sans SC',system-ui,sans-serif";
  }
  // Arabic / Hebrew / Persian / Urdu
  if (/[\u0590-\u06FF\u0750-\u077F]/.test(text)) {
    return "'SF Arabic','Geeza Pro','Tahoma','Arial Unicode MS',system-ui,sans-serif";
  }
  // Devanagari (Hindi, Marathi, Sanskrit, Nepali)
  if (/[\u0900-\u097F]/.test(text)) {
    return "'Noto Sans Devanagari','Mangal','Kohinoor Devanagari',system-ui,sans-serif";
  }
  // Bengali
  if (/[\u0980-\u09FF]/.test(text)) {
    return "'Noto Sans Bengali','Bangla MN','Vrinda',system-ui,sans-serif";
  }
  // Tamil
  if (/[\u0B80-\u0BFF]/.test(text)) {
    return "'Noto Sans Tamil','Tamil MN','Latha',system-ui,sans-serif";
  }
  // Thai
  if (/[\u0E00-\u0E7F]/.test(text)) {
    return "'Noto Sans Thai','Thonburi','Leelawadee',system-ui,sans-serif";
  }
  // Lao
  if (/[\u0E80-\u0EFF]/.test(text)) {
    return "'Noto Sans Lao','Lao MN',system-ui,sans-serif";
  }
  // Cyrillic (Russian, Ukrainian, Bulgarian, Serbian, etc.)
  if (/[\u0400-\u04FF]/.test(text)) {
    return "'Nunito','Roboto','Helvetica Neue',system-ui,sans-serif";
  }
  // Greek
  if (/[\u0370-\u03FF]/.test(text)) {
    return "'Nunito','Roboto','Helvetica Neue',system-ui,sans-serif";
  }
  // Default: solid sans-serif for any script we don't specifically handle
  return "'Nunito','Roboto','Helvetica Neue',system-ui,sans-serif";
}

// Note color associations — 12 distinct colors, one per pitch class (chromatic
// scale). Per Olivia's pedagogy: she's been teaching the twins these specific
// colors since birth. Sharps/flats share colors across enharmonic equivalents
// (C# and Db are the same color, etc.).
const NOTE_COLORS = {
  "C":  "#F62A3C",
  "C#": "#FFB979",  "Db": "#FFB979",
  "D":  "#FF7A00",
  "D#": "#FFED8F",  "Eb": "#FFED8F",
  "E":  "#FFD600",
  "F":  "#81C995",
  "F#": "#83FFD0",  "Gb": "#83FFD0",
  "G":  "#AECBFA",
  "G#": "#186EFF",  "Ab": "#186EFF",
  "A":  "#C4A5EA",
  "A#": "#9C39F4",  "Bb": "#9C39F4",
  "B":  "#FF85C8",
};
function noteColor(note) {
  const m = (note || "").match(/^([A-G])([#b]?)/);
  if (!m) return "#111";
  const key = m[1] + m[2];
  return NOTE_COLORS[key] || "#111";
}

// Staff position mapping: returns the y-position (in "step units") of a note
// on a treble or bass clef staff. 0 = the line/space the note sits on,
// counting upward. Uses standard music notation:
//   Treble staff: lines (bottom to top) E4 G4 B4 D5 F5; spaces F4 A4 C5 E5
//   Bass staff:   lines (bottom to top) G2 B2 D3 F3 A3; spaces A2 C3 E3 G3
// We choose treble for notes from middle C (C4) and up, bass for B3 and down.
// Returns { clef: "treble"|"bass", step: number, hasLedger: bool, isAccidental: bool }.
function noteStaffPosition(note) {
  const m = note.match(/^([A-G])([#b]?)(-?\d)$/);
  if (!m) return null;
  const letter = m[1];
  const acc = m[2];
  const octave = parseInt(m[3], 10);
  const isAccidental = acc !== "";
  // Diatonic step from C0 (where C0 = 0, D0 = 1, ..., B0 = 6)
  const letterStep = { C:0, D:1, E:2, F:3, G:4, A:5, B:6 };
  const totalStep = octave * 7 + letterStep[letter];
  // Pick clef: treble for C4 and above, bass for B3 and below
  const isTreble = totalStep >= 4 * 7; // C4 and up
  // Reference note step for each clef:
  //   Treble: bottom line is E4 → totalStep = 4*7 + 2 = 30. Each "step" up = +1.
  //   Bass:   bottom line is G2 → totalStep = 2*7 + 4 = 18.
  const refStep = isTreble ? 30 : 18;
  const stepFromBottom = totalStep - refStep;
  return {
    clef: isTreble ? "treble" : "bass",
    step: stepFromBottom,
    isAccidental,
    accidental: acc, // "#" or "b" or ""
  };
}

// ── CLEF GLYPHS ─────────────────────────────────────────────────────────
// Simplified but properly-anchored SVG clefs. Each takes the y-coordinate
// of its anchor line in the parent staff's coordinate space.
//
// Treble (G clef): The spiral curl wraps the G line (y = gLineY).
// Bass (F clef):   The two dots straddle the F line (y = fLineY).
//
// These are NOT full engraving-quality clefs — they're stylized for kid
// readability, but anatomically correct: the curl/dots land on the right
// staff line, and the overall proportions match standard music notation.

function TrebleClef({ gLineY, color = "#222" }) {
  // The treble clef is anchored at x=8 so it sits in the leftmost part of
  // the staff (which is 5..95 in our viewBox). The G-line passes through
  // the inner spiral. We construct the clef from a few SVG path commands:
  //   1. A vertical "spine" line that extends from above the staff down
  //      below (this is the descender that loops below the bottom line)
  //   2. An outer curl/loop around the G line (the spiral wrap)
  //   3. A small inner spot/circle at the center of the spiral on the G line
  // Coordinates are picked relative to gLineY so the whole shape moves
  // correctly with whatever staff y-position we're given.
  const cx = 12;          // horizontal center of the spiral
  const r  = 6;           // radius of the spiral curl
  return (
    <g>
      {/* Outer curl — the big swooping shape of the clef. We approximate
          it with a single closed cubic bezier path that loops around the
          G line and tapers off above and below. */}
      <path
        d={`
          M ${cx} ${gLineY - 22}
          C ${cx + 8} ${gLineY - 18}, ${cx + 9} ${gLineY - 6}, ${cx} ${gLineY - 2}
          C ${cx - 8} ${gLineY + 2}, ${cx - 8} ${gLineY + 8}, ${cx - 1} ${gLineY + 9}
          C ${cx + 6} ${gLineY + 10}, ${cx + 8} ${gLineY + 4}, ${cx + 4} ${gLineY}
          C ${cx + 1} ${gLineY - 2}, ${cx - 2} ${gLineY - 1}, ${cx - 2} ${gLineY + 1}
        `}
        fill="none" stroke={color} strokeWidth={1.6} strokeLinecap="round"
      />
      {/* Lower descender + bottom hook — extends below the staff per
          engraving convention. */}
      <path
        d={`
          M ${cx + 1} ${gLineY + 9}
          C ${cx + 1} ${gLineY + 14}, ${cx - 2} ${gLineY + 18}, ${cx - 5} ${gLineY + 19}
          C ${cx - 8} ${gLineY + 20}, ${cx - 8} ${gLineY + 16}, ${cx - 5} ${gLineY + 16}
        `}
        fill="none" stroke={color} strokeWidth={1.4} strokeLinecap="round"
      />
      {/* Tiny center dot ON the G line — visual anchor point of the spiral. */}
      <circle cx={cx} cy={gLineY} r={1.2} fill={color}/>
    </g>
  );
}

function BassClef({ fLineY, color = "#222" }) {
  // Bass clef: a comma-shape body curving from above the F line down and
  // around, plus two dots straddling the F line (one above, one below).
  // The body's main curve passes through and wraps around the F line.
  const cx = 14;          // horizontal anchor of the clef body
  return (
    <g>
      {/* Comma-shape body — starts above the F line, curls down and to
          the right around the F line. */}
      <path
        d={`
          M ${cx - 4} ${fLineY - 9}
          C ${cx + 2} ${fLineY - 11}, ${cx + 10} ${fLineY - 7}, ${cx + 8} ${fLineY}
          C ${cx + 6} ${fLineY + 7}, ${cx} ${fLineY + 10}, ${cx - 6} ${fLineY + 10}
        `}
        fill="none" stroke={color} strokeWidth={2.2} strokeLinecap="round"
      />
      {/* Inner curve to give it more visual weight (looks like a small "hook") */}
      <path
        d={`
          M ${cx - 1} ${fLineY - 7}
          C ${cx + 3} ${fLineY - 6}, ${cx + 5} ${fLineY - 2}, ${cx + 3} ${fLineY + 2}
        `}
        fill="none" stroke={color} strokeWidth={1.4} strokeLinecap="round"
      />
      {/* Two dots straddling the F line. Top dot one half-step above (in the
          space above the F line), bottom dot one half-step below. */}
      <circle cx={cx + 12} cy={fLineY - 2.5} r={1.4} fill={color}/>
      <circle cx={cx + 12} cy={fLineY + 2.5} r={1.4} fill={color}/>
    </g>
  );
}

