// Resolve rhythm content for a child. Session 1 = patterns in order,
// sessions 2 and 3 = shuffled.
function getRhythmContent(child, language, sessionNum) {
  const lang = language || "English";
  const allPos = migratePosition(child?.position);
  const stageId = allPos[lang]?.rhythm || RHYTHM_STAGES[0].id;
  const stage = RHYTHM_STAGES.find(s => s.id === stageId) || RHYTHM_STAGES[0];
  const patterns = sessionNum === 1 ? stage.patterns : shuffle(stage.patterns);
  return { stageId: stage.id, stage, patterns, label: stage.label };
}

// Play a rhythm pattern by stepping through its notes at a given tempo.
// Uses a single-pitch tone (C4) so the DURATION is what differentiates the
// note values. Tempo default = 80 BPM (comfortable for baby-attention spans).
// Returns a function that cancels playback if called.
// Synthesize a clap sound for rhythm sessions. We use a clap (not a tone)
// because rhythm is about TIMING, not pitch — and starting kids off with a
// pitched tone for rhythm muddies the lesson (they associate "rhythm" with
// "high note"). Clap matches what every early-music method does in person:
// clap, stomp, tap. Synthesized via WebAudio so no asset to load — works
// offline, no extra HTTP, no caching headaches.
//
// A convincing clap is essentially a short noise burst with a fast attack
// and quick decay, bandpass-filtered around 1.5kHz to give it a "papery"
// character. We add a small low-pass post-filter to soften the harshness
// for baby ears (parents should be able to play this loud without it being
// piercing).
function playClap() {
  const ctx = getAudioCtx();
  if (!ctx) return;
  if (ctx.state === "suspended") { try { ctx.resume(); } catch {} }

  const schedule = () => {
    const start = ctx.currentTime + 0.02;
    const dur = 0.08; // 80ms — feels percussive, doesn't bleed into next beat

    // Generate a short buffer of white noise — buffer source is more reliable
    // on iOS than ScriptProcessorNode and avoids deprecation warnings.
    const sampleRate = ctx.sampleRate;
    const bufferLen = Math.floor(sampleRate * dur);
    const buffer = ctx.createBuffer(1, bufferLen, sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < bufferLen; i++) {
      // White noise with mild envelope baked in — falls off toward end
      const t = i / bufferLen;
      data[i] = (Math.random() * 2 - 1) * (1 - t * 0.7);
    }

    const noise = ctx.createBufferSource();
    noise.buffer = buffer;

    // Bandpass around 1.5kHz — gives the "papery / wooden" clap character
    // rather than a hiss or whoosh.
    const bp = ctx.createBiquadFilter();
    bp.type = "bandpass";
    bp.frequency.value = 1500;
    bp.Q.value = 1.2;

    // Soft low-pass roll-off above 5kHz — keeps it from being piercing
    // when played loud near a baby's ears.
    const lp = ctx.createBiquadFilter();
    lp.type = "lowpass";
    lp.frequency.value = 5000;
    lp.Q.value = 0.7;

    // Sharp envelope — instant attack, exponential decay. This is what makes
    // it sound percussive rather than like static noise.
    const gain = ctx.createGain();
    gain.gain.setValueAtTime(0.0001, start);
    gain.gain.linearRampToValueAtTime(0.55, start + 0.001);  // 1ms attack
    gain.gain.exponentialRampToValueAtTime(0.0001, start + dur);

    noise.connect(bp);
    bp.connect(lp);
    lp.connect(gain);
    gain.connect(ctx.destination);

    noise.start(start);
    noise.stop(start + dur + 0.05);
  };

  if (ctx.state === "running") {
    schedule();
  } else {
    setTimeout(schedule, 80);
  }
}

function playRhythm(pattern, bpm = 80) {
  const beatMs = 60000 / bpm;
  const timers = [];
  let delay = 0;
  const isTriplet = pattern.triplet;
  // In a triplet, 3 eighths fit in 2 eighths' worth of time (one beat).
  // So each triplet note is ~(beatMs / 3) instead of (beatMs / 2).
  for (const note of pattern.notes) {
    const meta = NOTE_TYPE_META[note.type];
    if (!meta) continue;
    const noteBeats = isTriplet ? (2 / 3) * meta.beats : meta.beats;
    const noteMs = noteBeats * beatMs;
    // For rests, don't play anything — just wait. For everything else, play
    // a clap on the downbeat. Rhythm is about WHEN the clap lands; sustain
    // is communicated visually by the note shape, not audibly.
    if (note.type !== "rest") {
      timers.push(setTimeout(() => { try { playClap(); } catch {} }, delay));
    }
    delay += noteMs;
  }
  return () => timers.forEach(t => clearTimeout(t));
}

const RED   = "#E8192C";
// Bundle version marker — printed at the bottom of Parent Profile so testers
// (and Olivia) can confirm they're running the latest build. Bump this every
// time we ship. Format: yyyy-mm-dd-HHMM (UTC-ish; we just want monotonic).
// If the user's screen shows an OLD version, the service worker is serving
// stale cache — the "Force refresh" button next to it clears the SW + reloads.
const BUILD_VERSION = "2026-05-05-1500 · speech-lang-fix+5day-music-ui+voice-diag";
const MODEL = "claude-sonnet-4-20250514";
const shuffle = (a) => [...a].sort(() => Math.random() - 0.5);
// Use local time, not UTC — otherwise late-evening sessions in negative-offset
// timezones (like Pacific) get filed to tomorrow's date and break streak.
const todayKey = () => {
  const d = new Date();
  const y = d.getFullYear();
  const m = String(d.getMonth() + 1).padStart(2, "0");
  const day = String(d.getDate()).padStart(2, "0");
  return `${y}-${m}-${day}`;
};

