// "Child-ish" / younger-sounding voice keywords (varies a lot per platform)
const YOUNG_VOICE_HINTS = ["junior","kid","child","young","girl","boy"];

// Voice quality tiers — we strongly prefer higher-quality voices to make
// Claude's speech output sound more like a real person. These keywords appear
// in voice names across Apple/Google/Microsoft platforms.
const PREMIUM_VOICE_HINTS = [
  "premium","enhanced","neural","natural","siri","online","wavenet","studio",
];

// iOS 17+ added a class of "personality" / "novelty" voices that LIE about
// their language: they list themselves under en-US but actually speak in many
// languages (with terrible pronunciation in non-English). Examples: Eddy, Flo,
// Grandma, Grandpa, Sandy, Reed, Rocko, Shelley, Jester. Apple also has a set
// of joke voices from older macOS days (Albert, Bahh, Bells, Boing, Bubbles,
// Cellos, Deranged, "Good News", "Bad News", Hysterical, Pipe Organ, Trinoids,
// Whisper, Zarvox) that we never want for a baby learning app.
//
// These names get a SEVERE penalty in voiceScore, so even if they appear
// before Audrey/Anna/Tingting in getVoices() output, the proper regional
// voice wins.
const AVOID_VOICE_HINTS = [
  // Low-quality legacy engines
  "compact","espeak","festival",
  // iOS 17+ novelty / personality voices that masquerade as multi-lingual
  "eddy","flo","grandma","grandpa","sandy","reed","rocko","shelley","jester",
  // Classic macOS joke voices
  "albert","bahh","bells","boing","bubbles","cellos","deranged","good news",
  "bad news","hysterical","pipe organ","trinoids","whisper","zarvox","ralph",
  "fred","junior","kathy","princess","bruce","agnes","vicki",
  // Note: "vicki" was previously in FEMALE_VOICE_HINTS as a positive signal,
  // but on iOS 17+ it's actually a low-quality novelty-tier voice. The penalty
  // here outweighs the female bonus, which is the right call for our use case.
];

function voiceScore(voice, targetLang, preferredAccent) {
  // Higher score = better match. We optimize for (1) correct language,
  // (2) high quality voice engine, (3) young female voice, (4) regional accent match
  let score = 0;
  const name = (voice.name || "").toLowerCase();
  const vlang = (voice.lang || "").toLowerCase();
  const tlang = targetLang.toLowerCase();

  // Language match is most important
  // Language match is most important.
  // Special case for Chinese: the BCP-47 codes wuu-CN (Wu/Shanghainese),
  // nan-TW (Min Nan/Teochew/Taiwanese), and yue-* (Cantonese) are technically
  // separate language tags from zh-*, but in practice no consumer device
  // ships voices under those tags — they're all under zh-CN, zh-HK, zh-TW.
  // So for the "rare" Chinese variants, we treat ANY zh-* voice as a valid
  // family match. The ACCENT_HINTS system still biases toward voices that
  // mention "shanghai"/"wu"/"toisan"/"teochew" in their name when available,
  // but the fallback ensures the user hears SOMETHING in Chinese rather
  // than getting "no voice found" and having the word render in English.
  const CHINESE_FAMILY_PREFIXES = ["zh", "wuu", "nan", "yue", "cmn"];
  const tlangPrefix = tlang.split("-")[0];
  const vlangPrefix = vlang.split("-")[0];
  const bothChinese = CHINESE_FAMILY_PREFIXES.includes(tlangPrefix) &&
                      CHINESE_FAMILY_PREFIXES.includes(vlangPrefix);

  if (vlang === tlang) score += 100;
  else if (vlangPrefix === tlangPrefix) score += 60;
  else if (bothChinese) score += 40; // family fallback — lower than direct match
  else return -1; // wrong language — disqualify

  // AVOID hints take priority over everything else: if the voice name matches
  // a novelty / character / low-quality voice, slam the score WAY down so it
  // never beats a real regional voice. We use word-boundary matching here so
  // "Eddy" doesn't accidentally match a substring of a real voice name.
  // The penalty (-500) is intentionally larger than any combination of other
  // bonuses (max ≈ 250) so AVOID is effectively a hard veto whenever a real
  // option exists. If only AVOID voices exist for this language, the highest-
  // scoring one still wins (better something than silence).
  for (const h of AVOID_VOICE_HINTS) {
    // Match as a whole word (avoids "eddy" hitting "freddy" etc.)
    const wordRe = new RegExp("(^|[^a-z])" + h.replace(/[.*+?^${}()|[\]\\]/g, "\\$&") + "([^a-z]|$)", "i");
    if (wordRe.test(name)) { score -= 500; break; }
  }

  // Quality tier — strongly preferred. Premium/Enhanced voices are the ones
  // the parent explicitly downloaded — we should always pick them over the
  // base/compact equivalents.
  if (PREMIUM_VOICE_HINTS.some(h => name.includes(h))) score += 60;

  // Gender preference: female strongly preferred
  const isFemale = FEMALE_VOICE_HINTS.some(h => name.includes(h));
  const isMale   = MALE_VOICE_HINTS.some(h => name.includes(h));
  if (isFemale) score += 50;
  else if (isMale) score -= 20;

  // Young-sounding bonus
  if (YOUNG_VOICE_HINTS.some(h => name.includes(h))) score += 15;

  // Regional accent hints (for Vietnamese North/South, Chinese dialects)
  if (preferredAccent) {
    for (const hint of preferredAccent) {
      if (name.includes(hint.toLowerCase())) score += 30;
    }
  }

  // Prefer locally-installed over server voices (more reliable)
  if (voice.localService) score += 5;

  return score;
}

// Regional accent preferences for picking the best matching voice
const ACCENT_HINTS = {
  "Vietnamese (Northern)": ["hanoi","north","bắc","northern"],
  "Vietnamese (Southern)": ["saigon","ho chi minh","south","nam","southern"],
  "Chinese (Shanghainese)": ["shanghai","wu","shanghainese"],
  "Chinese (Toisanese)":    ["toisan","taishan","toishan"],
  "Chinese (Teochew)":      ["teochew","chaoshan","chaozhou","chao-chou"],
};

// Manual voice overrides — when the heuristic picker chooses wrong (e.g. a
// novelty voice we missed in AVOID_VOICE_HINTS), the user can pin a specific
// voice for a language via the Audio Test panel. Storage shape:
//   { [language]: voiceName }
// We match by name (not URI/voiceURI) because Apple's voice URIs change with
// downloads, but the name is stable.
function getVoiceOverrides() {
  try {
    const raw = localStorage.getItem("lb-voice-overrides");
    if (!raw) return {};
    const parsed = JSON.parse(raw);
    return (parsed && typeof parsed === "object") ? parsed : {};
  } catch { return {}; }
}

function setVoiceOverride(language, voiceName) {
  try {
    const overrides = getVoiceOverrides();
    if (voiceName) overrides[language] = voiceName;
    else delete overrides[language];
    localStorage.setItem("lb-voice-overrides", JSON.stringify(overrides));
  } catch {}
}

function pickBestVoice(voices, targetLang, language) {
  if (!voices || !voices.length) return null;
  // Honor manual override first — if the user has explicitly pinned a voice
  // for this language, use it (and don't second-guess them via scoring).
  // Match by name (case-insensitive prefix is fine since overrides are
  // populated from voices.name itself).
  if (language) {
    try {
      const overrides = getVoiceOverrides();
      const pinned = overrides[language];
      if (pinned) {
        const match = voices.find(v => v.name === pinned);
        if (match) return match;
      }
    } catch {}
  }
  // Otherwise use the heuristic scorer
  const accentHints = ACCENT_HINTS[language] || null;
  let best = null;
  let bestScore = -1;
  for (const v of voices) {
    const s = voiceScore(v, targetLang, accentHints);
    if (s > bestScore) { best = v; bestScore = s; }
  }
  return bestScore >= 0 ? best : null;
}

function speak(text, language) {
  if (!text || !window.speechSynthesis) return;
  try {
    window.speechSynthesis.cancel();
    // Look up the BCP-47 code for this curriculum language.
    // Critical: don't silently fall through to "en-US" for languages we
    // don't recognize — that would let pickBestVoice find an English voice
    // and read the foreign-language text in an English accent (which has
    // been the long-standing bug for Hawaiian/Khmer/Kazakh/etc).
    // Unknown language → bail rather than mispronounce.
    const targetLang = SPEECH_LANG[language];
    if (!targetLang) {
      if (language !== "English") return;
      // English fallback only when language is genuinely "English"
      // — other code paths set language deliberately, so this branch
      // exists for legacy callers that pass undefined/null/"".
    }
    const useLang = targetLang || "en-US";
    const utter = new SpeechSynthesisUtterance(text);
    utter.lang = useLang;

    // Infant-directed speech ("motherese"): slower rate, higher pitch,
    // warmer/brighter sound. Research shows babies are most responsive to these.
    utter.rate  = 0.78; // slower than normal — easier for babies to parse
    utter.pitch = 1.35; // higher pitch — signals warmth and friendliness
    utter.volume = 1.0;

    const voices = window.speechSynthesis.getVoices();
    if (voices.length > 0) {
      const match = pickBestVoice(voices, useLang, language);
      if (match) utter.voice = match;
      else if (language !== "English") return; // skip rather than mispronounce
    }

    window.speechSynthesis.speak(utter);
  } catch {}
}

// Warm up voices list on some browsers (Chrome/Safari load async)
if (typeof window !== "undefined" && window.speechSynthesis) {
  window.speechSynthesis.onvoiceschanged = () => window.speechSynthesis.getVoices();
}

// ── DOTS ─────────────────────────────────────────────────────────────────────

function dotR(n) {
  return n>80?5 : n>60?6 : n>40?7 : n>20?9 : n>10?12 : n>5?15 : 19;
}

function scatterDots(count, W=300, H=300) {
  if (!count) return [];
  const r = dotR(count);
  if (count > 35) {
    const cols = Math.ceil(Math.sqrt(count*(W/H)));
    const rows = Math.ceil(count/cols);
    const cW=W/cols, cH=H/rows, pts=[];
    let n=0;
    for (let row=0; row<rows && n<count; row++)
      for (let col=0; col<cols && n<count; col++) {
        pts.push({
          x: Math.max(r+2, Math.min(W-r-2, (col+.5)*cW + (Math.random()-.5)*cW*.55)),
          y: Math.max(r+2, Math.min(H-r-2, (row+.5)*cH + (Math.random()-.5)*cH*.55)),
        });
        n++;
      }
    return pts;
  }
  // Random placement with relaxing minimum distance: start with a generous
  // spacing, then if we can't fit all dots, reduce the spacing and try again.
  // This guarantees we always return exactly `count` dots, even when the
  // viewBox is small relative to the requested count.
  const margin = r + 4;
  const placeWithMinD = (minD) => {
    const placed = [];
    let att = 0;
    const maxAtt = count * 600;
    while (placed.length < count && att < maxAtt) {
      const x = margin + Math.random() * (W - margin * 2);
      const y = margin + Math.random() * (H - margin * 2);
      if (!placed.some(p => Math.hypot(p.x - x, p.y - y) < minD)) placed.push({ x, y });
      att++;
    }
    return placed;
  };
  // Try with progressively smaller min-distance until we fit all dots.
  for (const ratio of [2.7, 2.4, 2.1, 1.8, 1.5, 1.2, 1.0]) {
    const minD = r * ratio;
    const placed = placeWithMinD(minD);
    if (placed.length >= count) return placed.slice(0, count);
  }
  // Last resort: place on a regular grid (guaranteed to fit). This branch
  // should only run for pathologically small viewBoxes; we still want the
  // baby to see the right number of dots.
  const cols = Math.ceil(Math.sqrt(count));
  const rows = Math.ceil(count / cols);
  const cW = W / cols, cH = H / rows, pts = [];
  let n = 0;
  for (let row = 0; row < rows && n < count; row++)
    for (let col = 0; col < cols && n < count; col++) {
      pts.push({ x: (col + .5) * cW, y: (row + .5) * cH });
      n++;
    }
  return pts;
}

function ScatteredDots({ count, size=300 }) {
  const pts = useMemo(()=>scatterDots(count,size,size),[count]); // eslint-disable-line
  const r   = dotR(count);
  return (
    <svg viewBox={`0 0 ${size} ${size}`} style={{width:`min(${size}px,85vw)`,height:`min(${size}px,85vw)`}}>
      {pts.map((p,i)=><circle key={i} cx={p.x} cy={p.y} r={r} fill={RED} opacity=".92"/>)}
    </svg>
  );
}

function MiniDots({ count, size=100 }) {
  const pts = useMemo(()=>scatterDots(count,size,size),[count]); // eslint-disable-line
  const r   = Math.max(3,dotR(count)*.7);
  return (
    <svg viewBox={`0 0 ${size} ${size}`} style={{width:size,height:size}}>
      {pts.map((p,i)=><circle key={i} cx={p.x} cy={p.y} r={r} fill={RED}/>)}
    </svg>
  );
}

// ── EQUATIONS ─────────────────────────────────────────────────────────────────

// Generate 11 equations for a given stage, on a given day.
// Difficulty scales with how long the child has been on this stage.
// Per Olivia's revision (May 2026): 3 equations per session, repeated 3
// sessions per day, then a fresh 3 equations the next day. This matches
// Doman's tight-set repetition rhythm. We use a deterministic seed based
// on (stageId, dayNum) so all 3 daily sessions surface the same 3
// equations in the same content.
function genEquations(stageId, dayNum) {
  const stage = MATH_STAGES.find(s => s.id === stageId);
  if (!stage || !stage.isEq) return [];

  // How many days into this stage is the child? This scales difficulty.
  const daysIntoStage = Math.max(0, dayNum - stage.unlockDay);
  // Cap the max operand to keep things baby-friendly in early days.
  // Dot equations stay small (visual cards can't hold too many dots);
  // numeral equations can go higher.
  const isDotEq = stage.showDots && !stage.showNumerals;
  const maxOperand = isDotEq
    ? Math.min(9, 3 + Math.floor(daysIntoStage / 3))
    : Math.min(20, 5 + Math.floor(daysIntoStage / 2));

  // Deterministic PRNG (mulberry32) seeded by stage+day so the 3 daily
  // sessions get the same 3 equations. Without this, Math.random produces
  // different equations each session — defeating the "same set repeated"
  // pedagogy.
  const seed = (stage.unlockDay * 31337) ^ (dayNum * 2654435761) ^
               [...stageId].reduce((a, c) => (a * 31 + c.charCodeAt(0)) >>> 0, 0);
  let s = seed >>> 0;
  const rng = () => {
    s = (s + 0x6D2B79F5) >>> 0;
    let t = s;
    t = Math.imul(t ^ (t >>> 15), t | 1);
    t ^= t + Math.imul(t ^ (t >>> 7), t | 61);
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };

  const out = [];
  for (let i = 0; i < 3; i++) {
    let a, b, result, op;
    if (stage.op === "mix") {
      const ops = ["+","-","×","÷"];
      op = ops[Math.floor(rng() * ops.length)];
    } else {
      op = stage.op;
    }
    if (op === "+") {
      a = Math.floor(rng() * maxOperand) + 1;
      b = Math.floor(rng() * maxOperand) + 1;
      result = a + b;
    } else if (op === "-") {
      a = Math.floor(rng() * maxOperand) + 1;
      b = Math.floor(rng() * a) + 1; // keep result positive
      result = a - b;
    } else if (op === "×") {
      const mm = Math.min(5, Math.max(2, Math.ceil(maxOperand / 2)));
      a = Math.floor(rng() * mm) + 1;
      b = Math.floor(rng() * mm) + 1;
      result = a * b;
    } else if (op === "÷") {
      const mm = Math.min(5, Math.max(2, Math.ceil(maxOperand / 2)));
      result = Math.floor(rng() * mm) + 1;
      b = Math.floor(rng() * mm) + 1;
      a = result * b;
    }
    out.push({ op, a, b, result });
  }
  return out;
}

// ── MATH POSITION HELPERS (Apr 2026) ─────────────────────────────────────
// The per-language math position can be one of two shapes:
//   1. A bare string: "dots" (legacy; the child's day-window is derived from
//      their absolute day count in this language)
//   2. An object: { stageId: "dots", offsetDay: 26 } (granular; pins the
//      child to a specific day within the stage, e.g. window 50-60)
//
// Helpers below normalize either format. Parents use the granular form when
// they explicitly tell the app "my baby is on Dots day 26" via the level
// picker. Otherwise the legacy day-driven form keeps progressing naturally.
function getMathStageId(pos) {
  if (!pos) return null;
  if (typeof pos === "string") return pos;
  if (typeof pos === "object" && pos.stageId) return pos.stageId;
  return null;
}
function getMathOffsetDay(pos) {
  if (!pos || typeof pos !== "object") return null;
  if (pos.offsetDay && pos.offsetDay >= 1) return pos.offsetDay;
  return null;
}
// Resolve the actual dayNum to use for math windows. If the parent has set
// a granular offsetDay for the current stage, use that. Otherwise compute
// from absolute day. This way switching to a granular position immediately
// snaps the child to that window without affecting other categories.
function resolveMathDayNum(absoluteDayNum, mathPos) {
  const stageId = getMathStageId(mathPos);
  const offsetDay = getMathOffsetDay(mathPos);
  if (stageId && offsetDay) {
    const stage = MATH_STAGES.find(s => s.id === stageId);
    if (stage) return stage.unlockDay + offsetDay - 1;
  }
  return absoluteDayNum;
}

// Doman rolling window: start 0-10, each day drop 2 lowest and add 2 higher.
// Day 1: 0-10  (11 numbers)
// Day 1: 0-10 (11 numbers)
// Day 2: 2-12 (11 numbers)
// Day 3: 4-14 ... and so on.
// Caps at the hundreds so the baby progresses to advanced counting.
function getDomanWindow(dayNum, stageId) {
  const stage = MATH_STAGES.find(s => s.id === stageId);
  const offsetDay = stage ? Math.max(1, dayNum - stage.unlockDay + 1) : dayNum;
  const lo = Math.max(0, (offsetDay - 1) * 2);
  const hi = lo + 10;
  const nums = [];
  for (let n = lo; n <= hi; n++) nums.push(n);
  return nums;
}

// One session = 11 cards. Session 1 is always in-order to help babies
// anchor the sequence. Sessions 2 and 3 are shuffled for variety.
//
// Equation stages: Per Olivia's pedagogy (Apr 2026), each equation displays
// as 5 separate cards instead of one combined card:
//   1. left operand (1)
//   2. operator symbol (+) — speaks "plus"
//   3. right operand (1) — speaks number
//   4. equals sign (=) — speaks "equals"
//   5. result (2) — speaks number
// This matches Doman's flashcard methodology: one concept per card so the
// baby can visually focus on each element. We expand the {op,a,b,result}
// objects into 5-card sequences with `eqPart` markers for the renderer.
function getMathCards(stageId, dayNum, sessionNum) {
  const stage = MATH_STAGES.find(s => s.id === stageId);
  if (!stage) return [];
  if (!stage.isEq) {
    const w = getDomanWindow(dayNum, stageId);
    const ordered = sessionNum === 1 ? w : shuffle(w);
    return ordered.map(n => ({ n }));
  }
  // Equation stages — keep the genEquations logic but optionally un-shuffle
  // for session 1 so the first daily session is pedagogically ordered.
  const eqs = genEquations(stageId, dayNum);
  let orderedEqs;
  if (sessionNum === 1) {
    // Sort by left-operand ascending to approximate "session 1 in order"
    orderedEqs = [...eqs].sort((a, b) => {
      const av = a.left ?? a.n ?? a.a ?? 0;
      const bv = b.left ?? b.n ?? b.a ?? 0;
      return av - bv;
    });
  } else {
    orderedEqs = eqs;
  }

  // Expand each equation into 5 cards. Each card gets:
  //   - `eqPart`: which slot in the 5-card sequence ("left"|"op"|"right"|"eq"|"result")
  //   - `eqIdx`:  which equation this is (0..N-1) — used for review, navigation
  //   - `op`:     the operator string ("+", "-", "×", "÷")
  //   - `n`:      the number to display (for left/right/result cards)
  //   - `symbol`: the symbol to display (for op/eq cards)
  const cards = [];
  orderedEqs.forEach((eq, eqIdx) => {
    cards.push({ eqPart: "left",   eqIdx, op: eq.op, n: eq.a });
    cards.push({ eqPart: "op",     eqIdx, op: eq.op, symbol: eq.op });
    cards.push({ eqPart: "right",  eqIdx, op: eq.op, n: eq.b });
    cards.push({ eqPart: "eq",     eqIdx, op: eq.op, symbol: "=" });
    cards.push({ eqPart: "result", eqIdx, op: eq.op, n: eq.result });
  });
  return cards;
}

// Get the day number based on when parent first opened the app.
// Stored in localStorage; increments each new calendar day they return.
function getDayNumber() {
  try {
    const key = "lb-day-start";
    let startStr = localStorage.getItem(key);
    if (!startStr) {
      localStorage.setItem(key, todayKey());
      return 1;
    }
    const start = new Date(startStr + "T00:00:00");
    const today = new Date(todayKey() + "T00:00:00");
    const days = Math.floor((today - start) / (1000 * 60 * 60 * 24)) + 1;
    return Math.max(1, days);
  } catch {
    return 1;
  }
}

// Get the day number FOR A SPECIFIC LANGUAGE for a given child. A child learns
// each language at its own pace — so when they switch to a language they've
// never used, it should show day 1, not the global day count.
// We scan the child's session history for the earliest session done in that
// language across any category, and count from there.
function getDayNumberForLanguage(childId, language) {
  try {
    if (!childId || !language) return 1;
    const hist = JSON.parse(localStorage.getItem(`lb-history-${childId}`) || "{}");
    let earliest = null;  // "YYYY-MM-DD" string
    for (const dateKey of Object.keys(hist)) {
      const day = hist[dateKey] || {};
      // keys look like "words:English", "couplets:Korean", etc.
      const hasThisLang = Object.keys(day).some(k => k.endsWith(`:${language}`));
      if (hasThisLang) {
        if (!earliest || dateKey < earliest) earliest = dateKey;
      }
    }
    if (!earliest) return 1;  // Never started this language — day 1
    const start = new Date(earliest + "T00:00:00");
    const today = new Date(todayKey() + "T00:00:00");
    const days = Math.floor((today - start) / (1000 * 60 * 60 * 24)) + 1;
    return Math.max(1, days);
  } catch {
    return 1;
  }
}

// ── CHILD PROFILES ───────────────────────────────────────────────────────────
// Each child has: id, name, emoji, languages (array), createdAt
// Stored in localStorage as "lb-children" — array of child objects.
// Also tracks "lb-active-child" = current child id.

function loadChildren() {
  try {
    const raw = localStorage.getItem("lb-children");
    if (!raw) return [];
    const kids = JSON.parse(raw);
    // ── Chinese language migration (Apr 2026) ─────────────────────────────
    // Pre-fork users had "Chinese (Cantonese)" and "Chinese (Mandarin)" in
    // their child.languages arrays, position keys, and history. Map them
    // to the new variant names so existing testers don't lose progress.
    // ── Chinese rename migration (May 2026) ───────────────────────────────
    // T/S suffixes were renamed to Traditional/Simplified for clarity.
    // ── Vietnamese consolidation (May 2026) ───────────────────────────────
    // Plain "Vietnamese" maps to Northern (the literary standard).
    const LEGACY_CN_MAP = {
      "Chinese (Cantonese)":  "Chinese (Cantonese-Traditional)",
      "Chinese (Mandarin)":   "Chinese (Mandarin-Simplified)",
      "Chinese (Cantonese-T)": "Chinese (Cantonese-Traditional)",
      "Chinese (Cantonese-S)": "Chinese (Cantonese-Simplified)",
      "Chinese (Mandarin-T)":  "Chinese (Mandarin-Traditional)",
      "Chinese (Mandarin-S)":  "Chinese (Mandarin-Simplified)",
      "Vietnamese":            "Vietnamese (Northern)",
      // Spanish was briefly split (Apr 2026) into 3 variants and then
      // collapsed back (May 2026). Map any existing variant entries back
      // to the single "Spanish" so existing testers keep their progress.
      "Spanish (Latin America)": "Spanish",
      "Spanish (Mexico)":        "Spanish",
    };
    let migratedAny = false;
    for (const child of kids) {
      // (a) Migrate child.languages array
      if (Array.isArray(child.languages)) {
        // Use a Set so if two old names map to the same new name (or the
        // new name is already in the list) we de-dup automatically.
        const seen = new Set();
        const newLangs = [];
        for (const l of child.languages) {
          const mapped = LEGACY_CN_MAP[l] || l;
          if (!seen.has(mapped)) { seen.add(mapped); newLangs.push(mapped); }
        }
        if (newLangs.length !== child.languages.length || newLangs.some((l, i) => l !== child.languages[i])) {
          child.languages = newLangs;
          migratedAny = true;
        }
      }
      // (b) Migrate position keys — if both old and new keys exist for the
      // same language (rare edge case), the new key wins (avoids overwriting
      // newer progress with stale legacy data).
      if (child.position && typeof child.position === "object") {
        for (const oldKey of Object.keys(LEGACY_CN_MAP)) {
          if (child.position[oldKey]) {
            const newKey = LEGACY_CN_MAP[oldKey];
            if (!child.position[newKey]) {
              child.position[newKey] = child.position[oldKey];
            }
            delete child.position[oldKey];
            migratedAny = true;
          }
        }
      }
      // (c) Migrate enrolledClasses — each class has an array of language
      // strings. Replace any old names and de-dup.
      if (child.enrolledClasses && typeof child.enrolledClasses === "object" && !Array.isArray(child.enrolledClasses)) {
        for (const cid of Object.keys(child.enrolledClasses)) {
          const arr = child.enrolledClasses[cid];
          if (!Array.isArray(arr)) continue;
          const seen = new Set();
          const next = [];
          let changed = false;
          for (const l of arr) {
            const mapped = LEGACY_CN_MAP[l] || l;
            if (mapped !== l) changed = true;
            if (!seen.has(mapped)) { seen.add(mapped); next.push(mapped); }
          }
          if (changed || next.length !== arr.length) {
            child.enrolledClasses[cid] = next;
            migratedAny = true;
          }
        }
      }
      // (d) Migrate history (lb-history-${childId}) — keys like "category:language"
      try {
        const histKey = `lb-history-${child.id}`;
        const histRaw = localStorage.getItem(histKey);
        if (histRaw) {
          const hist = JSON.parse(histRaw);
          let histChanged = false;
          for (const dateKey of Object.keys(hist)) {
            const day = hist[dateKey];
            if (!day || typeof day !== "object") continue;
            const newDay = {};
            for (const compositeKey of Object.keys(day)) {
              // compositeKey is "${category}:${language}"
              const colonIdx = compositeKey.indexOf(":");
              if (colonIdx < 0) { newDay[compositeKey] = day[compositeKey]; continue; }
              const cat = compositeKey.slice(0, colonIdx);
              const lang = compositeKey.slice(colonIdx + 1);
              const mappedLang = LEGACY_CN_MAP[lang] || lang;
              const newCompositeKey = `${cat}:${mappedLang}`;
              if (newCompositeKey !== compositeKey) histChanged = true;
              // Merge counts — if both old and new keys exist for the same
              // (category, language), sum them so we don't lose session
              // history during the rename.
              newDay[newCompositeKey] = (newDay[newCompositeKey] || 0) + day[compositeKey];
            }
            hist[dateKey] = newDay;
          }
          if (histChanged) {
            localStorage.setItem(histKey, JSON.stringify(hist));
            migratedAny = true;
          }
        }
      } catch {}
      // (e) Migrate session counts and set progress — these are top-level
      // localStorage keys with the language baked in. We scan all keys
      // matching the prefix and rename any with old language names.
      try {
        const prefixesToScan = [
          `lb-sess-${child.id}-`,         // daily session counts: lb-sess-{id}-{cat}-{lang}-{date}
          `lb-set-progress-${child.id}-`, // per-set counter:      lb-set-progress-{id}-{cat}-{lang}
        ];
        const renames = []; // [{ from, to, mergeStrategy }]
        for (let i = 0; i < localStorage.length; i++) {
          const k = localStorage.key(i);
          if (!k) continue;
          const matchedPrefix = prefixesToScan.find(p => k.startsWith(p));
          if (!matchedPrefix) continue;
          // The remainder after the prefix can contain any of the old language
          // names. Replace them.
          let newKey = k;
          for (const oldLang of Object.keys(LEGACY_CN_MAP)) {
            if (newKey.includes(oldLang)) {
              newKey = newKey.split(oldLang).join(LEGACY_CN_MAP[oldLang]);
            }
          }
          if (newKey !== k) renames.push({ from: k, to: newKey });
        }
        for (const { from, to } of renames) {
          const oldVal = localStorage.getItem(from);
          if (oldVal == null) continue;
          // For session-count keys, merge counts if both old and new exist
          // (to preserve sessions logged under the old name).
          if (from.startsWith(`lb-sess-${child.id}-`)) {
            try {
              const oldData = JSON.parse(oldVal);
              const existingNew = localStorage.getItem(to);
              const newData = existingNew ? JSON.parse(existingNew) : { count: 0, lastAt: 0 };
              const merged = {
                count: Math.min(MAX_SESSIONS_PER_DAY, (newData.count || 0) + (oldData.count || 0)),
                lastAt: Math.max(newData.lastAt || 0, oldData.lastAt || 0),
              };
              localStorage.setItem(to, JSON.stringify(merged));
            } catch {
              // Fallback: just take the old value if either parse fails
              localStorage.setItem(to, oldVal);
            }
          } else if (from.startsWith(`lb-set-progress-${child.id}-`)) {
            // Set progress is a single integer (0-2). Take the max of old and
            // new so we don't undo recent progress.
            const oldN = parseInt(oldVal, 10) || 0;
            const existingNew = localStorage.getItem(to);
            const newN = existingNew ? (parseInt(existingNew, 10) || 0) : 0;
            localStorage.setItem(to, String(Math.max(oldN, newN)));
          } else {
            // Generic: just rename, prefer new value if it exists
            if (!localStorage.getItem(to)) localStorage.setItem(to, oldVal);
          }
          localStorage.removeItem(from);
          migratedAny = true;
        }
      } catch {}
    }
    if (migratedAny) {
      try { localStorage.setItem("lb-children", JSON.stringify(kids)); } catch {}
    }
    return kids;
  } catch { return []; }
}

function saveChildren(children) {
  try { localStorage.setItem("lb-children", JSON.stringify(children)); } catch {}
}

// ── PREMIUM SUBSCRIPTION (MOCK) ──────────────────────────────────────────────
// Mock subscription state. In production this will be backed by App Store /
// Google Play purchase verification. For now it's a localStorage flag toggled
// ── PRICING + SUBSCRIPTION SYSTEM ─────────────────────────────────────────
// Unified pricing model (May 2026):
//   Monthly: $14.99 / month
//   Annual:  $119   / year  (33% savings — equivalent to ~$9.92/mo)
//   Twins/triplets add-on: +$5/mo on either plan
// All plans include a 14-day free trial — NO CARD REQUIRED to start.
// Trial converts to paid only when the parent enters payment info.
// Promo codes can grant indefinite premium (founder uses CAILIYA personally).

const PRICING = {
  monthly: { amount: 14.99, currency: "USD", interval: "month",
             label: "$14.99/month",  cents: 1499 },
  annual:  { amount: 119,   currency: "USD", interval: "year",
             label: "$119/year",     cents: 11900,
             savingsLabel: "save 33% — about $9.92/mo" },
  multiples_addon: { amount: 5, currency: "USD", interval: "month",
                     label: "+$5/month for twins, triplets, or more",
                     cents: 500 },
  trialDays: 14,
};

// Promo codes that unlock premium without payment.
// Codes are stored uppercase and compared case-insensitively.
//   CAILIYA   → founder personal test code (Olivia's twins: Callisto + Elara
//              telescoped into one phonetic name). Indefinite premium.
const PROMO_CODES = {
  CAILIYA:  { tier: "family", interval: "yearly", multiples: true,
              note: "founder", expiresAt: null /* never */ },
};

// Stored shape:
//   { tier: "single"|"family",
//     interval: "monthly"|"yearly"|"trial"|"promo",
//     at: timestamp,
//     trialEndsAt: timestamp | null,    // only set during trial
//     promoCode: string | null,          // set when entered via promo
//     multiples: boolean,                // twins/triplets add-on active
//     dev: boolean,                      // set by dev toggle
//   }
function getPremium() {
  try {
    const raw = localStorage.getItem("lb-premium");
    if (!raw) return null;
    return JSON.parse(raw);
  } catch { return null; }
}

function setPremium(plan) {
  try {
    if (plan === null) localStorage.removeItem("lb-premium");
    else localStorage.setItem("lb-premium", JSON.stringify(plan));
  } catch {}
}

// `isPremium` returns true if the parent has any active premium status —
// including an active trial or an active promo code. Once the trial ends and
// no payment is on file, this returns false and the upsell sheet appears.
function isPremium() {
  const p = getPremium();
  if (!p) return false;
  // Promo codes (indefinite) — always premium
  if (p.interval === "promo") return true;
  // Trials — only premium until trialEndsAt
  if (p.interval === "trial") {
    if (!p.trialEndsAt) return false;
    return Date.now() < p.trialEndsAt;
  }
  // Dev toggle — always premium for testing
  if (p.dev) return true;
  // Real paid subscription — premium if recorded (real provider sync TBD)
  if (p.interval === "monthly" || p.interval === "yearly") return true;
  return false;
}

// Returns true only if the user is currently on a 14-day trial, regardless of
// whether the trial has expired. Used to show the "trial ends in N days" UI.
function isOnTrial() {
  const p = getPremium();
  return !!(p && p.interval === "trial");
}

// Returns days remaining on the trial, or 0 if not on trial / expired.
// Rounds UP so a trial with 23 hours left shows "1 day left" not "0".
function trialDaysRemaining() {
  const p = getPremium();
  if (!p || p.interval !== "trial" || !p.trialEndsAt) return 0;
  const ms = p.trialEndsAt - Date.now();
  if (ms <= 0) return 0;
  return Math.ceil(ms / (1000 * 60 * 60 * 24));
}

// Returns true if a trial was started AND has expired. Used to show the
// "your trial ended" upsell instead of the "start trial" prompt.
function isTrialExpired() {
  const p = getPremium();
  return !!(p && p.interval === "trial" && p.trialEndsAt && Date.now() >= p.trialEndsAt);
}

// Start a 14-day free trial. No card required. Sets trialEndsAt 14 days out.
// Idempotent — calling twice doesn't reset the clock (a user can't game it
// by toggling state). Returns the new premium object.
function startFreeTrial() {
  const existing = getPremium();
  // If they already have any active premium status, don't downgrade them
  if (existing && (existing.interval === "monthly" || existing.interval === "yearly" ||
                   existing.interval === "promo" || existing.dev)) {
    return existing;
  }
  // If they already started a trial (active or expired), don't restart it
  if (existing && existing.interval === "trial" && existing.trialEndsAt) {
    return existing;
  }
  const trialEndsAt = Date.now() + PRICING.trialDays * 24 * 60 * 60 * 1000;
  const plan = {
    tier: "family",
    interval: "trial",
    at: Date.now(),
    trialEndsAt,
    promoCode: null,
    multiples: false,
    dev: false,
  };
  setPremium(plan);
  try { localStorage.setItem("lb-trial-started", String(Date.now())); } catch {}
  return plan;
}

// Apply a promo code. Returns { ok, plan, error }.
//   - ok=true  → premium unlocked, plan is the new state
//   - ok=false → error has a user-facing message
function applyPromoCode(rawCode) {
  if (!rawCode || typeof rawCode !== "string") {
    return { ok: false, error: "Please enter a code." };
  }
  const code = rawCode.trim().toUpperCase();
  const def = PROMO_CODES[code];
  if (!def) {
    return { ok: false, error: "That code isn't valid. Double-check spelling." };
  }
  if (def.expiresAt && Date.now() > def.expiresAt) {
    return { ok: false, error: "This code has expired." };
  }
  const plan = {
    tier: def.tier || "family",
    interval: "promo",
    at: Date.now(),
    trialEndsAt: null,
    promoCode: code,
    multiples: !!def.multiples,
    dev: false,
  };
  setPremium(plan);
  return { ok: true, plan };
}

// Returns true if the parent has 2+ children — used to surface the
// twins/triplets add-on prompt automatically.
function hasMultipleChildren() {
  try {
    const kids = JSON.parse(localStorage.getItem("lb-children") || "[]");
    return Array.isArray(kids) && kids.length >= 2;
  } catch { return false; }
}

// Toggle the multiples add-on on the currently active subscription. Free
// while on trial / promo (we just flip the flag). When we wire the real
// payment provider, this is where we'd call updateSubscription.
function setMultiplesAddon(enabled) {
  const p = getPremium();
  if (!p) return false;
  p.multiples = !!enabled;
  setPremium(p);
  return true;
}

function getActiveChildId() {
  try { return localStorage.getItem("lb-active-child") || null; } catch { return null; }
}

// Parent's UI language preference — set once at first launch (before any child
// is created), used as the default for new child language picker. Independent
// from per-child language selection. Stored as a string matching one of the
// LANGUAGES values. Null means parent hasn't chosen yet (first launch).
function getParentLanguage() {
  try { return localStorage.getItem("lb-parent-lang") || null; } catch { return null; }
}
function setParentLanguage(lang) {
  try {
    if (lang) localStorage.setItem("lb-parent-lang", lang);
    else localStorage.removeItem("lb-parent-lang");
  } catch {}
  // Notify all components subscribed via useParentLang so the UI re-renders
  // in the new language without a page refresh.
  _setParentLangAndNotify(lang || "English");
}

function setActiveChildId(id) {
  try { localStorage.setItem("lb-active-child", id); } catch {}
}

function newChildId() {
  return "c_" + Date.now().toString(36) + Math.random().toString(36).slice(2,6);
}

// ── LEARNING POSITION ────────────────────────────────────────────────────────
// Parent-controlled: each child has a "position" indicating where they are in
// the curriculum PER LANGUAGE. Data shape:
//   child.position = {
//     English: { words:{month,setIdx}, couplets:null|{...}, sentences:null|{...}, knowledge:{...}, math:"dots" },
//     Korean:  { ... },
//     ...
//   }
// Children learn at different paces in different languages, so each language
// has its own level.
//
// Migration: older builds stored positions flat (no language key). On read we
// detect and wrap old data under "English" for backwards compat.

function migratePosition(raw) {
  // Returns the position object already keyed by language. Handles the old
  // flat format gracefully.
  if (!raw) return {};
  // Old format: has top-level "words" or "knowledge" or "math"
  const looksOld = raw.words !== undefined || raw.knowledge !== undefined ||
                   raw.couplets !== undefined || raw.sentences !== undefined ||
                   raw.math !== undefined;
  if (looksOld) return { English: raw };
  return raw;
}

function getChildPosition(child, category, language) {
  const lang = language || "English";
  const allPos = migratePosition(child?.position);
  const pos = allPos[lang]?.[category];
  if (pos !== undefined) return pos;
  // Defaults when language has no position set:
  //   words/knowledge → month 1 set 0
  //   couplets        → month 2 set 0 (couplets only exist in M2)
  //   sentences       → month 3 set 0 (sentences only exist in M3)
  //   math            → "dots"
  // Returning a default for couplets/sentences (rather than null) means once
  // their stage is unlocked by progress in single words, tapping into them
  // shows real content immediately — no extra setup step for the parent.
  if (category === "words" || category === "knowledge") return { month: 1, setIdx: 0 };
  if (category === "couplets")  return { month: 2, setIdx: 0 };
  if (category === "sentences") return { month: 3, setIdx: 0 };
  if (category === "math") return "dots";
  return null;
}

function setChildPosition(childId, category, position, language) {
  const lang = language || "English";
  const kids = loadChildren();
  const idx = kids.findIndex(c => c.id === childId);
  if (idx < 0) return;
  kids[idx].position = migratePosition(kids[idx].position);
  kids[idx].position[lang] = kids[idx].position[lang] || {};
  kids[idx].position[lang][category] = position;
  saveChildren(kids);
}

// Given a child's position, return the 3 consecutive sets for this session.
// If fewer than 3 sets remain in the month, wraps to next available or falls
// back to the last valid sets.
function getSetsForPosition(allSetsArray, position, month) {
  const monthSets = allSetsArray[month];
  if (!monthSets || monthSets.length === 0) return [];
  const { setIdx } = position;
  const result = [];
  for (let i = 0; i < 3; i++) {
    const idx = setIdx + i;
    if (idx < monthSets.length) {
      result.push(monthSets[idx]);
    } else {
      // Wrap or just take last available
      result.push(monthSets[monthSets.length - 1 - (i - (monthSets.length - setIdx - 1))] || monthSets[monthSets.length - 1]);
    }
  }
  return result.slice(0, 3);
}

// ── FAMILY PHOTOS ────────────────────────────────────────────────────────────
// Parents can upload real photos for family-member words so babies learn those
// specific faces. Photos are stored per-child as base64 in localStorage.
//
// Honest limits: localStorage caps around 5MB. We compress each upload to
// <200KB using canvas resize (max 600px wide), so ~15-25 family photos fit
// before hitting quota. If the quota fails, we show an error and keep the
// existing photos.

// Family photo slots — supports both generic ("sister") and kinship-specific
// ("sister_older", "grandma_paternal") uploads. Languages that differentiate
// kinship (Cantonese, Korean, Vietnamese, Hindi, etc.) look up the specific
// slot first and fall back to the generic slot if not available.
//
// The parent only sees the specific slots if at least one of the child's
// learning languages uses them (dynamic display, decision C from user).
// Words that appear in the ChildEditor's "Personal Photos" grid. Each one is
// a slot that the parent can upload a photo to. NOTE: home/child/elder/friend
// are intentionally NOT here — those are uploaded just-in-time via the
// in-session prompt right before the relevant card appears, so the parent
// understands WHY they're being asked. This keeps the profile editor focused
// on actual family members.
const FAMILY_PHOTO_WORDS = [
  "mother","father","baby","sister","brother","grandma","grandpa","aunt","uncle"
];

// Words for "places at home" that the parent can optionally upload as a JIT
// upgrade before the Locations set (M2 Set 28) starts. Stock photos are used
// if the parent skips. Uses the same setFamilyPhoto storage as family photos
// — semantically these are just additional photo slots, not a separate system.
const LOCATION_PHOTO_WORDS = [
  "kitchen","bedroom","bathroom","livingroom","garden"
];

// Kinship slot mapping — when the curriculum card has a specific kinship
// note (e.g. "older sister", "paternal grandma"), we try the specific slot
// first and fall back to the generic base word if that slot isn't uploaded.
const KINSHIP_SLOTS = {
  sister:  ["sister_older", "sister_younger"],
  brother: ["brother_older", "brother_younger"],
  grandma: ["grandma_paternal", "grandma_maternal"],
  grandpa: ["grandpa_paternal", "grandpa_maternal"],
  aunt:    ["aunt_paternal", "aunt_maternal"],
  uncle:   ["uncle_paternal", "uncle_maternal"],
};

// Human-readable labels for each kinship slot in the photo upload UI.
const KINSHIP_SLOT_LABELS = {
  sister_older:    "Older sister",
  sister_younger:  "Younger sister",
  brother_older:   "Older brother",
  brother_younger: "Younger brother",
  grandma_paternal:"Grandma (paternal — dad's mom)",
  grandma_maternal:"Grandma (maternal — mom's mom)",
  grandpa_paternal:"Grandpa (paternal — dad's dad)",
  grandpa_maternal:"Grandpa (maternal — mom's dad)",
  aunt_paternal:   "Aunt (paternal — dad's sister)",
  aunt_maternal:   "Aunt (maternal — mom's sister)",
  uncle_paternal:  "Uncle (paternal — dad's brother)",
  uncle_maternal:  "Uncle (maternal — mom's brother)",
};

// Given a card's English canonical word + optional note (e.g. "older sister",
// "paternal grandma"), determine the best photo slot to use.
// Returns the specific slot if the note matches, else the base word.
function resolveFamilyPhotoSlot(englishWord, note) {
  if (!englishWord) return null;
  const base = englishWord.toLowerCase();
  const n = (note || "").toLowerCase();
  if (base === "sister") {
    if (n.includes("older")) return "sister_older";
    if (n.includes("younger") || n.includes("youngest")) return "sister_younger";
    return "sister";
  }
  if (base === "brother") {
    if (n.includes("older")) return "brother_older";
    if (n.includes("younger") || n.includes("youngest")) return "brother_younger";
    return "brother";
  }
  if (base === "grandma") {
    if (n.includes("paternal")) return "grandma_paternal";
    if (n.includes("maternal")) return "grandma_maternal";
    return "grandma";
  }
  if (base === "grandpa") {
    if (n.includes("paternal")) return "grandpa_paternal";
    if (n.includes("maternal")) return "grandpa_maternal";
    return "grandpa";
  }
  if (base === "aunt") {
    if (n.includes("paternal")) return "aunt_paternal";
    if (n.includes("maternal")) return "aunt_maternal";
    return "aunt";
  }
  if (base === "uncle") {
    if (n.includes("paternal")) return "uncle_paternal";
    if (n.includes("maternal")) return "uncle_maternal";
    return "uncle";
  }
  return base;
}

// Given a family photo dictionary and a card, return the photo URL to display.
// Falls back from specific slot → generic base word → null.
// (Decision A from user: some personalization > none.)
function lookupFamilyPhoto(familyPhotos, englishWord, note) {
  if (!familyPhotos || !englishWord) return null;
  const slot = resolveFamilyPhotoSlot(englishWord, note);
  if (familyPhotos[slot]) return familyPhotos[slot];
  // Fall back to base word
  const base = englishWord.toLowerCase();
  if (familyPhotos[base]) return familyPhotos[base];
  // Phrase-level fallback: if the card is a couplet ("tall daddy",
  // "kind mommy") or a sentence ("Mommy is kind.", "I love Daddy."),
  // englishWord here is the full phrase. The single-word slot lookup
  // above won't match. Scan the phrase for family-keyword tokens and
  // map them back to their photo slots.
  const phraseMatch = lookupFamilyPhotoFromPhrase(familyPhotos, base);
  if (phraseMatch) return phraseMatch;
  // ── PEOPLE → FAMILY-PHOTO ALIASES ─────────────────────────────────────────
  // Generic "people" curriculum words (woman/man/child/elder) reuse the
  // parent-uploaded family photos. Per Olivia's curriculum design:
  //   "woman" card → shows the mother photo (if uploaded)
  //   "man"   card → shows the father photo (if uploaded)
  //   "child" card → shows the baby photo (if uploaded)
  //   "elder" card → shows grandma OR grandpa photo (whichever exists)
  // This avoids forcing parents to upload duplicate photos for the People
  // set. Falls through to null (then to curriculum/emoji) if the relevant
  // family slot is empty.
  const PEOPLE_ALIASES = {
    woman: ["mother"],
    man:   ["father"],
    child: ["baby"],
    elder: ["grandma", "grandpa", "grandma_paternal", "grandma_maternal", "grandpa_paternal", "grandpa_maternal"],
  };
  const aliasList = PEOPLE_ALIASES[base];
  if (aliasList) {
    for (const altSlot of aliasList) {
      if (familyPhotos[altSlot]) return familyPhotos[altSlot];
    }
  }
  return null;
}

// Scan a phrase (couplet or sentence) for family-keyword tokens and return
// the matching uploaded photo. Each phrase is expected to reference at most
// one family member; if multiple are mentioned (rare — none in the current
// curriculum), the first match wins. Mapping accounts for display-word
// variations ("mommy"/"mom" → mother slot, "daddy"/"dad" → father slot,
// "grandma"/"granny"/"nana" → grandma, "grandpa"/"granddad"/"papa" → grandpa).
//
// Token order matters: we test more-specific words before less-specific ones
// (e.g. "grandma" before "ma") so the right slot wins. Word-boundary regex
// avoids false positives — "I love mommy" should match, but "I love this
// shimmery dress" should NOT match "mer" inside a longer word.
//
// Special semantic slots:
//   "family" keyword → "family" slot (group photo of the whole family).
//                       Uploaded via the JIT family-group prompt before
//                       M3 sentences set 12 ("I love sentences") starts.
//   "life"   keyword → "baby" slot (child's avatar — already mirrored
//                       there at child creation). "I love my life" is
//                       semantically about the child themselves.
//   "home"   keyword → location photos (livingroom / kitchen / bedroom)
function lookupFamilyPhotoFromPhrase(familyPhotos, phrase) {
  if (!familyPhotos || !phrase) return null;
  const lower = phrase.toLowerCase();
  // Display word → photo slot. Order matters — more specific first.
  const FAMILY_KEYWORDS = [
    // Grandparents (test before "ma"/"pa" / "mom"/"dad" so they win)
    [/\bgrandma\b/,    ["grandma", "grandma_paternal", "grandma_maternal"]],
    [/\bgrandmother\b/,["grandma", "grandma_paternal", "grandma_maternal"]],
    [/\bgranny\b/,     ["grandma", "grandma_paternal", "grandma_maternal"]],
    [/\bnana\b/,       ["grandma", "grandma_paternal", "grandma_maternal"]],
    [/\bgrandpa\b/,    ["grandpa", "grandpa_paternal", "grandpa_maternal"]],
    [/\bgrandfather\b/,["grandpa", "grandpa_paternal", "grandpa_maternal"]],
    [/\bgranddad\b/,   ["grandpa", "grandpa_paternal", "grandpa_maternal"]],
    [/\bpapa\b/,       ["grandpa", "grandpa_paternal", "grandpa_maternal", "father"]],
    // Aunts and uncles
    [/\baunt\b|\bauntie\b/, ["aunt", "aunt_paternal", "aunt_maternal"]],
    [/\buncle\b/,      ["uncle", "uncle_paternal", "uncle_maternal"]],
    // Siblings
    [/\bsister\b|\bsis\b/,    ["sister", "sister_older", "sister_younger"]],
    [/\bbrother\b|\bbro\b/,   ["brother", "brother_older", "brother_younger"]],
    // Parents (after grandparent tests so "grandma" doesn't get hijacked)
    [/\bmommy\b|\bmom\b|\bmama\b|\bmother\b/, ["mother"]],
    [/\bdaddy\b|\bdad\b|\bfather\b/,           ["father"]],
    // Baby
    [/\bbaby\b/,       ["baby"]],
    // "I love my family" — group photo slot. Tested AFTER specific kinship
    // words so something like "Mommy is family" (not in the curriculum but
    // future-proofing) still resolves to mother first.
    [/\bfamily\b/,     ["family"]],
    // "I love my life" — points at the child themselves. Resolves to
    // the child's avatar (which is auto-mirrored into the "baby" family
    // slot at child creation). Falls back to whatever's in the baby slot
    // if the parent uploaded one separately, then to null → emoji.
    [/\blife\b/,       ["baby"]],
    // Home → location photos (if uploaded). "I love my home." style.
    [/\bhome\b|\bhouse\b/, ["livingroom", "kitchen", "bedroom"]],
  ];
  for (const [pattern, slots] of FAMILY_KEYWORDS) {
    if (pattern.test(lower)) {
      for (const slot of slots) {
        if (familyPhotos[slot]) return familyPhotos[slot];
      }
      // Keyword was present but no photo uploaded for any candidate slot.
      // Don't keep scanning — the card is clearly about this family member,
      // and falling through to a different keyword (e.g. matching "baby"
      // because the sentence happens to contain it later) would be wrong.
      return null;
    }
  }
  return null;
}

// Determine which kinship slots to show in the photo upload UI, given the
// languages the child is actively learning. Decision C from user: dynamic.
// Returns an array of slot ids like ["sister_older","grandma_paternal"].
function kinshipSlotsForLanguages(learningLanguages) {
  if (!learningLanguages || learningLanguages.length === 0) return [];
  const uses = (base) => learningLanguages.some(l => l !== "English" && KINSHIP_LANGUAGES.includes(l) && KINSHIP_VARIANTS[base]?.[l]);
  const out = [];
  if (uses("sister"))  out.push("sister_older", "sister_younger");
  if (uses("brother")) out.push("brother_older", "brother_younger");
  if (uses("grandma")) out.push("grandma_paternal", "grandma_maternal");
  if (uses("grandpa")) out.push("grandpa_paternal", "grandpa_maternal");
  if (uses("aunt"))    out.push("aunt_paternal", "aunt_maternal");
  if (uses("uncle"))   out.push("uncle_paternal", "uncle_maternal");
  return out;
}

function getFamilyPhotos(childId) {
  try {
    const raw = localStorage.getItem(`lb-photos-${childId}`);
    return raw ? JSON.parse(raw) : {};
  } catch { return {}; }
}

function setFamilyPhoto(childId, word, dataUrl) {
  try {
    const photos = getFamilyPhotos(childId);
    if (dataUrl) photos[word] = dataUrl; else delete photos[word];
    localStorage.setItem(`lb-photos-${childId}`, JSON.stringify(photos));
    return true;
  } catch (e) {
    // Usually DOMException: QuotaExceededError
    console.warn("Family photo storage failed:", e);
    return false;
  }
}

// Rhythm: track which pattern types each child has already been introduced
// to (i.e. seen the word/concept card for). After they've learned it once,
// future encounters of the same pattern just show the rhythm notation +
// audio without the word card. This keeps sessions fun and focused on
// CLAPPING THE RHYTHMS rather than re-learning vocabulary they already know.
//
// The "learned" key isn't pattern.id — different patterns can introduce the
// same concept (e.g. "Quarter note" appears in both basic-beats and time-2-4).
// We track by the pattern's `label` since labels are concept descriptions.
function getRhythmLearned(childId) {
  try {
    const raw = localStorage.getItem(`lb-rhythm-learned-${childId}`);
    return raw ? new Set(JSON.parse(raw)) : new Set();
  } catch { return new Set(); }
}
function markRhythmLearned(childId, conceptKey) {
  try {
    const set = getRhythmLearned(childId);
    set.add(conceptKey);
    localStorage.setItem(`lb-rhythm-learned-${childId}`, JSON.stringify([...set]));
  } catch {}
}

// Compress a File to a base64 data URL, max 600px wide, JPEG quality 0.8.
// Returns a promise resolving to the data URL string.
function compressImageFile(file) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onerror = () => reject(new Error("Could not read file"));
    reader.onload = (e) => {
      const img = new Image();
      img.onerror = () => reject(new Error("Could not decode image"));
      img.onload = () => {
        // Reduced from 600×0.8 to 400×0.7 — cuts storage ~3× without
        // visible quality loss at the photo display size (300px). Important
        // for families uploading many kinship variants (twin × 23 slots).
        const maxW = 400;
        const scale = Math.min(1, maxW / img.width);
        const w = Math.round(img.width * scale);
        const h = Math.round(img.height * scale);
        const canvas = document.createElement("canvas");
        canvas.width = w; canvas.height = h;
        const ctx = canvas.getContext("2d");
        ctx.drawImage(img, 0, 0, w, h);
        resolve(canvas.toDataURL("image/jpeg", 0.7));
      };
      img.src = e.target.result;
    };
    reader.readAsDataURL(file);
  });
}

// ── FAMILY CODE (share across caregivers) ────────────────────────────────────
// A "family code" packages: children profiles + their history.
// Parent A generates → shares via text/email. Parent B pastes → everything syncs.
// Stored as base64-encoded JSON. Short enough to text easily when compressed.

function buildFamilyPayload() {
  const kids = loadChildren();
  const histories = {};
  kids.forEach(c => {
    try {
      const h = localStorage.getItem(`lb-history-${c.id}`);
      if (h) histories[c.id] = JSON.parse(h);
    } catch {}
  });
  return { v: 1, kids, histories, ts: Date.now() };
}

function encodeFamilyCode() {
  const payload = buildFamilyPayload();
  const json = JSON.stringify(payload);
  try {
    // Use TextEncoder so non-Latin names survive base64
    const bytes = new TextEncoder().encode(json);
    let binary = "";
    bytes.forEach(b => { binary += String.fromCharCode(b); });
    const b64 = btoa(binary);
    // Make it URL-safe and prefix for recognition
    return "LB1-" + b64.replace(/\+/g,"-").replace(/\//g,"_").replace(/=+$/,"");
  } catch {
    return "";
  }
}

function decodeFamilyCode(code) {
  try {
    const s = code.trim().replace(/^LB1-/i,"");
    const b64 = s.replace(/-/g,"+").replace(/_/g,"/");
    // re-pad
    const padded = b64 + "=".repeat((4 - b64.length % 4) % 4);
    const binary = atob(padded);
    const bytes = new Uint8Array(binary.length);
    for (let i=0;i<binary.length;i++) bytes[i] = binary.charCodeAt(i);
    const json = new TextDecoder().decode(bytes);
    const data = JSON.parse(json);
    if (!data || data.v !== 1 || !Array.isArray(data.kids)) throw new Error("Invalid payload");
    return data;
  } catch (e) {
    return null;
  }
}

// Apply an imported family: MERGE kids by id (new ones added, existing replaced),
// and MERGE history taking the MAX count per (date, category:language) key.
function applyFamilyPayload(payload) {
  const existing = loadChildren();
  const byId = {};
  existing.forEach(c => { byId[c.id] = c; });
  payload.kids.forEach(c => { byId[c.id] = c; });
  const merged = Object.values(byId);
  saveChildren(merged);

  // Merge history per child (taking max of each date+key to avoid double-counting
  // if both caregivers logged the same session)
  Object.entries(payload.histories || {}).forEach(([childId, remoteHist]) => {
    try {
      const key = `lb-history-${childId}`;
      const localHist = JSON.parse(localStorage.getItem(key) || "{}");
      const allDates = new Set([...Object.keys(localHist), ...Object.keys(remoteHist)]);
      const out = {};
      allDates.forEach(d => {
        const a = localHist[d] || {};
        const b = remoteHist[d] || {};
        const day = {};
        const allKeys = new Set([...Object.keys(a), ...Object.keys(b)]);
        allKeys.forEach(k => { day[k] = Math.max(a[k]||0, b[k]||0); });
        out[d] = day;
      });
      localStorage.setItem(key, JSON.stringify(out));
    } catch {}
  });

  return merged;
}

// ── SESSION TRACKING (per-child, per-language) ───────────────────────────────
// Doman protocol: 3 sessions per day per (child, category, language),
// with at least 5 minutes between sessions.

const SESSION_COOLDOWN_MS = 5 * 60 * 1000;
const MAX_SESSIONS_PER_DAY = 3;

function sessionKey(childId, category, language, dk) {
  return `lb-sess-${childId}-${category}-${language}-${dk}`;
}

function getSessionStatus(childId, category, language) {
  try {
    const dk = todayKey();
    const raw = localStorage.getItem(sessionKey(childId, category, language, dk));
    const data = raw ? JSON.parse(raw) : { count: 0, lastAt: 0 };

    if (data.count >= MAX_SESSIONS_PER_DAY) {
      return { sessionNum: MAX_SESSIONS_PER_DAY, locked: true, reason: "done", secondsUntilReady: 0 };
    }

    const now = Date.now();
    const since = now - (data.lastAt || 0);
    if (data.count > 0 && since < SESSION_COOLDOWN_MS) {
      const secondsUntilReady = Math.ceil((SESSION_COOLDOWN_MS - since) / 1000);
      return { sessionNum: data.count + 1, locked: true, reason: "cooldown", secondsUntilReady };
    }

    return { sessionNum: data.count + 1, locked: false, secondsUntilReady: 0 };
  } catch {
    return { sessionNum: 1, locked: false, secondsUntilReady: 0 };
  }
}

// Per-set graduation threshold by category. Number of sessions a child must
// accumulate on the current set/stage before advancing to the next. Reading,
// math, and knowledge use the standard Doman 3-sessions cadence. Music and
// rhythm use a longer 15-session cadence (Nov 2026) — these are deeper
// pattern-recognition disciplines that don't internalize after just 3 hits.
//   reading/couplets/sentences/encyclopedia/math: 3 sessions per set
//     (≈1 day of practice at 3 sessions/day)
//   music/rhythm: 15 sessions per stage
//     (≈5 days of practice at 3 sessions/day; carryover model — same as
//     reading, missing days just delays graduation, doesn't reset)
const SESSIONS_TO_GRADUATE = {
  reading:      3,
  couplets:     3,
  sentences:    3,
  encyclopedia: 3,
  math:         3,
  music:        15,
  rhythm:       15,
};
const DEFAULT_SESSIONS_TO_GRADUATE = 3;
function sessionsToGraduate(category) {
  return SESSIONS_TO_GRADUATE[category] || DEFAULT_SESSIONS_TO_GRADUATE;
}

// Per-set session counter — separate from the daily count. Advancement
// is tied to "have we done N sessions ON THIS SET" rather than "have
// we done N sessions TODAY". This way, missing a day doesn't make the
// curriculum stop advancing: yesterday's incomplete session count
// carries over to today, and the set graduates as soon as N cumulative
// sessions are done.
//
// Daily count (sessionKey) is still used for cooldown and "you've done
// your 3 today" UI gating, but does NOT trigger advancement on its own.
function setProgressKey(childId, category, language) {
  return `lb-set-progress-${childId}-${category}-${language || "English"}`;
}
function getSetProgress(childId, category, language) {
  try {
    const raw = localStorage.getItem(setProgressKey(childId, category, language));
    if (!raw) return 0;
    const n = parseInt(raw, 10);
    if (!Number.isFinite(n)) return 0;
    // Clamp to one less than the graduation threshold — that's the highest
    // valid in-progress state. Anything at-or-above triggers graduation
    // and resets to 0 inside markSessionComplete.
    const max = sessionsToGraduate(category) - 1;
    return Math.max(0, Math.min(max, n));
  } catch { return 0; }
}
function setSetProgress(childId, category, language, n) {
  try { localStorage.setItem(setProgressKey(childId, category, language), String(n)); } catch {}
}

// Some categories should advance LANGUAGE-AGNOSTICALLY: the underlying
// content isn't language-specific, so 3 sessions in 3 different languages
// should still count as 3 sessions toward graduation.
//   - music & rhythm: a G-major scale or 4/4 beat sounds identical in any
//     language session. The "language" of a music session is just whatever
//     the child has selected globally; it doesn't change the audio.
//   - knowledge subjects (M1-M3): the photo of a peacock is the same in
//     every language. M4-M6 (facts mode) IS language-specific (the facts
//     get translated), so those keep per-language tracking.
//
// Reading (words/couplets/sentences) is GENUINELY per-language — "apple"
// vs "manzana" vs "蘋果" each need their own progression because the
// printed word is different.
//
// We funnel the cross-language categories through a single sentinel key
// so their per-set counter accumulates across whatever language the parent
// selects. Daily session count + cooldown remain per-language so the
// cooldown UX feels right within a single session.
const GLOBAL_LANG_KEY = "__global__";

function isLanguageAgnosticCategory(category, child, language) {
  if (category === "music" || category === "rhythm") return true;
  if (category === "encyclopedia") {
    // Knowledge subjects (M1-M3) are visual/universal; facts (M4-M6) are
    // genuinely per-language (translated facts). Read the child's current
    // knowledge position for THIS language to decide.
    try {
      const pos = getChildPosition(child, "knowledge", language);
      const month = pos?.month || 1;
      return month <= 3; // subjects mode → global; facts mode → per-language
    } catch { return true; }
  }
  return false;
}

function progressLangKey(category, child, language) {
  return isLanguageAgnosticCategory(category, child, language)
    ? GLOBAL_LANG_KEY
    : language;
}

function markSessionComplete(childId, category, language) {
  try {
    const dk = todayKey();
    const key = sessionKey(childId, category, language, dk);
    const raw = localStorage.getItem(key);
    const data = raw ? JSON.parse(raw) : { count: 0, lastAt: 0 };
    data.count = Math.min(MAX_SESSIONS_PER_DAY, data.count + 1);
    data.lastAt = Date.now();
    localStorage.setItem(key, JSON.stringify(data));

    // Log in history: per child, by date, by category, by language
    const histKey = `lb-history-${childId}`;
    const hist = JSON.parse(localStorage.getItem(histKey) || "{}");
    if (!hist[dk]) hist[dk] = {};
    const dayKey = `${category}:${language}`;
    hist[dk][dayKey] = (hist[dk][dayKey] || 0) + 1;
    localStorage.setItem(histKey, JSON.stringify(hist));

    // Per-set advancement (May 2026): a set graduates when it has
    // accumulated 3 sessions, regardless of which calendar days those
    // sessions fell on. This is what makes the carryover behavior work:
    // if yesterday ended with 2/3 sessions on Set N, today's first
    // session is the 3rd and graduates the set; remaining sessions
    // today (if any) advance into Set N+1.
    //
    // For language-agnostic categories (music/rhythm/knowledge-subjects)
    // we use a global pseudo-language key so 3 sessions in 3 different
    // language tabs still count as 3 toward set graduation. For reading
    // and knowledge facts, the per-set counter remains per-language.
    const child = (() => {
      try {
        const kids = JSON.parse(localStorage.getItem("lb-children") || "[]");
        return kids.find(c => c.id === childId);
      } catch { return null; }
    })();
    const progressLang = progressLangKey(category, child, language);
    const newSetCount = getSetProgress(childId, category, progressLang) + 1;
    const threshold = sessionsToGraduate(category);
    if (newSetCount >= threshold) {
      // Set complete → reset and advance position
      setSetProgress(childId, category, progressLang, 0);
      advancePositionAfterFinalSession(childId, category, language);
    } else {
      setSetProgress(childId, category, progressLang, newSetCount);
    }

    // Track first-ever Day 1 completion so we can prompt the parent to
    // upload extended-family photos (grandma/grandpa/aunt/uncle —
    // these words appear ~Day 30 in the curriculum). Daily-count is
    // the right trigger here (not set-count): we want to celebrate the
    // first time they finish all 3 sessions in one day.
    if (data.count >= MAX_SESSIONS_PER_DAY) {
      try {
        const promptKey = `lb-day1-complete-${childId}`;
        if (!localStorage.getItem(promptKey)) {
          localStorage.setItem(promptKey, String(Date.now()));
        }
      } catch {}
    }
  } catch {}
}

// Advance the per-language curriculum position forward by one unit. Called
// from markSessionComplete when the per-SET session counter hits 3 (a set's
// 3 sessions may span multiple calendar days — that's the whole point of
// per-set counting). The unit of advancement varies by category:
//   reading/couplets/sentences: setIdx += 1, wrapping to next month
//   knowledge: same as reading
//   math: day-number-driven; position (stage) only advances when the child
//     finishes the rolling window cycle of the current stage. We auto-advance
//     conservatively — only when an explicit unlock day is reached. For now
//     math doesn't advance here; it advances naturally via the day-number
//     formula in getDomanWindow().
//   music/rhythm: per-set advancement (May 2026) — each scale/stage rolls
//     forward to the next after 3 sessions. Previous "weekly cadence"
//     (21 sessions per scale) was perceived as stagnant by parents.
function advancePositionAfterFinalSession(childId, category, language) {
  try {
    const kids = JSON.parse(localStorage.getItem("lb-children") || "[]");
    const idx = kids.findIndex(c => c.id === childId);
    if (idx < 0) return;
    const lang = language || "English";
    if (!kids[idx].position) kids[idx].position = {};
    if (kids[idx].position && !kids[idx].position[lang] && (kids[idx].position.words || kids[idx].position.math)) {
      // Old flat format — migrate first
      const flat = kids[idx].position;
      kids[idx].position = { English: flat };
    }
    if (!kids[idx].position[lang]) kids[idx].position[lang] = {};
    const langPos = kids[idx].position[lang];

    // Map session category → position key in the data structure
    const posKeyMap = {
      reading:      "words",
      couplets:     "couplets",
      sentences:    "sentences",
      encyclopedia: "knowledge",
    };
    const posKey = posKeyMap[category];

    if (posKey) {
      // Sets-based advancement: increment setIdx, wrap to next month if needed
      const cur = langPos[posKey] || { month: 1, setIdx: 0 };
      const monthData = (
        posKey === "words"     ? WORDS_BY_MONTH :
        posKey === "couplets"  ? COUPLETS_BY_MONTH :
        posKey === "sentences" ? SENTENCES_BY_MONTH :
        posKey === "knowledge" ? KNOWLEDGE_BY_MONTH : null
      );
      if (!monthData) return;

      const monthSets = monthData[cur.month];
      // For knowledge: months 4-6 reuse months 1-3 content (facts mode pass)
      const contentMonth = (posKey === "knowledge" && cur.month > 3) ? cur.month - 3 : cur.month;
      const actualMonthSets = monthData[contentMonth];
      // Number of sets in the current month (some months may have null data)
      const monthLen = actualMonthSets ? actualMonthSets.length : (monthSets ? monthSets.length : 0);
      let nextMonth = cur.month;
      let nextSetIdx = cur.setIdx + 1;
      // If we've passed the last set in the current month, roll to next month.
      // Knowledge runs M1-M6 (M4-6 are facts-mode passes through M1-3 content).
      // Other categories cap at M3.
      const maxMonth = posKey === "knowledge" ? 6 : 3;
      if (nextSetIdx >= monthLen) {
        // Find the next month that has data
        let m = cur.month + 1;
        while (m <= maxMonth) {
          // For knowledge M4-6, check the corresponding M1-3 content slot
          const checkMonth = (posKey === "knowledge" && m > 3) ? m - 3 : m;
          if (monthData[checkMonth]) break;
          m++;
        }
        if (m > maxMonth) {
          // Curriculum complete for this category/language. Stay parked at the
          // final set so progress.isClassFullyComplete trips correctly and the
          // child can still review.
          nextMonth = cur.month;
          nextSetIdx = monthLen - 1;
        } else {
          nextMonth = m;
          nextSetIdx = 0;
        }
      }
      langPos[posKey] = { month: nextMonth, setIdx: nextSetIdx };
      kids[idx].position[lang] = langPos;

      // Cross-language mirror for knowledge SUBJECTS (M1-M3 only). The
      // visual content is the same in every language — same peacock photo,
      // same musical-instrument photo. So when a session in any language
      // graduates a subject set, all other enrolled languages should jump
      // forward too. Once the child enters facts mode (M4+), the content
      // genuinely diverges per language and we revert to per-language
      // tracking. Reading-category posKeys (words/couplets/sentences) stay
      // strictly per-language because the printed text differs by language.
      if (posKey === "knowledge" && nextMonth <= 3) {
        const allLangs = Array.from(new Set([
          lang,
          ...((kids[idx].languages) || []),
          ...Object.keys(kids[idx].position || {}),
        ]));
        for (const L of allLangs) {
          if (!kids[idx].position[L]) kids[idx].position[L] = {};
          // Only mirror if the OTHER language hasn't already advanced past
          // this point — we want to push forward, never backward, and we
          // don't clobber a language that's individually ahead.
          const other = kids[idx].position[L].knowledge;
          const ahead = other && (
            (other.month > nextMonth) ||
            (other.month === nextMonth && other.setIdx >= nextSetIdx)
          );
          if (!ahead) {
            kids[idx].position[L].knowledge = { month: nextMonth, setIdx: nextSetIdx };
          }
        }
      }

      localStorage.setItem("lb-children", JSON.stringify(kids));
      return;
    }

    if (category === "music" || category === "rhythm") {
      // Per-set advancement (May 2026): each scale/stage graduates after
      // the standard 3 sessions, same as reading. This means music advances
      // to the next scale every full day of practice (rather than the
      // original 7-day weekly cadence). Per Olivia, music should feel
      // like daily forward progress, not stagnation.
      //
      // Cross-language sync (Nov 2026 fix): music/rhythm content is
      // language-agnostic (a G-major scale sounds the same regardless of
      // which language tab the parent picked). When the global per-set
      // counter graduates, we advance the position in the CURRENT language
      // AND mirror that advance to every other language the child has
      // enrolled in — so they don't see G-major in English but stale
      // C-major in Spanish.
      const allLangs = Array.from(new Set([
        lang,
        ...((kids[idx].languages) || []),
        ...Object.keys(kids[idx].position || {}),
      ]));
      if (category === "music") {
        const stages = MUSIC_SCALES;
        const curId = langPos.music || stages[0].id;
        const i = stages.findIndex(s => s.id === curId);
        if (i >= 0 && i < stages.length - 1) {
          const nextId = stages[i + 1].id;
          for (const L of allLangs) {
            if (!kids[idx].position[L]) kids[idx].position[L] = {};
            kids[idx].position[L].music = nextId;
          }
        }
      } else {
        const stages = RHYTHM_STAGES;
        const curId = langPos.rhythm || stages[0].id;
        const i = stages.findIndex(s => s.id === curId);
        if (i >= 0 && i < stages.length - 1) {
          const nextId = stages[i + 1].id;
          for (const L of allLangs) {
            if (!kids[idx].position[L]) kids[idx].position[L] = {};
            kids[idx].position[L].rhythm = nextId;
          }
        }
      }
      localStorage.setItem("lb-children", JSON.stringify(kids));
    }
    // Math: if the parent has pinned a granular position {stageId, offsetDay},
    // advance the offsetDay by 1 once the child completes their daily cadence
    // (this function fires after the FINAL session of the day per the
    // markSessionComplete logic). This keeps the pin behaving like a "starting
    // point" rather than a permanent freeze. If math is in the legacy bare-
    // string format, we skip — the day-driven formula handles progression.
    if (category === "math") {
      const cur = langPos.math;
      if (cur && typeof cur === "object" && cur.stageId && cur.offsetDay) {
        const stage = MATH_STAGES.find(s => s.id === cur.stageId);
        if (stage) {
          const isQuantityStage = !stage.isEq;
          const maxDay = isQuantityStage ? 46 : 20;
          const nextDay = cur.offsetDay + 1;
          if (nextDay > maxDay) {
            // Roll to the next stage at default day-driven mode (drop the pin)
            const stageIdx = MATH_STAGES.findIndex(s => s.id === cur.stageId);
            if (stageIdx >= 0 && stageIdx < MATH_STAGES.length - 1) {
              langPos.math = MATH_STAGES[stageIdx + 1].id;
            } else {
              // Already on the last stage — keep the pin at maxDay
              langPos.math = { stageId: cur.stageId, offsetDay: maxDay };
            }
          } else {
            langPos.math = { stageId: cur.stageId, offsetDay: nextDay };
          }
          kids[idx].position[lang] = langPos;
          localStorage.setItem("lb-children", JSON.stringify(kids));
        }
      }
    }
  } catch {}
}

function getHistory(childId) {
  try {
    return JSON.parse(localStorage.getItem(`lb-history-${childId}`) || "{}");
  } catch { return {}; }
}

// When a parent jumps a child's level forward via "adjust level", assume the
// child has been exposed to the cards up to that new position and backfill
// the session-completion history accordingly. This way the progress report
// (CEFR / word counts / per-language progress) reflects the parent's intent.
//
// Strategy: for each set skipped forward, credit 3 completed sessions (the
// standard daily cadence). The exposure-count formula elsewhere converts
// sessions → words (5 new words averaged per session across the rolling
// window of 3). We backfill into a special "retroactive" day-key so it
// doesn't pollute today's session status/cooldowns.
function backfillHistoryForPositionJump(childId, language, oldPos, newPos) {
  if (!childId || !language || !newPos) return;
  // Compute how many sets moved forward. Handles words/couplets/sentences/knowledge
  // (sets-based categories). For math/music/rhythm (flat stages), we don't backfill
  // because the exposure-count formula doesn't care about those.
  const countSets = (start, end, maxMonths = 3) => {
    if (!start || !end) return 0;
    let n = 0;
    for (let m = (start.month || 1); m <= maxMonths; m++) {
      // If same month as start, count from start.setIdx, else from 0
      const fromIdx = (m === (start.month || 1)) ? (start.setIdx || 0) : 0;
      // If same month as end, count up to end.setIdx, else we'd need the month's
      // set count — but we don't have that here. Use a safe upper bound of 10.
      const toIdx = (m === (end.month || 1)) ? (end.setIdx || 0) : 10;
      if (m < (end.month || 1)) n += (10 - fromIdx); // whole-month skip
      else if (m === (end.month || 1)) n += Math.max(0, toIdx - fromIdx);
    }
    return n;
  };

  // Each category maps to a session key used in history (e.g. "reading:English")
  const mapping = [
    { posKey: "words",     sessionKey: "reading" },
    { posKey: "couplets",  sessionKey: "couplets" },
    { posKey: "sentences", sessionKey: "sentences" },
    { posKey: "knowledge", sessionKey: "encyclopedia" },
  ];

  let hist = getHistory(childId);
  // Use a synthetic "retroactive" day-key so real session tracking isn't affected
  const RETRO_KEY = "retro-level-adjust";
  if (!hist[RETRO_KEY]) hist[RETRO_KEY] = {};

  let wroteAny = false;
  for (const { posKey, sessionKey } of mapping) {
    const oldP = oldPos?.[posKey];
    const newP = newPos?.[posKey];
    if (!newP) continue; // didn't set this category
    const setsAdvanced = countSets(oldP || { month: 1, setIdx: 0 }, newP);
    if (setsAdvanced <= 0) continue;
    // 3 sessions per set assumed
    const sessionsToCredit = setsAdvanced * 3;
    const key = `${sessionKey}:${language}`;
    const existing = hist[RETRO_KEY][key] || 0;
    hist[RETRO_KEY][key] = existing + sessionsToCredit;
    wroteAny = true;
  }

  if (wroteAny) {
    try { localStorage.setItem(`lb-history-${childId}`, JSON.stringify(hist)); } catch {}
  }
}

// ── AGE HELPERS ───────────────────────────────────────────────────────────────
// Given a YYYY-MM-DD birthdate string and an optional reference date, compute
// the child's age. Returns null if birthdate missing/invalid. Returns a small
// object {days, weeks, months, label} where `label` is the best human-readable
// summary for the progress screen (e.g. "3 weeks", "11 months", "16 months").

function ageFromBirthdate(birthdate, refDate) {
  if (!birthdate) return null;
  try {
    const bd = new Date(birthdate + "T00:00:00");
    if (isNaN(bd.getTime())) return null;
    const ref = refDate instanceof Date ? refDate : new Date();
    const msPerDay = 1000 * 60 * 60 * 24;
    const days = Math.floor((ref - bd) / msPerDay);
    if (days < 0) return null;
    const weeks = Math.floor(days / 7);
    // Months via calendar math (approximate but stable for milestones)
    let months = (ref.getFullYear() - bd.getFullYear()) * 12 + (ref.getMonth() - bd.getMonth());
    if (ref.getDate() < bd.getDate()) months -= 1;
    months = Math.max(0, months);
    let label;
    if (weeks < 12) {
      label = weeks === 1 ? "1 week old" : `${weeks} weeks old`;
    } else if (months < 24) {
      label = months === 1 ? "1 month old" : `${months} months old`;
    } else {
      const years = Math.floor(months / 12);
      const remM = months % 12;
      label = remM === 0 ? `${years} years old` : `${years}y ${remM}m old`;
    }
    return { days, weeks, months, label };
  } catch { return null; }
}

// Compute streak (consecutive days with at least one session of any kind)
function computeStreak(hist) {
  if (!hist) return 0;
  // Local-date arithmetic: build keys by stepping day-by-day using local time,
  // not UTC. Start from today; if today has activity, count it and walk back.
  // If today has no activity but yesterday does, start from yesterday.
  const dateToKey = (d) => {
    const y = d.getFullYear();
    const m = String(d.getMonth() + 1).padStart(2, "0");
    const day = String(d.getDate()).padStart(2, "0");
    return `${y}-${m}-${day}`;
  };
  const dayHasActivity = (key) => {
    const day = hist[key];
    return !!(day && Object.values(day).some(v => v > 0));
  };

  const today = new Date();
  today.setHours(0, 0, 0, 0);

  // Find the most recent day with activity (today or yesterday)
  let cursor = new Date(today);
  if (!dayHasActivity(dateToKey(cursor))) {
    cursor.setDate(cursor.getDate() - 1);
    if (!dayHasActivity(dateToKey(cursor))) return 0;
  }

  // Walk backward from cursor, counting consecutive active days
  let streak = 0;
  while (dayHasActivity(dateToKey(cursor))) {
    streak++;
    cursor.setDate(cursor.getDate() - 1);
  }
  return streak;
}

