function PhotoDisplay({ emoji, style }) {
  return (
    <div style={{
      ...style,
      background: "linear-gradient(135deg, #FFF0F1 0%, #FFE4E6 100%)",
      display: "flex",
      alignItems: "center",
      justifyContent: "center",
      fontSize: 200,
      lineHeight: 1,
    }}>
      {emoji || "✨"}
    </div>
  );
}

