async function translateWords(words, lang) {
  const useKinship = KINSHIP_LANGUAGES.includes(lang);
  const result = [];

  // ── Chinese 4-way variant fork (Apr 2026, revised) ────────────────────
  // The data files store translations under two legacy keys:
  //   "Chinese (Cantonese)" — already in traditional script (HK style/vocab)
  //   "Chinese (Mandarin)"  — already in simplified script (PRC standard)
  //
  // User-facing variants:
  //   Cantonese-Traditional (HK)       → reads (Cantonese) directly. HK vocab+script.
  //   Cantonese-Simplified (mainland) → reads (Mandarin) directly. Mainland Cantonese
  //                            speakers read written Chinese in the standard
  //                            (Mandarin-style) form, but pronounce it in
  //                            Cantonese phonology. So written form = Mandarin,
  //                            speech = zh-HK voice.
  //   Mandarin-Simplified (PRC)       → reads (Mandarin) directly. PRC standard.
  //   Mandarin-Traditional (Taiwan)    → reads (Mandarin), simpToTrad, + TW vocab overrides.
  //                            Taiwan speakers natively use traditional script
  //                            and a substantial set of distinct vocabulary.
  //
  // Why this design: We keep the legacy data keys so 500+ EXTRA_TRANSLATIONS
  // entries don't need to be touched. The variant-specific behavior (which
  // data key to read, whether to script-convert, which vocab to override)
  // is computed at lookup time.

  // Taiwan Mandarin vocabulary that differs from PRC Mandarin. These are
  // overrides applied AFTER script conversion. Compiled from common
  // TW-vs-CN Mandarin reference lists; biased toward words a parent and
  // toddler would actually use (food, transit, household items, places).
  // Where the SAME characters are pronounced differently between TW and CN
  // (no written difference), no override is needed — the zh-TW voice handles it.
  const TW_VOCAB_OVERRIDES = {
    // ── Food ──
    "pineapple":  "鳳梨",   // CN: 菠蘿
    "potato":     "馬鈴薯", // CN: 土豆 (土豆 in TW means peanut!)
    "tomato":     "番茄",   // CN: 西紅柿 (also used)
    "peanut":     "花生",   // same in both
    "pasta":      "義大利麵", // CN: 意大利面
    "noodle":     "麵",     // same characters but TW always 麵 traditional
    "noodles":    "麵條",
    "yogurt":     "優格",   // CN: 酸奶
    "cheese":     "起司",   // CN: 奶酪/乳酪
    "cookie":     "餅乾",   // both use 餅乾 in TC
    "popcorn":    "爆米花", // same
    "icecream":   "冰淇淋", // same
    "salad":      "沙拉",   // same
    "sushi":      "壽司",   // same
    "soup":       "湯",     // same in TC
    "rice":       "米",     // same
    // ── Vehicles & transit ──
    "bicycle":    "腳踏車", // CN: 自行車
    "motorcycle": "機車",   // CN: 摩托車
    "scooter":    "速克達", // CN: 踏板車; though most TW say 機車 for both
    "taxi":       "計程車", // CN: 出租車
    "bus":        "公車",   // CN: 公交車
    "subway":     "捷運",   // CN: 地鐵 (Taipei MRT specifically called 捷運)
    "train":      "火車",   // same
    "ferry":      "渡輪",   // same
    "airplane":   "飛機",   // same
    "plane":      "飛機",
    // ── Tech & modern ──
    "blog":       "部落格", // CN: 博客
    "software":   "軟體",   // CN: 軟件
    "internet":   "網路",   // CN: 網絡
    "mobile":     "手機",   // same
    "phone":      "手機",   // same in casual usage
    "computer":   "電腦",   // same
    "tablet":     "平板",   // same
    "laptop":     "筆電",   // CN: 筆記本電腦
    "video":      "影片",   // CN: 視頻
    "tv":         "電視",   // same
    // ── Household & places ──
    "refrigerator": "冰箱", // CN/TW both use 冰箱; HK uses 雪櫃
    "elevator":   "電梯",   // same
    "lift":       "電梯",
    "garbage":    "垃圾",   // same chars, different pronunciation (lèsè vs lājī)
    "trash":      "垃圾",
    // Casual greeting, days
    "school":     "學校",   // same
    // ── Animals (most overlap, a few diverge) ──
    "panda":      "貓熊",   // CN: 熊貓 (Taiwan officially 貓熊, though 熊貓 also used)
    "dolphin":    "海豚",   // same
    "penguin":    "企鵝",   // same
    // ── Places ──
    "airport":    "機場",   // same
    "hospital":   "醫院",   // same
    // ── Common nouns where TW and CN diverge ──
    "ticket":     "票",     // same
    "passport":   "護照",   // same
    "luggage":    "行李",   // same
    "suitcase":   "行李箱", // same
  };

  const CHINESE_VARIANT_CONFIG = {
    // Cantonese-Traditional = HK style: traditional + HK conversational vocabulary
    "Chinese (Cantonese-Traditional)": {
      dataKey: "Chinese (Cantonese)",
      transform: null,
      twOverrides: false,
    },
    // Cantonese-Simplified = mainland: written Chinese as Mandarin speakers write it,
    // but pronounced with Cantonese phonology. Reads from Mandarin data.
    "Chinese (Cantonese-Simplified)": {
      dataKey: "Chinese (Mandarin)",
      transform: null,
      twOverrides: false,
    },
    // Mandarin-Simplified = PRC standard: simplified script, mainland vocabulary
    "Chinese (Mandarin-Simplified)": {
      dataKey: "Chinese (Mandarin)",
      transform: null,
      twOverrides: false,
    },
    // Mandarin-Traditional = Taiwan: traditional script + TW vocabulary
    "Chinese (Mandarin-Traditional)": {
      dataKey: "Chinese (Mandarin)",
      transform: simpToTrad,
      twOverrides: true,
    },
  };
  const variantConfig = CHINESE_VARIANT_CONFIG[lang];

  // Spanish was previously split 3 ways (Spain, Latin America, Mexico) with
  // per-region vocabulary overrides. As of May 2026 we collapsed back to a
  // single "Spanish" — for the baby curriculum the dialect differences are
  // marginal and the extra options cluttered the language list. Words like
  // "manzana", "perro", "casa" are universal across regions; the few that
  // differ (papa vs patata, jugo vs zumo) appear later in the curriculum
  // and parents can use the "suggest a translation" feature when shipped.
  const spanishVariant = null;

  // Some languages are dialects that share their written form with a "parent"
  // language. E.g. Taiwanese and Cantonese both use traditional Chinese
  // characters; Teochew / Shanghainese / Toisanese are typically written using
  // simplified Chinese (Mandarin). Vietnamese dialects use standard Vietnamese
  // script. For these dialects we fall back to the parent language's
  // translations when a direct translation is not available.
  //
  // Speech/pronunciation is a separate concern; users who want native
  // pronunciation of dialects can use the upcoming custom-recording feature.
  const writtenFallback = {
    "Taiwanese":             "Chinese (Cantonese)",   // traditional characters
    "Chinese (Teochew)":     "Chinese (Mandarin)",     // simplified
    "Chinese (Shanghainese)":"Chinese (Mandarin)",     // simplified
    "Chinese (Toisanese)":   "Chinese (Mandarin)",     // simplified
    "Vietnamese (Northern)": "Vietnamese",
    "Vietnamese (Southern)": "Vietnamese",
  }[lang];

  // Effective lookup language(s).
  let lookupLangs;
  if (variantConfig) {
    lookupLangs = [variantConfig.dataKey];
  } else if (spanishVariant) {
    lookupLangs = [spanishVariant.dataKey];
  } else {
    lookupLangs = writtenFallback ? [lang, writtenFallback] : [lang];
  }
  const kinshipLookupLang = useKinship ? lang : (KINSHIP_LANGUAGES.includes(writtenFallback) ? writtenFallback : null);

  // Apply TW vocab override (if any) and/or script conversion.
  // Override takes precedence over script conversion.
  // For Spanish variants, apply the regional vocab override first, then
  // fall through to the base Spanish translation.
  const applyVariantTransform = (translatedText, lookupKey) => {
    if (spanishVariant && lookupKey && spanishVariant.overrides[lookupKey]) {
      return spanishVariant.overrides[lookupKey];
    }
    if (!variantConfig) return translatedText;
    if (variantConfig.twOverrides && lookupKey && TW_VOCAB_OVERRIDES[lookupKey]) {
      return TW_VOCAB_OVERRIDES[lookupKey];
    }
    if (variantConfig.transform) {
      return variantConfig.transform(translatedText);
    }
    return translatedText;
  };

  for (const w of words) {
    const key = w.word?.toLowerCase();

    // Check if this word has kinship variants for this language (or fallback)
    const kinshipLang = [lang, writtenFallback, variantConfig?.dataKey].find(
      l => l && KINSHIP_VARIANTS[key]?.[l]
    );
    if (kinshipLang) {
      const variants = KINSHIP_VARIANTS[key][kinshipLang];
      for (const v of variants) {
        result.push({
          ...w,
          word: applyVariantTransform(v.word, key),
          emoji: v.emoji || w.emoji,
          note: v.note,                // "older sister", "paternal grandma", etc.
          original: w.word,
          // Preserve gender-specific forms so applyGenderToCard can filter later
          ...(v.womanWord && { womanWord: applyVariantTransform(v.womanWord, key) }),
          ...(v.manWord   && { manWord:   applyVariantTransform(v.manWord, key) }),
          ...(v.bothWord  && { bothWord:  applyVariantTransform(v.bothWord, key) }),
        });
      }
      continue;
    }

    // Regular translation path — try every lookup language in order
    const lookups = [key];
    if (key && key.length > 2) {
      if (key.endsWith("ies")) lookups.push(key.slice(0, -3) + "y");
      if (key.endsWith("ves")) lookups.push(key.slice(0, -3) + "f");
      if (key.endsWith("s"))   lookups.push(key.slice(0, -1));
      if (key.endsWith("es"))  lookups.push(key.slice(0, -2));
    }
    let hit = null;
    let hitKey = null;
    outer: for (const ll of lookupLangs) {
      for (const lk of lookups) {
        hit = CORE_TRANSLATIONS[lk]?.[ll] || EXTRA_TRANSLATIONS[lk]?.[ll];
        if (hit) { hitKey = lk; break outer; }
      }
    }
    if (hit) {
      result.push({ ...w, word: applyVariantTransform(hit, hitKey), original: w.word });
    } else {
      result.push({ ...w, original: w.word });
    }
  }

  return result;
}

// Position-based fetching: parent picks current month+setIdx per child.
// Returns a flat deck of items from 3 consecutive sets (5+5+5 = 15 cards).
// Each item is annotated with `setName` and `setId` for session labeling.
async function fetchDailyWords(child, language) {
  const pos = getChildPosition(child, "words", language);
  if (!pos) return [];
  const sets = getSetsForPosition(WORDS_BY_MONTH, pos, pos.month);
  if (!sets || sets.length === 0) return [];
  const out = [];
  for (const s of sets) {
    for (const item of s.items) {
      out.push({
        word: item.word,
        emoji: emojiForWord(item.word),  // defined below
        setName: s.name,
        setId: s.id,
      });
    }
  }
  return out;
}

