// Look up a curriculum photo URL for a single-word card. The photoKey override
// (if present on the curriculum item) takes priority over the word lookup —
// this lets the same word have different photos in different sets, e.g.
// "chicken" the live bird vs "chicken" the cooked meat. Returns null if
// nothing matches; caller should fall through to family-photo or emoji.
function photoUrlForWord(englishWord, photoKey) {
  if (photoKey && WORD_PHOTO_URLS[photoKey]) return WORD_PHOTO_URLS[photoKey];
  if (!englishWord) return null;
  return WORD_PHOTO_URLS[englishWord.toLowerCase()] || null;
}

async function fetchDailyKnowledge(child, language) {
  const pos = getChildPosition(child, "knowledge", language);
  if (!pos) return [];
  // Knowledge curriculum has 6 logical months but only 3 months of content.
  // Months 1-3 = identification mode (just the card name + photo).
  // Months 4-6 = facts mode (same content, but with 3 facts per card).
  // We map M4→M1, M5→M2, M6→M3 to fetch the right set data; the EncyclopediaSession
  // gets a separate factsMode flag to decide rendering.
  const contentMonth = pos.month > 3 ? pos.month - 3 : pos.month;
  const sets = getSetsForPosition(KNOWLEDGE_BY_MONTH, pos, contentMonth);
  if (!sets || sets.length === 0) return [];
  const out = [];
  for (const s of sets) {
    for (const item of s.items) {
      // Apply per-language fact translation if available. Falls back to English
      // facts when the (cardId, language) pair isn't in the translation table.
      // English facts are used directly when language === "English".
      let facts = item.facts || [null, null, null];
      if (language && language !== "English") {
        const tr = getKnowledgeFactsTranslation(item.id, language);
        if (tr && Array.isArray(tr) && tr.length > 0) {
          // Use translated facts; if the array is shorter than English, fall
          // back to English for the missing slots so the session still works.
          facts = facts.map((eng, i) => tr[i] || eng);
        }
      }
      out.push({
        id: item.id,
        title: titleForKnowledge(item.id, language),
        // Curated Wikipedia Commons URL if available, else picsum placeholder.
        photoUrl: photoUrlForKnowledge(item.id),
        setName: s.name,
        setId: s.id,
        // Three facts per card, shown in sessions 1/2/3 respectively.
        facts,
      });
    }
  }
  return out;
}

async function fetchDailyCouplets(child, language) {
  const pos = getChildPosition(child, "couplets", language);
  if (!pos) return [];
  const sets = getSetsForPosition(COUPLETS_BY_MONTH, pos, pos.month);
  if (!sets || sets.length === 0) return [];
  const out = [];
  for (const s of sets) {
    for (const item of s.items) {
      out.push({
        words: item.words,
        word: item.words.join(" "),
        // Couplet-specific photo URL when available (May 2026 spreadsheet
        // update). When omitted, the renderer falls back to single-word
        // photo lookup or family-photo override (whichever the renderer
        // resolves first based on word + parent setup).
        photoUrl: item.photoUrl || null,
        setName: s.name,
        setId: s.id,
      });
    }
  }
  return out;
}

async function fetchDailySentences(child, language) {
  const pos = getChildPosition(child, "sentences", language);
  if (!pos) return [];
  const sets = getSetsForPosition(SENTENCES_BY_MONTH, pos, pos.month);
  if (!sets || sets.length === 0) return [];
  const out = [];
  for (const s of sets) {
    for (const item of s.items) {
      out.push({
        sentence: item.sentence,
        word: item.sentence,
        // Sentence-specific photo URL when available (May 2026 spreadsheet
        // update). Same fallback chain as couplets.
        photoUrl: item.photoUrl || null,
        setName: s.name,
        setId: s.id,
      });
    }
  }
  return out;
}

// ── REVIEW MODE: fetch cards for a SPECIFIC past set ────────────────────
// Used when parent taps a completed set in the roadmap to review it (e.g.
// the family set with personal photos). Does NOT advance the child's
// progress — combine with sessionStatus.isReplay=true to ensure that.
//
// stageType: "reading" | "couplets" | "sentences" | "knowledge"
// month: 1-3 (or 1-6 for knowledge)
// setIdx: 0-based index within that month
async function fetchSetCards(stageType, month, setIdx) {
  if (stageType === "reading") {
    const monthSets = WORDS_BY_MONTH[month] || [];
    const s = monthSets[setIdx];
    if (!s) return [];
    return s.items.map(item => ({
      word: item.word,
      emoji: emojiForWord(item.word),
      setName: s.name,
      setId: s.id,
    }));
  }
  if (stageType === "couplets") {
    const monthSets = COUPLETS_BY_MONTH[month] || [];
    const s = monthSets[setIdx];
    if (!s) return [];
    return s.items.map(item => ({
      words: item.words,
      word: item.words.join(" "),
      setName: s.name,
      setId: s.id,
    }));
  }
  if (stageType === "sentences") {
    const monthSets = SENTENCES_BY_MONTH[month] || [];
    const s = monthSets[setIdx];
    if (!s) return [];
    return s.items.map(item => ({
      sentence: item.sentence,
      word: item.sentence,
      setName: s.name,
      setId: s.id,
    }));
  }
  if (stageType === "knowledge") {
    // Knowledge maps M4→M1, M5→M2, M6→M3 (same content, facts mode).
    const contentMonth = month > 3 ? month - 3 : month;
    const monthSets = KNOWLEDGE_BY_MONTH[contentMonth] || [];
    const s = monthSets[setIdx];
    if (!s) return [];
    return s.items.map(item => ({
      id: item.id,
      title: titleForKnowledge(item.id, "English"),
      photoUrl: photoUrlForKnowledge(item.id),
      setName: s.name,
      setId: s.id,
      facts: item.facts || [null, null, null],
    }));
  }
  return [];
}

