// Shown for 3s on app launch. Big centered logo, no text, no spinner.
function SplashScreen() {
  return (
    <div style={{minHeight:"100vh",background:"#fff",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",padding:32,gap:22}}>
      {/* Load the same fonts that flash cards use so splash text matches.
          Kept here at splash-time so parents don't see a font flash when
          the app transitions to the home screen. */}
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Baloo+2:wght@700;800&family=Fredoka+One&family=Nunito:wght@700;800;900&display=swap');
        @keyframes lbSplashFade {
          0% { opacity: 0; transform: scale(0.9); }
          20% { opacity: 1; transform: scale(1); }
          90% { opacity: 1; transform: scale(1); }
          100% { opacity: 0.85; transform: scale(1); }
        }
      `}</style>
      <h1 style={{fontFamily:"'Fredoka One','Baloo 2',cursive",fontSize:44,color:RED,margin:0,letterSpacing:-1,lineHeight:1.1,textAlign:"center",animation:"lbSplashFade 1s ease-out forwards"}}>
        Limitless Babies
      </h1>
      <img src={LOGO_SRC} alt="Limitless Babies" style={{width:200,height:"auto",objectFit:"contain",display:"block",animation:"lbSplashFade 1s ease-out forwards"}}/>
    </div>
  );
}

function formatMMSS(sec) {
  const m = Math.floor(sec / 60);
  const s = sec % 60;
  return `${m}:${String(s).padStart(2,"0")}`;
}

function CooldownScreen({ reason, secondsUntilReady, sessionNum, category, onBack, onReplay }) {
  const [remaining, setRemaining] = useState(secondsUntilReady);

  useEffect(()=>{
    if (reason !== "cooldown") return;
    const t = setInterval(()=>setRemaining(r => Math.max(0, r - 1)), 1000);
    return ()=>clearInterval(t);
  }, [reason]);

  useEffect(()=>{
    if (reason === "cooldown" && remaining === 0) {
      // cooldown cleared — kick back to home so they can re-enter
      onBack();
    }
  }, [remaining, reason, onBack]);

  const done = reason === "done";
  const title = done
    ? t("All 3 sessions complete today! 🎉")
    : `${t("Session")} ${sessionNum} ${t("ready in")}…`;
  const subtitle = done
    ? t("Wonderful work! Come back tomorrow for a fresh set.")
    : t("5-minute break between sessions helps learning stick.");

  return (
    <div style={{minHeight:"100vh",background:"#fff",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",gap:18,textAlign:"center",padding:32}}>
      <img src={LOGO_SRC} alt="Limitless Babies" style={{width:110,height:"auto",objectFit:"contain"}}/>
      <div style={{fontSize:48}}>{done ? "🌟" : "⏳"}</div>
      <p style={{fontFamily:"'Fredoka One','Baloo 2',system-ui,sans-serif",fontSize:22,color:RED,maxWidth:320,lineHeight:1.2}}>{title}</p>
      {!done && (
        <div style={{fontFamily:"'Fredoka One','Baloo 2',system-ui,sans-serif",fontSize:54,color:"#111",lineHeight:1}}>
          {formatMMSS(remaining)}
        </div>
      )}
      <p style={{fontFamily:"Nunito,sans-serif",fontWeight:700,color:"#aaa",fontSize:13,maxWidth:300,lineHeight:1.4}}>{subtitle}</p>

      {/* Replay buttons shown only when all 3 sessions are done */}
      {done && onReplay && (
        <div style={{marginTop:6,display:"flex",flexDirection:"column",alignItems:"center",gap:10}}>
          <div style={{fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:11,color:"#999",textTransform:"uppercase",letterSpacing:.5}}>{t("review a session")}</div>
          <div style={{display:"flex",gap:8,justifyContent:"center",flexWrap:"wrap"}}>
            {[1,2,3].map(n => (
              <button key={n} onClick={()=>onReplay(n)}
                style={{background:"#fff",border:`2px solid ${RED}`,borderRadius:50,padding:"8px 16px",cursor:"pointer",fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:12,color:RED}}>
                ↻ {t("Session")} {n}
              </button>
            ))}
          </div>
          <div style={{fontFamily:"Nunito,sans-serif",fontWeight:700,fontSize:10,color:"#ccc",maxWidth:280,lineHeight:1.4}}>
            {t("Replays don't add to today's count.")}
          </div>
        </div>
      )}

      <button onClick={onBack}
        style={{marginTop:8,background:"#f5f5f5",border:"none",borderRadius:50,padding:"10px 22px",cursor:"pointer",fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:14,color:"#555"}}>
        ← {t("back to home")}
      </button>
    </div>
  );
}

function CompleteScreen({ category, sessionNum, onBack }) {
  const isLast = sessionNum >= 3;
  return (
    <div style={{minHeight:"100vh",background:"#fff",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",gap:18,textAlign:"center",padding:32}}>
      <img src={LOGO_SRC} alt="Limitless Babies" style={{width:110,height:"auto",objectFit:"contain"}}/>
      <div style={{fontSize:56}}>{isLast ? "🏆" : "✨"}</div>
      <p style={{fontFamily:"'Fredoka One','Baloo 2',system-ui,sans-serif",fontSize:22,color:RED,maxWidth:320,lineHeight:1.2}}>
        {isLast
          ? t("You finished all 3 sessions today!")
          : `${t("Session")} ${sessionNum} ${t("of")} 3 ${t("complete!")}`}
      </p>
      <p style={{fontFamily:"Nunito,sans-serif",fontWeight:700,color:"#aaa",fontSize:13,maxWidth:300,lineHeight:1.4}}>
        {isLast
          ? t("Amazing consistency. See you tomorrow!")
          : `${t("Take a 5-minute break, then come back for the next session.")}`}
      </p>
      <button onClick={onBack}
        style={{marginTop:8,background:RED,border:"none",borderRadius:50,padding:"11px 26px",cursor:"pointer",fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:14,color:"#fff"}}>
        {t("back to home →")}
      </button>
    </div>
  );
}

function ProgressScreen({ child, onBack }) {
  useParentLang();
  const hist = useMemo(()=>getHistory(child?.id), [child?.id]);
  const dayNum = useMemo(()=>getDayNumber(), []);
  const dates = Object.keys(hist).sort().reverse();

  // Aggregate totals by category & by language
  const byCategory = { reading: 0, math: 0, encyclopedia: 0, couplets: 0, sentences: 0, book: 0 };
  const byLanguage = {};
  dates.forEach(d => {
    const day = hist[d] || {};
    Object.entries(day).forEach(([k, count]) => {
      const [cat, lang] = k.split(":");
      if (byCategory[cat] !== undefined) byCategory[cat] += count;
      if (lang) byLanguage[lang] = (byLanguage[lang] || 0) + count;
    });
  });
  const grandTotal = byCategory.reading + byCategory.math + byCategory.encyclopedia + byCategory.couplets + byCategory.sentences + byCategory.book;

  const streak = useMemo(()=>computeStreak(hist), [hist]);
  const today = todayKey();
  const oneDay = 1000 * 60 * 60 * 24;

  // Today's progress per category (summing all languages)
  const todayData = { reading: 0, math: 0, encyclopedia: 0, couplets: 0, sentences: 0, book: 0 };
  const todayHist = hist[today] || {};
  Object.entries(todayHist).forEach(([k, count]) => {
    const [cat] = k.split(":");
    if (todayData[cat] !== undefined) todayData[cat] += count;
  });

  const StatCard = ({ label, value, emoji, big }) => (
    <div style={{flex:1,background:"#fff",border:"2px solid #f0f0f0",borderRadius:18,padding:"16px 14px",textAlign:"center",minWidth:0}}>
      <div style={{fontSize:big?30:22,marginBottom:4}}>{emoji}</div>
      <div style={{fontFamily:"'Fredoka One','Baloo 2',cursive",fontSize:big?32:22,color:RED,lineHeight:1}}>{value}</div>
      <div style={{fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:11,color:"#aaa",marginTop:4,textTransform:"uppercase",letterSpacing:.5}}>{label}</div>
    </div>
  );

  const dayLabel = (d) => {
    const dt = new Date(d + "T00:00:00");
    if (d === today) return "today";
    const diff = Math.round((new Date(today+"T00:00:00") - dt) / oneDay);
    if (diff === 1) return "yesterday";
    if (diff < 7) return dt.toLocaleDateString(undefined, { weekday:"long" }).toLowerCase();
    return dt.toLocaleDateString(undefined, { month:"short", day:"numeric" }).toLowerCase();
  };

  const TodayRow = ({ label, emoji, done }) => (
    <div style={{display:"flex",alignItems:"center",gap:12,padding:"10px 14px",background:"#fafafa",borderRadius:14}}>
      <span style={{fontSize:22}}>{emoji}</span>
      <span style={{flex:1,fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:14,color:"#333"}}>{label}</span>
      <div style={{display:"flex",gap:5}}>
        {[1,2,3].map(i => (
          <div key={i} style={{width:10,height:10,borderRadius:"50%",background:i<=done?RED:"#e0e0e0"}}/>
        ))}
      </div>
    </div>
  );

  // Get per-language summary for a day
  const dayByLang = (day) => {
    const langs = {};
    Object.entries(day||{}).forEach(([k, c]) => {
      const [, lang] = k.split(":");
      if (lang) langs[lang] = (langs[lang] || 0) + c;
    });
    return langs;
  };

  // Sort languages by total sessions descending
  const languageEntries = Object.entries(byLanguage).sort((a,b)=>b[1]-a[1]);

  return (
    <div style={{minHeight:"100vh",background:"#fff",display:"flex",flexDirection:"column"}}>
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",padding:"14px 18px",borderBottom:"1px solid #f5f5f5"}}>
        <button onClick={onBack} style={{background:"#f5f5f5",border:"none",borderRadius:50,width:38,height:38,fontSize:17,cursor:"pointer",color:"#555",display:"flex",alignItems:"center",justifyContent:"center"}}>←</button>
        <div style={{textAlign:"center"}}>
          <h2 style={{fontFamily:"'Fredoka One','Baloo 2',cursive",fontSize:18,color:"#111",margin:0}}>{t("Progress")}</h2>
          {child && (
            <p style={{fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:11,color:"#aaa",margin:"2px 0 0"}}>
              {child.avatarPhoto ? "👶" : child.emoji} {child.name}
              {ageFromBirthdate(child.birthdate) && (
                <span style={{color:RED}}> · {ageFromBirthdate(child.birthdate).label}</span>
              )}
            </p>
          )}
        </div>
        <div style={{width:38}}/>
      </div>

      <div style={{flex:1,overflowY:"auto",padding:"18px 18px 32px"}}>
        {grandTotal === 0 ? (
          <div style={{textAlign:"center",padding:"60px 24px"}}>
            <div style={{fontSize:56,marginBottom:12}}>🌱</div>
            <p style={{fontFamily:"'Fredoka One','Baloo 2',cursive",fontSize:22,color:"#111",marginBottom:8}}>{t("No sessions yet")}</p>
            <p style={{fontFamily:"Nunito,sans-serif",fontWeight:700,fontSize:14,color:"#aaa",maxWidth:280,margin:"0 auto",lineHeight:1.4}}>
              Tap Reading, Math, or Knowledge to get started!
            </p>
          </div>
        ) : (
          <>
            <div style={{display:"flex",gap:10,marginBottom:18}}>
              <StatCard label="day" value={dayNum} emoji="🗓️" big/>
              <StatCard label="streak" value={streak} emoji="🔥" big/>
              <StatCard label="sessions" value={grandTotal} emoji="⭐" big/>
            </div>

            {/* CEFR-adjacent vocabulary milestone */}
            {(() => {
              const vocab = countUniqueWordsExposed(hist);
              const milestone = cefrForVocabCount(vocab);
              const age = ageFromBirthdate(child?.birthdate);
              return (
                <div style={{marginBottom:22,background:"linear-gradient(135deg,#FFF0F1 0%,#FFE4E6 100%)",border:`2px solid ${RED}`,borderRadius:18,padding:"16px 18px"}}>
                  <div style={{display:"flex",alignItems:"center",gap:12,marginBottom:6}}>
                    <span style={{fontSize:28}}>🎓</span>
                    <div style={{flex:1}}>
                      <div style={{fontFamily:"'Fredoka One','Baloo 2',cursive",fontSize:18,color:RED,lineHeight:1.1}}>{milestone.babyLabel}</div>
                      <div style={{fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:11,color:"#888",marginTop:3,letterSpacing:.3}}>{milestone.level}</div>
                      <div style={{fontFamily:"Nunito,sans-serif",fontWeight:700,fontSize:11,color:"#999",marginTop:3}}>{milestone.description}</div>
                    </div>
                    <div style={{textAlign:"right"}}>
                      <div style={{fontFamily:"'Fredoka One','Baloo 2',cursive",fontSize:20,color:RED,lineHeight:1}}>~{vocab}</div>
                      <div style={{fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:10,color:"#aaa",textTransform:"uppercase",letterSpacing:.5}}>words</div>
                    </div>
                  </div>
                  {age && child?.name && vocab > 0 && (
                    <div style={{marginTop:10,padding:"10px 12px",background:"#fff",borderRadius:12,fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:13,color:"#444",textAlign:"center",lineHeight:1.35}}>
                      ✨ {child.name} has learned <span style={{color:RED}}>{vocab}</span> words at <span style={{color:RED}}>{age.label.replace(" old","")}</span>!
                    </div>
                  )}
                  <div style={{fontFamily:"Nunito,sans-serif",fontWeight:700,fontSize:10,color:"#999",lineHeight:1.4,marginTop:8,fontStyle:"italic"}}>
                    Vocabulary exposure mapped to CEFR vocabulary-size thresholds. Not a formal assessment.
                  </div>
                </div>
              );
            })()}

            {/* Per-language CEFR breakdown — only renders when at least one
                language has recorded word-session exposure. Shows one compact
                row per language with its own CEFR level + vocab count so
                parents can see progress in each language separately. */}
            {(() => {
              const perLang = languagesWithVocabProgress(hist);
              if (perLang.length === 0) return null;
              return (
                <div style={{marginBottom:22}}>
                  <h3 style={{fontFamily:"'Fredoka One','Baloo 2',cursive",fontSize:15,color:"#111",marginBottom:10,paddingLeft:4}}>
                    progress by language
                  </h3>
                  <div style={{display:"flex",flexDirection:"column",gap:8}}>
                    {perLang.map(({ language: lang, vocab }) => {
                      const m = cefrForVocabCount(vocab);
                      return (
                        <div key={lang} style={{display:"flex",alignItems:"center",gap:12,background:"#fff",border:"1px solid #eee",borderRadius:14,padding:"12px 14px"}}>
                          <div style={{flex:1,minWidth:0}}>
                            <div style={{fontFamily:"'Fredoka One','Baloo 2',cursive",fontSize:15,color:"#111",lineHeight:1.1}}>{lang}</div>
                            <div style={{fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:11,color:RED,marginTop:3}}>{m.babyLabel}</div>
                            <div style={{fontFamily:"Nunito,sans-serif",fontWeight:700,fontSize:10,color:"#999",marginTop:1}}>{m.level}</div>
                          </div>
                          <div style={{textAlign:"right",flexShrink:0}}>
                            <div style={{fontFamily:"'Fredoka One','Baloo 2',cursive",fontSize:15,color:RED,lineHeight:1}}>~{vocab}</div>
                            <div style={{fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:10,color:"#aaa",marginTop:2}}>words</div>
                          </div>
                        </div>
                      );
                    })}
                  </div>
                </div>
              );
            })()}

            {/* ── GRADUATIONS ─────────────────────────────────────────────────
                Show all the classes the child has graduated, with the
                language(s) they graduated in. Only renders when there is at
                least one graduation to celebrate. */}
            {(() => {
              const graduations = AVAILABLE_CLASSES
                .map(c => ({
                  classMeta: c,
                  langs: getGraduatedLanguages(child, c.id),
                }))
                .filter(g => g.langs.length > 0);
              if (graduations.length === 0) return null;
              return (
                <div style={{marginBottom:22}}>
                  <h3 style={{fontFamily:"'Fredoka One','Baloo 2',cursive",fontSize:15,color:"#111",marginBottom:10,paddingLeft:4}}>
                    🎓 graduations
                  </h3>
                  <div style={{display:"flex",flexDirection:"column",gap:8}}>
                    {graduations.map(({ classMeta, langs }) => (
                      <div key={classMeta.id}
                        style={{display:"flex",alignItems:"center",gap:12,background:"linear-gradient(135deg,#FFF0F1 0%,#FFE4E6 100%)",border:`2px solid ${RED}`,borderRadius:14,padding:"12px 14px"}}>
                        <span style={{fontSize:24}}>{classMeta.emoji}</span>
                        <div style={{flex:1,minWidth:0}}>
                          <div style={{fontFamily:"'Fredoka One','Baloo 2',cursive",fontSize:14,color:RED,lineHeight:1.1}}>
                            {classMeta.label} 🎓
                          </div>
                          <div style={{fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:11,color:"#666",marginTop:3,lineHeight:1.4}}>
                            Graduated in {langs.join(", ")}
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              );
            })()}

            <div style={{marginBottom:22}}>
              <h3 style={{fontFamily:"'Fredoka One','Baloo 2',cursive",fontSize:15,color:"#111",marginBottom:10,paddingLeft:4}}>today</h3>
              <div style={{display:"flex",flexDirection:"column",gap:8}}>
                {(() => {
                  const dayNum = getDayNumber();
                  return (
                    <>
                      <TodayRow label="Reading" emoji="📖" done={todayData.reading}/>
                      {dayNum >= 31 && <TodayRow label="Couplets" emoji="📝" done={todayData.couplets||0}/>}
                      {dayNum >= 61 && <TodayRow label="Sentences" emoji="✍️" done={todayData.sentences||0}/>}
                      {dayNum >= 91 && <TodayRow label="Book" emoji="📚" done={todayData.book||0}/>}
                      <TodayRow label="Math" emoji="🔢" done={todayData.math}/>
                      <TodayRow label="Knowledge" emoji="🌍" done={todayData.encyclopedia}/>
                    </>
                  );
                })()}
              </div>
            </div>

            <div style={{marginBottom:22}}>
              <h3 style={{fontFamily:"'Fredoka One','Baloo 2',cursive",fontSize:15,color:"#111",marginBottom:10,paddingLeft:4}}>by category</h3>
              <div style={{display:"flex",gap:10,flexWrap:"wrap"}}>
                <StatCard label="reading" value={byCategory.reading} emoji="📖"/>
                <StatCard label="math" value={byCategory.math} emoji="🔢"/>
                <StatCard label="knowledge" value={byCategory.encyclopedia} emoji="🌍"/>
              </div>
            </div>

            {languageEntries.length > 0 && (
              <div style={{marginBottom:22}}>
                <h3 style={{fontFamily:"'Fredoka One','Baloo 2',cursive",fontSize:15,color:"#111",marginBottom:10,paddingLeft:4}}>by language</h3>
                <div style={{display:"flex",flexDirection:"column",gap:6}}>
                  {languageEntries.map(([lang, count])=>{
                    const maxCount = languageEntries[0][1];
                    const pct = Math.max(8, (count/maxCount)*100);
                    return (
                      <div key={lang} style={{display:"flex",alignItems:"center",gap:12,padding:"10px 14px",background:"#fafafa",borderRadius:12}}>
                        <span style={{flex:"0 0 110px",fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:13,color:"#333"}}>{lang}</span>
                        <div style={{flex:1,height:8,background:"#efefef",borderRadius:4,overflow:"hidden"}}>
                          <div style={{height:"100%",width:`${pct}%`,background:RED,borderRadius:4,transition:"width .4s"}}/>
                        </div>
                        <span style={{fontFamily:"'Fredoka One','Baloo 2',cursive",fontSize:14,color:RED,minWidth:26,textAlign:"right"}}>{count}</span>
                      </div>
                    );
                  })}
                </div>
              </div>
            )}

            <div>
              <h3 style={{fontFamily:"'Fredoka One','Baloo 2',cursive",fontSize:15,color:"#111",marginBottom:10,paddingLeft:4}}>recent days</h3>
              <div style={{display:"flex",flexDirection:"column",gap:6}}>
                {dates.slice(0,14).map(d => {
                  const day = hist[d];
                  let total = 0;
                  Object.values(day).forEach(v => { total += v; });
                  const langs = Object.entries(dayByLang(day)).sort((a,b)=>b[1]-a[1]).slice(0,3);
                  return (
                    <div key={d} style={{display:"flex",alignItems:"center",gap:12,padding:"10px 14px",background:"#fafafa",borderRadius:12}}>
                      <span style={{flex:"0 0 88px",fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:13,color:"#555",textTransform:"capitalize"}}>{dayLabel(d)}</span>
                      <span style={{flex:1,fontFamily:"Nunito,sans-serif",fontWeight:700,fontSize:11,color:"#aaa",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>
                        {langs.map(([l,c]) => `${l} ${c}`).join(" · ") || "—"}
                      </span>
                      <span style={{fontFamily:"'Fredoka One','Baloo 2',cursive",fontSize:14,color:total>=9?RED:"#bbb",minWidth:22,textAlign:"right"}}>{total}</span>
                    </div>
                  );
                })}
              </div>
            </div>
          </>
        )}
      </div>
    </div>
  );
}

// ── MODALS ────────────────────────────────────────────────────────────────────

function Sheet({ onClose, children }) {
  return (
    <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,.4)",zIndex:200,display:"flex",alignItems:"flex-end",justifyContent:"center"}} onClick={onClose}>
      <div onClick={e=>e.stopPropagation()} style={{background:"#fff",borderRadius:"28px 28px 0 0",width:"100%",maxWidth:480,maxHeight:"82vh",display:"flex",flexDirection:"column"}}>
        {children}
      </div>
    </div>
  );
}

function LanguagePicker({ selected, onSelect, onClose }) {
  const [q, setQ] = useState("");
  const filtered = LANGUAGES.filter(l=>l.toLowerCase().includes(q.toLowerCase()));
  return (
    <Sheet onClose={onClose}>
      <div style={{padding:"22px 22px 14px",borderBottom:"1px solid #f0f0f0"}}>
        <h2 style={{fontFamily:"'Fredoka One','Baloo 2',cursive",fontSize:24,color:"#111",margin:"0 0 10px"}}>🌍 Choose Language</h2>
        <input autoFocus value={q} onChange={e=>setQ(e.target.value)} placeholder="Search languages…"
          style={{width:"100%",padding:"10px 14px",borderRadius:12,border:"2px solid #eee",fontSize:15,fontFamily:"Nunito,sans-serif",fontWeight:700,outline:"none",boxSizing:"border-box"}}
          onFocus={e=>e.target.style.borderColor=RED} onBlur={e=>e.target.style.borderColor="#eee"}/>
      </div>
      <div style={{overflowY:"auto",flex:1,paddingBottom:28}}>
        {filtered.map(lang=>(
          <button key={lang} onClick={()=>{onSelect(lang);onClose();}}
            style={{display:"block",width:"100%",textAlign:"left",padding:"12px 22px",border:"none",background:selected===lang?"#FFF0F1":"transparent",color:selected===lang?RED:"#333",fontFamily:"Nunito,sans-serif",fontWeight:700,fontSize:15,cursor:"pointer",borderLeft:selected===lang?`4px solid ${RED}`:"4px solid transparent"}}>
            {lang}{selected===lang?" ✓":""}
          </button>
        ))}
      </div>
    </Sheet>
  );
}

// Simpler language picker limited to the active child's enabled languages
function ChildLanguagePicker({ languages, selected, onSelect, onEditLanguages, onClose, child }) {
  useParentLang();
  // Show all of the child's languages — even those without class enrollments.
  // When the user picks an unenrolled language, the home screen shows a clear
  // "Not enrolled yet" CTA that points to the profile editor. (Per Olivia's
  // request 2026-04: keep the picker complete; let the home screen do the
  // explaining.)
  return (
    <Sheet onClose={onClose}>
      <div style={{padding:"22px 22px 14px",borderBottom:"1px solid #f0f0f0"}}>
        <h2 style={{fontFamily:"'Fredoka One','Baloo 2',system-ui,sans-serif",fontSize:24,color:"#111",margin:0}}>🌍 {t("Language for this session")}</h2>
        <p style={{fontFamily:"Nunito,sans-serif",fontWeight:700,fontSize:12,color:"#aaa",margin:"6px 0 0"}}>{t("Choose from your child's languages")}</p>
      </div>
      <div style={{overflowY:"auto",flex:1,paddingBottom:16}}>
        {languages.map(lang=>{
          const enrolledLangs = child ? getEnrolledLanguages(child) : languages;
          const enrolled = enrolledLangs.includes(lang);
          return (
            <button key={lang} onClick={()=>{onSelect(lang);onClose();}}
              style={{display:"flex",alignItems:"center",justifyContent:"space-between",width:"100%",textAlign:"left",padding:"13px 22px",border:"none",background:selected===lang?"#FFF0F1":"transparent",color:selected===lang?RED:"#333",fontFamily:"Nunito,sans-serif",fontWeight:700,fontSize:15,cursor:"pointer",borderLeft:selected===lang?`4px solid ${RED}`:"4px solid transparent"}}>
              <span style={{display:"flex",alignItems:"center",gap:8}}>
                <span style={{fontSize:15}}>{flagFor(lang)}</span>
                <span>{lang}</span>
                {!enrolled && (
                  <span style={{fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:9,color:"#bbb",letterSpacing:.4,textTransform:"uppercase",marginLeft:4}}>
                    not enrolled
                  </span>
                )}
              </span>
              {selected===lang && <span style={{fontSize:14}}>✓</span>}
            </button>
          );
        })}
      </div>
      <div style={{padding:"12px 22px 22px",borderTop:"1px solid #f0f0f0"}}>
        <button onClick={()=>{onClose();onEditLanguages();}}
          style={{width:"100%",background:"#f5f5f5",border:"2px dashed #ccc",borderRadius:50,padding:"10px 18px",cursor:"pointer",fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:13,color:"#666"}}>
          + manage child's languages
        </button>
      </div>
    </Sheet>
  );
}


function MathStagePicker({ selected, onSelect, onClose }) {
  return (
    <Sheet onClose={onClose}>
      <div style={{padding:"22px 22px 14px",borderBottom:"1px solid #f0f0f0"}}>
        <h2 style={{fontFamily:"'Fredoka One','Baloo 2',cursive",fontSize:24,color:"#111",margin:0}}>🔢 Math Level</h2>
        <p style={{fontFamily:"Nunito,sans-serif",fontWeight:700,fontSize:12,color:"#bbb",margin:"5px 0 0"}}>Parent-controlled progression</p>
      </div>
      <div style={{overflowY:"auto",flex:1,padding:"6px 0 28px"}}>
        {MATH_STAGES.map((s,i)=>(
          <button key={s.id} onClick={()=>{onSelect(s.id);onClose();}}
            style={{display:"flex",alignItems:"center",gap:14,width:"100%",textAlign:"left",padding:"14px 22px",border:"none",background:selected===s.id?"#FFF0F1":"transparent",cursor:"pointer",borderLeft:selected===s.id?`4px solid ${RED}`:"4px solid transparent"}}>
            <div style={{width:28,height:28,borderRadius:"50%",background:selected===s.id?RED:"#f0f0f0",color:selected===s.id?"#fff":"#999",display:"flex",alignItems:"center",justifyContent:"center",fontFamily:"'Fredoka One','Baloo 2',cursive",fontSize:13,flexShrink:0}}>{i+1}</div>
            <div>
              <div style={{fontFamily:"'Fredoka One','Baloo 2',cursive",fontSize:17,color:selected===s.id?RED:"#222"}}>{s.label}</div>
              <div style={{fontFamily:"Nunito,sans-serif",fontWeight:700,fontSize:11,color:"#bbb"}}>{s.desc}</div>
            </div>
          </button>
        ))}
      </div>
    </Sheet>
  );
}

// ── CHILD AVATAR PICKER ──────────────────────────────────────────────────────

const CHILD_EMOJIS = ["👶","🧒","👧","👦","🐣","🐥","🦊","🐻","🐨","🐼","🦁","🐰","🦄","🦋","🌸","⭐","🌟","🌈","🍎","🧚"];

// ── CLASSES (ENROLLMENT) ─────────────────────────────────────────────────────
// Parents enroll their child in specific "classes" during profile creation.
// Only enrolled classes appear on the home screen. When a child finishes an
// entire class, they can graduate — shows a 🎓 badge and celebrates completion.
//
// Default for new children: all classes enrolled (parent can uncheck).
// Default for existing children (backward compat): all classes enrolled.
const AVAILABLE_CLASSES = [
  { id:"reading",   label:"Reading",   emoji:"📖", desc:"Words, phrases, and stories · 0–6 years" },
  { id:"math",      label:"Math",      emoji:"🔢", desc:"Quantities and equations · 0–30 months" },
  { id:"knowledge", label:"Knowledge", emoji:"🌍", desc:"Facts about the world · 0–6 years" },
  // Music uses English-only note names (C, D, E, F, G, A, B) — translating
  // those into other languages doesn't make pedagogical sense (the international
  // standard for note literacy is the English letter system, even in non-English
  // music programs). Per Olivia: music tile only appears when "English" is the
  // active language, and enrollment is force-locked to ["English"].
  { id:"music",     label:"Music",     emoji:"🎵", desc:"Perfect pitch + rhythm training · 0–6 years", englishOnly:true },
];

// Enrollment data model — child.enrolledClasses can be either:
//   1. New format: { classId: [language, ...] } — per-language enrollment
//   2. Old format: [classId, ...] — applies to ALL the child's languages
//   3. Missing — defaults to all classes for all languages
// Helpers below normalize all three to the new format internally.

// Returns the enrollment as an object: { classId: [language, ...] }
function getEnrollmentMap(child) {
  if (!child) {
    // No child — return all classes for English only
    const map = {};
    AVAILABLE_CLASSES.forEach(c => { map[c.id] = ["English"]; });
    return map;
  }
  const langs = child.languages || ["English"];
  const ec = child.enrolledClasses;
  // New format: object
  if (ec && typeof ec === "object" && !Array.isArray(ec)) {
    return ec;
  }
  // Old format: array of class ids — applies to all child's languages
  if (Array.isArray(ec)) {
    const map = {};
    ec.forEach(cid => { map[cid] = [...langs]; });
    return map;
  }
  // Missing — default all classes to all child's languages
  const map = {};
  AVAILABLE_CLASSES.forEach(c => { map[c.id] = [...langs]; });
  return map;
}

// Returns the array of class ids the child has at least ONE language enrolled in.
function getEnrolledClasses(child) {
  const map = getEnrollmentMap(child);
  return AVAILABLE_CLASSES.map(c => c.id).filter(cid => (map[cid] || []).length > 0);
}

// Returns true if the child is enrolled in this class for ANY language
// (when no language is given) or for the specific language given.
function isClassEnrolled(child, classId, language) {
  const map = getEnrollmentMap(child);
  const langs = map[classId] || [];
  if (language) return langs.includes(language);
  return langs.length > 0;
}

// Returns the languages the child is enrolled in for this class.
function getClassLanguages(child, classId) {
  const map = getEnrollmentMap(child);
  return map[classId] || [];
}

// Returns the unique set of languages this child is enrolled in for ANY
// class. Used to filter the home-screen language picker so parents don't
// see languages with zero enrollments. Music is excluded from the
// per-language enrollment set since music is English-only and would
// otherwise pollute the list.
function getEnrolledLanguages(child) {
  if (!child) return [];
  const map = getEnrollmentMap(child);
  const langs = new Set();
  for (const [classId, classLangs] of Object.entries(map)) {
    if (classId === "music") continue;
    for (const l of (classLangs || [])) langs.add(l);
  }
  return [...langs];
}

// Auto-detect whether a class is fully complete based on actual progress.
// Per user decision: "graduated" once ANY ONE enrolled language reaches the
// end of the curriculum for that class. This makes graduation an attainable
// celebration in multilingual families (the strict "all languages must be
// done" version was discouraging).
function isClassFullyComplete(child, classId) {
  if (!child) return false;
  const enrolledLangs = getClassLanguages(child, classId);
  if (enrolledLangs.length === 0) return false;
  const pos = (typeof migratePosition === "function") ? migratePosition(child.position) : (child.position || {});

  // Helper: did this child complete at least one book session in this language?
  // Reading isn't graduated until the child has practiced reading actual books.
  const hasCompletedBook = (lang) => {
    if (!child?.id) return false;
    try {
      const hist = JSON.parse(localStorage.getItem(`lb-history-${child.id}`) || "{}");
      // History keys are "category:language" → count
      for (const day of Object.values(hist)) {
        if (day[`book:${lang}`] && day[`book:${lang}`] > 0) return true;
      }
    } catch {}
    return false;
  };

  // Get the actual final-set index for a category in a given month.
  // Falls back to a safe high number if the curriculum data isn't accessible.
  const finalSetIdxFor = (category, month) => {
    const data = (
      category === "words"     ? WORDS_BY_MONTH :
      category === "couplets"  ? COUPLETS_BY_MONTH :
      category === "sentences" ? SENTENCES_BY_MONTH :
      category === "knowledge" ? KNOWLEDGE_BY_MONTH : null
    );
    if (!data) return 99;
    const monthSets = data[month];
    if (!monthSets) return -1;
    return monthSets.length - 1;
  };

  const langComplete = (lang, cls) => {
    const lp = pos[lang] || {};
    if (cls === "reading") {
      // Reading covers words → couplets → sentences → books. Graduation
      // requires ALL FOUR to be complete in this language:
      //   • Words at Month 3 final set
      //   • Couplets at Month 2 final set (Month 2 is the only month with couplets)
      //   • Sentences at Month 3 final set
      //   • At least one completed book session
      const w = lp.words || lp.reading;
      const wordsDone = w && w.month >= 3 && w.setIdx >= finalSetIdxFor("words", 3);
      const couplets = lp.couplets;
      const coupletsDone = couplets && couplets.month >= 2 && couplets.setIdx >= finalSetIdxFor("couplets", 2);
      const sentences = lp.sentences;
      const sentencesDone = sentences && sentences.month >= 3 && sentences.setIdx >= finalSetIdxFor("sentences", 3);
      const bookDone = hasCompletedBook(lang);
      return wordsDone && coupletsDone && sentencesDone && bookDone;
    }
    if (cls === "math") return (getMathStageId(lp.math) === "eq-both");
    if (cls === "knowledge") {
      const k = lp.knowledge;
      if (!k) return false;
      return (k.month >= 3) && (k.setIdx >= finalSetIdxFor("knowledge", 3));
    }
    if (cls === "music") {
      const lastScale  = MUSIC_SCALES[MUSIC_SCALES.length - 1]?.id;
      const lastRhythm = RHYTHM_STAGES[RHYTHM_STAGES.length - 1]?.id;
      return lp.music === lastScale && lp.rhythm === lastRhythm;
    }
    return false;
  };

  // ANY one enrolled language complete = graduated
  return enrolledLangs.some(lang => langComplete(lang, classId));
}

// Returns the language(s) in which the child has graduated this class.
// Used by the progress screen to show "🎓 Graduated in English"
function getGraduatedLanguages(child, classId) {
  if (!child) return [];
  const enrolledLangs = getClassLanguages(child, classId);
  const pos = (typeof migratePosition === "function") ? migratePosition(child.position) : (child.position || {});

  // Same strict checks as isClassFullyComplete — kept in sync intentionally.
  const hasCompletedBook = (lang) => {
    if (!child?.id) return false;
    try {
      const hist = JSON.parse(localStorage.getItem(`lb-history-${child.id}`) || "{}");
      for (const day of Object.values(hist)) {
        if (day[`book:${lang}`] && day[`book:${lang}`] > 0) return true;
      }
    } catch {}
    return false;
  };
  const finalSetIdxFor = (category, month) => {
    const data = (
      category === "words"     ? WORDS_BY_MONTH :
      category === "couplets"  ? COUPLETS_BY_MONTH :
      category === "sentences" ? SENTENCES_BY_MONTH :
      category === "knowledge" ? KNOWLEDGE_BY_MONTH : null
    );
    if (!data) return 99;
    const monthSets = data[month];
    if (!monthSets) return -1;
    return monthSets.length - 1;
  };

  return enrolledLangs.filter(lang => {
    const lp = pos[lang] || {};
    if (classId === "reading") {
      const w = lp.words || lp.reading;
      const wordsDone = w && w.month >= 3 && w.setIdx >= finalSetIdxFor("words", 3);
      const couplets = lp.couplets;
      const coupletsDone = couplets && couplets.month >= 2 && couplets.setIdx >= finalSetIdxFor("couplets", 2);
      const sentences = lp.sentences;
      const sentencesDone = sentences && sentences.month >= 3 && sentences.setIdx >= finalSetIdxFor("sentences", 3);
      const bookDone = hasCompletedBook(lang);
      return wordsDone && coupletsDone && sentencesDone && bookDone;
    }
    if (classId === "math") return getMathStageId(lp.math) === "eq-both";
    if (classId === "knowledge") {
      const k = lp.knowledge;
      return k && k.month >= 3 && k.setIdx >= finalSetIdxFor("knowledge", 3);
    }
    if (classId === "music") {
      const lastScale  = MUSIC_SCALES[MUSIC_SCALES.length - 1]?.id;
      const lastRhythm = RHYTHM_STAGES[RHYTHM_STAGES.length - 1]?.id;
      return lp.music === lastScale && lp.rhythm === lastRhythm;
    }
    return false;
  });
}

function isClassGraduated(child, classId) {
  // Graduation is now auto-detected from progress, not stored as a flag.
  // We keep the function name + signature so existing call sites still work.
  return isClassFullyComplete(child, classId);
}

// ── ONBOARDING IMPORT (paste family code during setup) ───────────────────────

function OnboardingImport({ onImported, onBack }) {
  const [text, setText] = useState("");
  const [error, setError] = useState(null);
  const doImport = () => {
    const payload = decodeFamilyCode(text);
    if (!payload) {
      setError("Code is invalid. Make sure you copied the whole thing.");
      return;
    }
    applyFamilyPayload(payload);
    onImported();
  };
  return (
    <div style={{width:"100%",maxWidth:360,marginTop:20}}>
      <p style={{fontFamily:"Nunito,sans-serif",fontWeight:700,fontSize:13,color:"#666",textAlign:"center",lineHeight:1.5,marginBottom:14}}>
        Paste the family code shared with you. It starts with <strong>LB1-</strong>.
      </p>
      <textarea value={text} onChange={e=>{setText(e.target.value);setError(null);}} placeholder="LB1-eyJ2..."
        style={{width:"100%",minHeight:120,padding:"12px 14px",borderRadius:14,border:`2px solid ${error?RED:"#eee"}`,fontSize:12,fontFamily:"ui-monospace,SFMono-Regular,monospace",outline:"none",boxSizing:"border-box",resize:"vertical"}}/>
      {error && (
        <div style={{marginTop:8,padding:"10px 12px",background:"#FFF0F1",borderRadius:10,fontFamily:"Nunito,sans-serif",fontWeight:700,fontSize:12,color:RED}}>
          {error}
        </div>
      )}
      <div style={{display:"flex",gap:8,marginTop:14}}>
        <button onClick={onBack}
          style={{flex:1,background:"#f5f5f5",border:"none",borderRadius:50,padding:"12px 18px",cursor:"pointer",fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:14,color:"#666"}}>
          back
        </button>
        <button onClick={doImport} disabled={!text.trim()}
          style={{flex:2,background:text.trim()?RED:"#ddd",border:"none",borderRadius:50,padding:"12px 18px",cursor:text.trim()?"pointer":"not-allowed",fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:14,color:"#fff"}}>
          import family
        </button>
      </div>
    </div>
  );
}

// ── ONBOARDING (first-time setup) ────────────────────────────────────────────

function Onboarding({ onDone, premium, onPremiumNeeded }) {
  useParentLang();
  // Parent UI language picker shown FIRST, before anything else. Once they
  // pick a language we store it and use it as the default for child lang too.
  const [step, setStep] = useState(() => getParentLanguage() ? 0 : "parent-lang");
  const [parentLang, setParentLangState] = useState(() => getParentLanguage() || "English");
  const [children, setChildren] = useState([]);
  const [name, setName] = useState("");
  const [birthdate, setBirthdate] = useState("");
  const [emoji, setEmoji] = useState(CHILD_EMOJIS[0]);
  // Optional photo avatar — parents can use a real photo of their child
  // instead of (or in addition to) an emoji. The photo also gets stored as
  // the family-photos "baby" slot so the "baby" word card uses the same
  // photo automatically. Per Olivia's design: simpler than two separate slots.
  const [avatarPhoto, setAvatarPhoto] = useState(null);
  const [gender, setGender] = useState("prefer");
  // Default the child's languages to whatever the parent speaks (so the
  // initial setup lands in the parent's native experience). They can add
  // more languages in the picker.
  const [langs, setLangs] = useState(() => [getParentLanguage() || "English"]);
  const [showLangPicker, setShowLangPicker] = useState(false);
  // Search filter for parent language picker
  const [parentLangQuery, setParentLangQuery] = useState("");
  // Enrollment built during onboarding — defaults to all classes for all languages
  const [enrollment, setEnrollment] = useState(null);
  // Family photos uploaded during onboarding for THIS child
  const [photoUploads, setPhotoUploads] = useState({});
  const [photoError, setPhotoError] = useState("");

  const handleChildFormDone = () => {
    if (!name.trim()) return;
    // Default all classes to all selected languages — parents can adjust on next screen
    const defaultEnroll = {};
    AVAILABLE_CLASSES.forEach(c => { defaultEnroll[c.id] = [...langs]; });
    setEnrollment(defaultEnroll);
    setStep(1.5);
  };

  const persistChildAndAdvance = () => {
    if (!name.trim()) return;
    const id = newChildId();
    const child = {
      id,
      name: name.trim(),
      emoji,
      // If parent uploaded a photo, store it on the child object so the
      // home screen + profile show the photo as the avatar.
      avatarPhoto: avatarPhoto || null,
      gender,
      birthdate: birthdate || null,
      languages: langs.length ? langs : ["English"],
      enrolledClasses: enrollment || undefined,
      createdAt: Date.now(),
    };
    // Persist photos to localStorage for this child id
    try {
      const photoMap = {};
      Object.entries(photoUploads).forEach(([slot, dataUrl]) => {
        if (dataUrl) photoMap[slot] = dataUrl;
      });
      // Avatar photo also serves as the "baby" family photo — same slot,
      // simpler mental model. If parent uploaded a separate baby slot photo
      // earlier, that takes precedence (parent already explicitly chose).
      if (avatarPhoto && !photoMap.baby) {
        photoMap.baby = avatarPhoto;
      }
      if (Object.keys(photoMap).length > 0) {
        localStorage.setItem(`lb-photos-${id}`, JSON.stringify(photoMap));
      }
    } catch {}
    const next = [...children, child];
    setChildren(next);
    // Reset for next child
    setName(""); setBirthdate("");
    setEmoji(CHILD_EMOJIS[next.length % CHILD_EMOJIS.length]);
    setAvatarPhoto(null);
    setGender("prefer");
    setLangs(["English"]);
    setEnrollment(null);
    setPhotoUploads({});
    setPhotoError("");
    setStep(3);
  };

  const finish = () => {
    saveChildren(children);
    if (children.length) setActiveChildId(children[0].id);
    onDone();
  };

  const toggleLang = (l) => {
    setLangs(prev => prev.includes(l) ? prev.filter(x=>x!==l) : [...prev, l]);
  };

  return (
    <div style={{minHeight:"100vh",background:"#fff",display:"flex",flexDirection:"column",alignItems:"center",padding:"36px 24px",overflowY:"auto"}}>
      <img src={LOGO_SRC} alt="" style={{width:110,height:"auto",objectFit:"contain",marginBottom:8}}/>
      <h1 style={{fontSize:30,color:"#111",margin:0,fontFamily:"'Fredoka One','Baloo 2',system-ui,sans-serif",letterSpacing:-.5,textAlign:"center"}}>Limitless Babies</h1>

      {step === "parent-lang" && (
        <>
          <div style={{fontSize:48,marginTop:18,marginBottom:4}}>👋</div>
          <p style={{color:"#111",fontFamily:"Nunito,sans-serif",fontSize:18,marginTop:8,fontWeight:800,textAlign:"center",maxWidth:340,lineHeight:1.3}}>
            {parentLang ? tLookup("What language do you speak?", parentLang) : "What language do you speak?"}
          </p>
          <p style={{color:"#888",fontFamily:"Nunito,sans-serif",fontSize:13,marginTop:6,fontWeight:700,textAlign:"center",maxWidth:320,lineHeight:1.5}}>
            {parentLang ? tLookup("We'll use this for the app interface and as the starting language for your child. You can change it later.", parentLang) : "We'll use this for the app interface and as the starting language for your child. You can change it later."}
          </p>

          <input
            value={parentLangQuery}
            onChange={e=>setParentLangQuery(e.target.value)}
            placeholder={parentLang ? tLookup("Search languages…", parentLang) : "Search languages…"}
            style={{width:"100%",maxWidth:360,marginTop:18,padding:"12px 16px",borderRadius:14,border:"2px solid #eee",fontSize:15,fontFamily:"Nunito,sans-serif",fontWeight:700,outline:"none",boxSizing:"border-box"}}
            onFocus={e=>e.target.style.borderColor=RED}
            onBlur={e=>e.target.style.borderColor="#eee"}
          />

          <div style={{width:"100%",maxWidth:360,marginTop:14,maxHeight:"45vh",overflowY:"auto",border:"1px solid #f0f0f0",borderRadius:14,boxShadow:"0 2px 12px rgba(0,0,0,.04)"}}>
            {LANGUAGES
              .filter(l => l.toLowerCase().includes(parentLangQuery.toLowerCase()))
              .map(l => (
                <button key={l} onClick={()=>setParentLangState(l)}
                  style={{display:"flex",alignItems:"center",justifyContent:"space-between",width:"100%",textAlign:"left",padding:"11px 16px",border:"none",borderBottom:"1px solid #fafafa",background:parentLang===l?"#FFF0F1":"transparent",color:parentLang===l?RED:"#333",fontFamily:"Nunito,sans-serif",fontWeight:700,fontSize:14,cursor:"pointer"}}>
                  <span style={{display:"flex",alignItems:"center",gap:10}}>
                    <span style={{fontSize:16}}>{flagFor(l)}</span>
                    <span>{l}</span>
                  </span>
                  {parentLang===l && <span style={{fontSize:16}}>✓</span>}
                </button>
              ))}
          </div>

          <button
            onClick={()=>{
              setParentLanguage(parentLang);
              // Pre-fill the child language picker with the parent's language
              setLangs([parentLang]);
              setStep(0);
            }}
            style={{marginTop:24,background:RED,border:"none",borderRadius:50,padding:"14px 36px",cursor:"pointer",fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:15,color:"#fff",boxShadow:"0 6px 20px rgba(232,25,44,.25)"}}>
            {parentLang ? tLookup("continue →", parentLang) : "continue →"}
          </button>
        </>
      )}

      {step === 0 && (
        <>
          <p style={{color:"#666",fontFamily:"Nunito,sans-serif",fontSize:15,marginTop:16,fontWeight:700,textAlign:"center",maxWidth:320,lineHeight:1.5}}>
            {t("Welcome! Let's set up profiles for your little learners. You can add as many children and languages as you'd like.")}
          </p>
          <button onClick={()=>setStep(1)}
            style={{marginTop:36,background:RED,border:"none",borderRadius:50,padding:"14px 36px",cursor:"pointer",fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:15,color:"#fff",boxShadow:"0 6px 20px rgba(232,25,44,.25)"}}>
            {t("get started →")}
          </button>
          <button onClick={()=>setStep("import")}
            style={{marginTop:14,background:"none",border:"none",cursor:"pointer",fontFamily:"Nunito,sans-serif",fontWeight:700,fontSize:13,color:"#aaa",textDecoration:"underline"}}>
            {t("I have a family code")}
          </button>
        </>
      )}

      {step === "import" && (
        <OnboardingImport onImported={onDone} onBack={()=>setStep(0)}/>
      )}

      {step === 1 && (
        <>
          <p style={{color:"#888",fontFamily:"Nunito,sans-serif",fontSize:13,marginTop:8,fontWeight:700,textAlign:"center"}}>
            {children.length === 0 ? "First child" : `Child ${children.length + 1}`}
          </p>

          <div style={{width:"100%",maxWidth:360,marginTop:24}}>
            <label style={{display:"block",fontFamily:"Nunito,sans-serif",fontSize:12,fontWeight:800,color:"#999",marginBottom:6,letterSpacing:.5,textTransform:"uppercase"}}>{t("Name")}</label>
            <input value={name} onChange={e=>setName(e.target.value)} placeholder="e.g., Lily"
              style={{width:"100%",padding:"13px 16px",borderRadius:14,border:"2px solid #eee",fontSize:16,fontFamily:"Nunito,sans-serif",fontWeight:700,outline:"none",boxSizing:"border-box"}}
              onFocus={e=>e.target.style.borderColor=RED} onBlur={e=>e.target.style.borderColor="#eee"}/>
          </div>

          <div style={{width:"100%",maxWidth:360,marginTop:18}}>
            <label style={{display:"block",fontFamily:"Nunito,sans-serif",fontSize:12,fontWeight:800,color:"#999",marginBottom:6,letterSpacing:.5,textTransform:"uppercase"}}>{t("Birthdate")}</label>
            <input type="date" value={birthdate} onChange={e=>setBirthdate(e.target.value)} max={new Date().toISOString().slice(0,10)}
              style={{width:"100%",padding:"13px 16px",borderRadius:14,border:"2px solid #eee",fontSize:16,fontFamily:"Nunito,sans-serif",fontWeight:700,outline:"none",boxSizing:"border-box",color:birthdate?"#111":"#999"}}
              onFocus={e=>e.target.style.borderColor=RED} onBlur={e=>e.target.style.borderColor="#eee"}/>
            <p style={{fontFamily:"Nunito,sans-serif",fontSize:10,color:"#aaa",fontWeight:700,marginTop:6,lineHeight:1.4}}>
              Optional — used to track age-based milestones in the progress report.
            </p>
          </div>

          <div style={{width:"100%",maxWidth:360,marginTop:18}}>
            <label style={{display:"block",fontFamily:"Nunito,sans-serif",fontSize:12,fontWeight:800,color:"#999",marginBottom:6,letterSpacing:.5,textTransform:"uppercase"}}>{t("Gender")}</label>
            <div style={{display:"flex",gap:6}}>
              {[
                { id:"girl",   label:"Girl",   emoji:"👧" },
                { id:"boy",    label:"Boy",    emoji:"👦" },
                { id:"prefer", label:"Prefer not to say", emoji:"🤗" },
              ].map(g => (
                <button key={g.id} type="button" onClick={()=>setGender(g.id)}
                  style={{flex:1,padding:"10px 8px",borderRadius:12,border:`2px solid ${gender===g.id?RED:"#eee"}`,background:gender===g.id?"#FFF0F1":"#fff",cursor:"pointer",display:"flex",flexDirection:"column",alignItems:"center",gap:3,fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:10,color:gender===g.id?RED:"#666"}}>
                  <span style={{fontSize:18}}>{g.emoji}</span>
                  <span style={{lineHeight:1.1,textAlign:"center"}}>{g.label}</span>
                </button>
              ))}
            </div>
            <p style={{fontFamily:"Nunito,sans-serif",fontSize:10,color:"#aaa",fontWeight:700,marginTop:6,lineHeight:1.4}}>
              Used only for languages where words differ by speaker gender (e.g., Korean older sibling: 오빠/형). If you prefer not to say, both forms are shown.
            </p>
          </div>

          <div style={{width:"100%",maxWidth:360,marginTop:18}}>
            <label style={{display:"block",fontFamily:"Nunito,sans-serif",fontSize:12,fontWeight:800,color:"#999",marginBottom:8,letterSpacing:.5,textTransform:"uppercase"}}>{t("Avatar")}</label>

            {/* Avatar photo + emoji row. The photo upload acts as both the
                profile avatar AND the "baby" family photo (used on the
                'baby' word card) — same slot, simpler mental model. */}
            <div style={{display:"flex",alignItems:"center",gap:12,marginBottom:10}}>
              <label style={{cursor:"pointer",position:"relative",width:64,height:64,borderRadius:"50%",overflow:"hidden",background:"#fff",border:avatarPhoto?`3px solid ${RED}`:"3px dashed #ddd",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}>
                {avatarPhoto ? (
                  <img src={avatarPhoto} alt="" style={{width:"100%",height:"100%",objectFit:"cover"}}/>
                ) : (
                  <span style={{fontSize:28,opacity:.4}}>📷</span>
                )}
                <input type="file" accept="image/*"
                  onChange={async (e) => {
                    const f = e.target.files?.[0];
                    if (!f) return;
                    try {
                      const dataUrl = await compressImageFile(f);
                      setAvatarPhoto(dataUrl);
                    } catch (err) {
                      setPhotoError("Couldn't read that photo — try another.");
                    }
                    e.target.value = "";
                  }}
                  style={{position:"absolute",inset:0,opacity:0,cursor:"pointer"}}/>
              </label>
              <div style={{flex:1,minWidth:0}}>
                <div style={{fontFamily:"'Fredoka One','Baloo 2',cursive",fontSize:13,color:avatarPhoto?"#111":"#666",lineHeight:1.2}}>
                  {avatarPhoto ? "Photo of " + (name || "your child") : "Use a photo of " + (name || "your child") + "?"}
                </div>
                <div style={{fontFamily:"Nunito,sans-serif",fontWeight:700,fontSize:11,color:"#888",marginTop:3,lineHeight:1.45}}>
                  {avatarPhoto
                    ? <span><span style={{color:RED}}>✓ uploaded.</span> Also used on the "baby" flashcard.</span>
                    : "Tap the circle to upload. Or pick an emoji below."}
                </div>
                {avatarPhoto && (
                  <button type="button" onClick={()=>setAvatarPhoto(null)}
                    style={{background:"none",border:"none",padding:0,marginTop:4,fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:10,color:"#aaa",cursor:"pointer",textDecoration:"underline"}}>
                    remove photo
                  </button>
                )}
              </div>
            </div>

            {/* Emoji grid — used when no photo is uploaded. If both are set,
                photo takes precedence in display; emoji is preserved as a
                fallback for future use. */}
            <div style={{display:"flex",flexWrap:"wrap",gap:6,opacity:avatarPhoto?0.5:1}}>
              {CHILD_EMOJIS.map(e=>(
                <button key={e} onClick={()=>setEmoji(e)}
                  style={{width:44,height:44,fontSize:24,border:`2px solid ${emoji===e?RED:"#eee"}`,background:emoji===e?"#FFF0F1":"#fff",borderRadius:12,cursor:"pointer"}}>
                  {e}
                </button>
              ))}
            </div>
            <p style={{fontFamily:"Nunito,sans-serif",fontSize:10,color:"#aaa",fontWeight:700,marginTop:8,lineHeight:1.5}}>
              🔒 Photos stay on this device only — they never leave your phone.
            </p>
          </div>

          <div style={{width:"100%",maxWidth:360,marginTop:18}}>
            <label style={{display:"block",fontFamily:"Nunito,sans-serif",fontSize:12,fontWeight:800,color:"#999",marginBottom:8,letterSpacing:.5,textTransform:"uppercase"}}>
              Languages to learn ({langs.length})
            </label>
            <div style={{display:"flex",flexWrap:"wrap",gap:6,marginBottom:10}}>
              {langs.map(l=>(
                <div key={l} style={{display:"flex",alignItems:"center",gap:6,background:"#FFF0F1",border:`2px solid ${RED}`,borderRadius:50,padding:"6px 12px",fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:13,color:RED}}>
                  {l}
                  <button onClick={()=>toggleLang(l)} style={{background:"none",border:"none",cursor:"pointer",color:RED,padding:0,fontSize:14,lineHeight:1}}>×</button>
                </div>
              ))}
            </div>
            <button onClick={()=>setShowLangPicker(true)}
              style={{display:"flex",alignItems:"center",gap:6,background:"#f5f5f5",border:"2px dashed #ccc",borderRadius:50,padding:"8px 16px",cursor:"pointer",fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:13,color:"#666"}}>
              + add language
            </button>
          </div>

          <div style={{display:"flex",gap:10,marginTop:28}}>
            <button onClick={()=>setStep(0)}
              style={{background:"#f5f5f5",border:"none",borderRadius:50,padding:"12px 18px",cursor:"pointer",fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:14,color:"#666"}}>
              ←
            </button>
            {children.length > 0 && (
              <button onClick={()=>setStep(3)}
                style={{background:"#f5f5f5",border:"none",borderRadius:50,padding:"12px 22px",cursor:"pointer",fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:14,color:"#666"}}>
                skip
              </button>
            )}
            <button onClick={handleChildFormDone} disabled={!name.trim()}
              style={{background:name.trim()?RED:"#ddd",border:"none",borderRadius:50,padding:"12px 26px",cursor:name.trim()?"pointer":"not-allowed",fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:14,color:"#fff"}}>
              next →
            </button>
          </div>

          {showLangPicker && (
            <LanguageMultiPicker selected={langs} onToggle={toggleLang} onClose={()=>setShowLangPicker(false)} premium={premium} onPremiumNeeded={()=>{ setShowLangPicker(false); onPremiumNeeded && onPremiumNeeded(); }}/>
          )}
        </>
      )}

      {step === 1.5 && (
        <>
          <p style={{fontFamily:"'Fredoka One','Baloo 2',cursive",fontSize:22,color:"#111",marginTop:18,marginBottom:8,textAlign:"center"}}>
            Choose {name}'s classes
          </p>
          <p style={{fontFamily:"Nunito,sans-serif",fontWeight:700,fontSize:13,color:"#888",lineHeight:1.55,textAlign:"center",maxWidth:340,marginBottom:18}}>
            Pick which classes {name} will take, and in which languages. You can always change this later.
          </p>

          <div style={{width:"100%",maxWidth:380,display:"flex",flexDirection:"column",gap:10}}>
            {AVAILABLE_CLASSES.map(c => {
              const enrolledLangs = (enrollment && enrollment[c.id]) || [];
              const isOn = enrolledLangs.length > 0;
              const isMusic = c.id === "music";
              const subtitle = isMusic
                ? (isOn ? "Enabled · pitch + rhythm" : "Not enrolled")
                : (!isOn ? "Not enrolled"
                   : enrolledLangs.length === langs.length ? `All ${langs.length} ${langs.length === 1 ? "language" : "languages"}`
                   : `${enrolledLangs.length} of ${langs.length}: ${enrolledLangs.join(", ")}`);
              return (
                <div key={c.id} style={{borderRadius:16,border:`2px solid ${isOn?RED:"#eee"}`,background:isOn?"#FFF8F8":"#fafafa",overflow:"hidden"}}>
                  <button type="button"
                    onClick={() => {
                      if (isMusic) {
                        setEnrollment(prev => ({ ...prev, music: isOn ? [] : [...langs] }));
                      } else {
                        // Toggle: if currently all-enrolled, set to none; else set to all
                        setEnrollment(prev => ({
                          ...prev,
                          [c.id]: isOn && enrolledLangs.length === langs.length ? [] : [...langs]
                        }));
                      }
                    }}
                    style={{width:"100%",background:"none",border:"none",padding:"12px 14px",cursor:"pointer",display:"flex",alignItems:"center",gap:10,textAlign:"left"}}>
                    <span style={{fontSize:26,filter:isOn?"none":"grayscale(1)",opacity:isOn?1:.5}}>{c.emoji}</span>
                    <div style={{flex:1,minWidth:0}}>
                      <div style={{fontFamily:"'Fredoka One','Baloo 2',cursive",fontSize:14,color:isOn?"#111":"#999",lineHeight:1.15}}>{c.label}</div>
                      <div style={{fontFamily:"Nunito,sans-serif",fontWeight:700,fontSize:11,color:"#888",marginTop:3,lineHeight:1.4}}>{subtitle}</div>
                    </div>
                    <div style={{width:34,height:20,borderRadius:50,background:isOn?RED:"#ddd",position:"relative",flexShrink:0}}>
                      <div style={{position:"absolute",top:2,left:isOn?16:2,width:16,height:16,borderRadius:"50%",background:"#fff",transition:"left .2s",boxShadow:"0 1px 3px rgba(0,0,0,.2)"}}/>
                    </div>
                  </button>

                  {/* Per-language chips for non-music classes when more than 1 language selected */}
                  {!isMusic && isOn && langs.length > 1 && (
                    <div style={{padding:"4px 14px 12px"}}>
                      <div style={{display:"flex",flexWrap:"wrap",gap:5}}>
                        {langs.map(lang => {
                          const on = enrolledLangs.includes(lang);
                          return (
                            <button key={lang} type="button"
                              onClick={() => {
                                setEnrollment(prev => {
                                  const cur = new Set(prev[c.id] || []);
                                  if (cur.has(lang)) cur.delete(lang); else cur.add(lang);
                                  return { ...prev, [c.id]: Array.from(cur) };
                                });
                              }}
                              style={{
                                background:on?RED:"#fff",
                                color:on?"#fff":"#666",
                                border:`1.5px solid ${on?RED:"#ddd"}`,
                                borderRadius:50,padding:"5px 10px",cursor:"pointer",
                                fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:10,
                                display:"flex",alignItems:"center",gap:4,
                              }}>
                              {LANGUAGE_FLAGS[lang] && <span>{LANGUAGE_FLAGS[lang]}</span>}
                              <span>{lang}</span>
                            </button>
                          );
                        })}
                      </div>
                    </div>
                  )}
                </div>
              );
            })}
          </div>

          <div style={{display:"flex",gap:10,marginTop:24}}>
            <button onClick={()=>setStep(1)}
              style={{background:"#f5f5f5",border:"none",borderRadius:50,padding:"12px 22px",cursor:"pointer",fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:14,color:"#666"}}>
              ←
            </button>
            <button onClick={()=>setStep(2)}
              style={{background:RED,border:"none",borderRadius:50,padding:"12px 26px",cursor:"pointer",fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:14,color:"#fff"}}>
              next →
            </button>
          </div>
        </>
      )}

      {step === 2 && (() => {
        // Slots to upload during onboarding — exactly the first set of words
        // (Family Members) plus any kinship-distinguishing slots if relevant.
        const baseSlots = [
          { slot:"mother", label:"Mother",  emoji:"👩" },
          { slot:"father", label:"Father",  emoji:"👨" },
          { slot:"sister", label:"Sister",  emoji:"👧" },
          { slot:"brother",label:"Brother", emoji:"👦" },
          { slot:"baby",   label:"Baby",    emoji:"👶" },
        ];
        // Kinship-aware slots (if a learning language differentiates)
        const kinshipExtras = [];
        const usesKinship = (base) => langs.some(l => l !== "English" && KINSHIP_LANGUAGES.includes(l) && KINSHIP_VARIANTS[base]?.[l]);
        if (usesKinship("sister")) {
          kinshipExtras.push({ slot:"sister_older",   label:"Older sister",   emoji:"👩" });
          kinshipExtras.push({ slot:"sister_younger", label:"Younger sister", emoji:"👧" });
        }
        if (usesKinship("brother")) {
          kinshipExtras.push({ slot:"brother_older",   label:"Older brother",   emoji:"👨" });
          kinshipExtras.push({ slot:"brother_younger", label:"Younger brother", emoji:"👦" });
        }
        const allSlots = [...baseSlots, ...kinshipExtras];

        const handlePick = async (slot, file) => {
          if (!file) return;
          setPhotoError("");
          try {
            const dataUrl = await compressImageFile(file);
            setPhotoUploads(prev => ({ ...prev, [slot]: dataUrl }));
          } catch (e) {
            setPhotoError("Couldn't read that photo — try another.");
          }
        };

        const uploadedCount = Object.values(photoUploads).filter(Boolean).length;

        return (
          <>
            <p style={{fontFamily:"'Fredoka One','Baloo 2',cursive",fontSize:22,color:"#111",marginTop:18,marginBottom:8,textAlign:"center"}}>
              Add family photos for {name}
            </p>
            <div style={{maxWidth:360,fontFamily:"Nunito,sans-serif",fontWeight:700,fontSize:13,color:"#666",lineHeight:1.6,textAlign:"center",marginBottom:6}}>
              The first lesson is <strong>Family Members</strong>! Upload a photo for each word — when {name} sees the card, they'll see a familiar face instead of a generic icon.
            </div>
            <div style={{maxWidth:360,fontFamily:"Nunito,sans-serif",fontWeight:700,fontSize:12,color:RED,lineHeight:1.6,textAlign:"center",marginBottom:14}}>
              💛 This is the magic moment babies LOVE — they're learning to read AND to recognize the people they love at the same time.
            </div>

            <div style={{width:"100%",maxWidth:360,display:"grid",gridTemplateColumns:"repeat(3, 1fr)",gap:8,marginBottom:12}}>
              {baseSlots.map(s => {
                const photo = photoUploads[s.slot];
                return (
                  <div key={s.slot} style={{display:"flex",flexDirection:"column",alignItems:"center",gap:4}}>
                    <label style={{cursor:"pointer",position:"relative",width:"100%",aspectRatio:"1/1",borderRadius:12,overflow:"hidden",background:"#fff",border:photo?`2px solid ${RED}`:"2px dashed #ddd",display:"flex",alignItems:"center",justifyContent:"center"}}>
                      {photo ? (
                        <img src={photo} alt="" style={{width:"100%",height:"100%",objectFit:"cover"}}/>
                      ) : (
                        <div style={{display:"flex",flexDirection:"column",alignItems:"center",gap:2}}>
                          <span style={{fontSize:24,opacity:.5}}>{s.emoji}</span>
                          <span style={{fontSize:18,color:"#ccc"}}>+</span>
                        </div>
                      )}
                      <input type="file" accept="image/*"
                        onChange={e => { const f = e.target.files?.[0]; if (f) handlePick(s.slot, f); e.target.value = ""; }}
                        style={{position:"absolute",inset:0,opacity:0,cursor:"pointer"}}/>
                    </label>
                    <span style={{fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:11,color:"#666"}}>{s.label}</span>
                  </div>
                );
              })}
            </div>

            {kinshipExtras.length > 0 && (
              <>
                <div style={{maxWidth:360,padding:"8px 12px",background:"#FFF8F8",border:`1px dashed ${RED}55`,borderRadius:10,fontFamily:"Nunito,sans-serif",fontWeight:700,fontSize:10,color:"#777",lineHeight:1.5,marginBottom:8}}>
                  Since {name} is learning languages that distinguish older/younger siblings, you can add specific photos. Optional — the generic photos above will be used otherwise.
                </div>
                <div style={{width:"100%",maxWidth:360,display:"grid",gridTemplateColumns:"repeat(2, 1fr)",gap:8,marginBottom:12}}>
                  {kinshipExtras.map(s => {
                    const photo = photoUploads[s.slot];
                    return (
                      <div key={s.slot} style={{display:"flex",alignItems:"center",gap:8,padding:6,background:"#fff",border:photo?`2px solid ${RED}`:"1px dashed #ddd",borderRadius:10}}>
                        <label style={{cursor:"pointer",position:"relative",width:42,height:42,borderRadius:8,overflow:"hidden",background:"#fafafa",border:"1px solid #eee",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}>
                          {photo ? <img src={photo} alt="" style={{width:"100%",height:"100%",objectFit:"cover"}}/> : <span style={{fontSize:16,opacity:.5}}>{s.emoji}</span>}
                          <input type="file" accept="image/*"
                            onChange={e => { const f = e.target.files?.[0]; if (f) handlePick(s.slot, f); e.target.value = ""; }}
                            style={{position:"absolute",inset:0,opacity:0,cursor:"pointer"}}/>
                        </label>
                        <span style={{flex:1,fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:11,color:"#444",lineHeight:1.2}}>{s.label}</span>
                      </div>
                    );
                  })}
                </div>
              </>
            )}

            <div style={{maxWidth:360,padding:"10px 14px",background:"#F6F8FC",borderRadius:12,fontFamily:"Nunito,sans-serif",fontWeight:700,fontSize:11,color:"#666",lineHeight:1.55,marginBottom:6}}>
              📸 You can add more family photos (grandparents, aunts, uncles, etc.) anytime from {name}'s profile. Photos are stored on your device only — they never leave your phone. <strong>If you have multiple kids, photos transfer easily between profiles — no need to upload twice.</strong>
            </div>
            <p style={{maxWidth:360,fontFamily:"Nunito,sans-serif",fontWeight:700,fontSize:10,color:"#999",lineHeight:1.5,textAlign:"center",marginBottom:14,fontStyle:"italic"}}>
              Families come in all shapes — same-sex parents, single parents, foster families. Upload whoever feels right under "Mother" or "Father" — what matters is that {name} sees their loved ones.
            </p>

            {photoError && <p style={{fontFamily:"Nunito,sans-serif",fontWeight:700,fontSize:11,color:RED,marginBottom:8}}>{photoError}</p>}

            <div style={{display:"flex",gap:10,marginTop:8}}>
              <button onClick={()=>setStep(1.5)}
                style={{background:"#f5f5f5",border:"none",borderRadius:50,padding:"12px 22px",cursor:"pointer",fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:14,color:"#666"}}>
                ←
              </button>
              <button onClick={persistChildAndAdvance}
                style={{background:"#f5f5f5",border:"none",borderRadius:50,padding:"12px 22px",cursor:"pointer",fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:14,color:"#666"}}>
                skip for now
              </button>
              <button onClick={persistChildAndAdvance}
                style={{background:RED,border:"none",borderRadius:50,padding:"12px 26px",cursor:"pointer",fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:14,color:"#fff"}}>
                {uploadedCount > 0 ? `save ${uploadedCount} & continue →` : "continue →"}
              </button>
            </div>
          </>
        );
      })()}

      {step === 3 && (
        <>
          <div style={{fontSize:48,marginTop:20}}>{children[children.length-1]?.emoji}</div>
          <p style={{fontFamily:"'Fredoka One','Baloo 2',cursive",fontSize:22,color:"#111",marginTop:8,textAlign:"center"}}>
            {children[children.length-1]?.name} is all set!
          </p>
          <p style={{fontFamily:"Nunito,sans-serif",fontWeight:700,color:"#888",fontSize:14,marginTop:10,textAlign:"center",maxWidth:300,lineHeight:1.5}}>
            Want to add another little learner? You can always add more later.
          </p>

          <div style={{marginTop:14,display:"flex",flexWrap:"wrap",gap:8,justifyContent:"center",maxWidth:360}}>
            {children.map(c=>(
              <div key={c.id} style={{display:"flex",alignItems:"center",gap:6,background:"#FFF0F1",borderRadius:50,padding:"6px 14px",fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:13,color:RED}}>
                {c.emoji} {c.name}
              </div>
            ))}
          </div>

          <div style={{display:"flex",gap:10,marginTop:32}}>
            <button onClick={()=>setStep(1)}
              style={{background:"#f5f5f5",border:"none",borderRadius:50,padding:"13px 22px",cursor:"pointer",fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:14,color:"#666"}}>
              + add another
            </button>
            <button onClick={finish}
              style={{background:RED,border:"none",borderRadius:50,padding:"13px 32px",cursor:"pointer",fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:14,color:"#fff"}}>
              let's begin →
            </button>
          </div>
        </>
      )}
    </div>
  );
}

// ── LANGUAGE MULTI-PICKER (used in onboarding & child settings) ──────────────

function LanguageMultiPicker({ selected, onToggle, onClose, premium, onPremiumNeeded }) {
  const [q, setQ] = useState("");
  const filtered = LANGUAGES.filter(l=>l.toLowerCase().includes(q.toLowerCase()));
  // All languages are free. Premium unlocks multi-child accounts and custom
  // family photo libraries — language access itself is unrestricted.
  const handleTap = (lang) => {
    onToggle(lang);
  };

  return (
    <Sheet onClose={onClose}>
      <div style={{padding:"22px 22px 14px",borderBottom:"1px solid #f0f0f0"}}>
        <h2 style={{fontFamily:"'Fredoka One','Baloo 2',system-ui,sans-serif",fontSize:24,color:"#111",margin:"0 0 6px"}}>🌍 Languages</h2>
        <p style={{fontFamily:"Nunito,sans-serif",fontWeight:700,fontSize:12,color:"#aaa",marginBottom:10}}>
          Tap to add or remove. {selected.length} selected.
        </p>
        <input autoFocus value={q} onChange={e=>setQ(e.target.value)} placeholder="Search languages…"
          style={{width:"100%",padding:"10px 14px",borderRadius:12,border:"2px solid #eee",fontSize:15,fontFamily:"Nunito,sans-serif",fontWeight:700,outline:"none",boxSizing:"border-box"}}
          onFocus={e=>e.target.style.borderColor=RED} onBlur={e=>e.target.style.borderColor="#eee"}/>
      </div>
      <div style={{overflowY:"auto",flex:1,paddingBottom:16}}>
        {filtered.map(lang=>{
          const isSelected = selected.includes(lang);
          return (
            <button key={lang} onClick={()=>handleTap(lang)}
              style={{display:"flex",alignItems:"center",justifyContent:"space-between",width:"100%",textAlign:"left",padding:"12px 22px",border:"none",background:isSelected?"#FFF0F1":"transparent",color:isSelected?RED:"#333",fontFamily:"Nunito,sans-serif",fontWeight:700,fontSize:15,cursor:"pointer",borderLeft:isSelected?`4px solid ${RED}`:"4px solid transparent"}}>
              <span>{lang}</span>
              <span style={{fontSize:16}}>{isSelected?"✓":"+"}</span>
            </button>
          );
        })}
      </div>
      <div style={{padding:"12px 22px 20px",borderTop:"1px solid #f0f0f0"}}>
        <button onClick={onClose} style={{width:"100%",background:RED,border:"none",borderRadius:50,padding:"12px 22px",cursor:"pointer",fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:14,color:"#fff"}}>done</button>
      </div>
    </Sheet>
  );
}

// ── CHILD SWITCHER (the little pill showing active child + tap to switch) ────

function ChildSwitcher({ activeChild, onOpen }) {
  if (!activeChild) return null;
  return (
    <button onClick={onOpen}
      style={{display:"flex",alignItems:"center",gap:8,background:"#fff",border:"2px solid #f0f0f0",borderRadius:50,padding:"6px 14px 6px 6px",cursor:"pointer",fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:13,color:"#333",boxShadow:"0 2px 8px rgba(0,0,0,.04)"}}>
      {activeChild.avatarPhoto ? (
        <img src={activeChild.avatarPhoto} alt=""
          style={{width:28,height:28,borderRadius:"50%",objectFit:"cover",background:"#FFF0F1"}}/>
      ) : (
        <span style={{width:28,height:28,borderRadius:"50%",background:"#FFF0F1",display:"flex",alignItems:"center",justifyContent:"center",fontSize:16}}>{activeChild.emoji}</span>
      )}
      {activeChild.name}
      <span style={{fontSize:9,color:"#999",marginLeft:2}}>▼</span>
    </button>
  );
}

// ── CHILDREN MANAGEMENT SHEET ────────────────────────────────────────────────

function ChildrenSheet({ children, activeId, onSelect, onAddNew, onEdit, onShare, onSignOut, onClose }) {
  useParentLang();
  const [parentLang, setParentLangLocal] = useState(() => getParentLanguage() || "English");
  const [showParentLangPicker, setShowParentLangPicker] = useState(false);
  const [parentLangQuery, setParentLangQuery] = useState("");

  return (
    <Sheet onClose={onClose}>
      <div style={{padding:"22px 22px 14px",borderBottom:"1px solid #f0f0f0"}}>
        <h2 style={{fontFamily:"'Fredoka One','Baloo 2',system-ui,sans-serif",fontSize:24,color:"#111",margin:0}}>{t("Who's learning?")}</h2>
      </div>
      <div style={{overflowY:"auto",flex:1,padding:"10px 14px"}}>
        {children.map(c=>{
          const isActive = c.id === activeId;
          return (
            <div key={c.id} style={{display:"flex",alignItems:"center",gap:10,padding:"10px",borderRadius:14,background:isActive?"#FFF0F1":"transparent",marginBottom:4}}>
              <button onClick={()=>onSelect(c.id)}
                style={{flex:1,display:"flex",alignItems:"center",gap:12,background:"none",border:"none",cursor:"pointer",padding:"4px",textAlign:"left"}}>
                {c.avatarPhoto ? (
                  <img src={c.avatarPhoto} alt=""
                    style={{width:44,height:44,borderRadius:"50%",objectFit:"cover",border:isActive?`2px solid ${RED}`:"2px solid transparent",background:"#f5f5f5"}}/>
                ) : (
                  <span style={{width:44,height:44,borderRadius:"50%",background:isActive?"#fff":"#f5f5f5",display:"flex",alignItems:"center",justifyContent:"center",fontSize:24,border:isActive?`2px solid ${RED}`:"2px solid transparent"}}>{c.emoji}</span>
                )}
                <div>
                  <div style={{fontFamily:"'Fredoka One','Baloo 2',system-ui,sans-serif",fontSize:17,color:isActive?RED:"#111"}}>{c.name}</div>
                  <div style={{fontFamily:"Nunito,sans-serif",fontWeight:700,fontSize:11,color:"#aaa"}}>
                    {c.languages.length} {c.languages.length===1?"language":"languages"}
                  </div>
                </div>
                {isActive && <span style={{marginLeft:"auto",color:RED,fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:12}}>{t("active ✓")}</span>}
              </button>
              <button onClick={()=>onEdit(c)}
                style={{background:"none",border:"none",cursor:"pointer",fontSize:18,color:"#999",padding:"6px 8px"}}>
                ✎
              </button>
            </div>
          );
        })}

        {/* Parent's UI language preference. Shown after the children list so
            it's clear this is about the parent, not the children. Tapping
            opens a picker; selection persists across launches. */}
        <div style={{marginTop:18,padding:"14px 12px",background:"#FAFBFC",borderRadius:14,border:"1px solid #f0f0f0"}}>
          <div style={{fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:11,color:"#888",letterSpacing:.5,textTransform:"uppercase",marginBottom:6}}>
            {t("What you speak")}
          </div>
          <button onClick={()=>setShowParentLangPicker(true)}
            style={{width:"100%",display:"flex",alignItems:"center",justifyContent:"space-between",background:"#fff",border:"1.5px solid #eee",borderRadius:12,padding:"10px 14px",cursor:"pointer",fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:14,color:"#333"}}>
            <span style={{display:"flex",alignItems:"center",gap:8}}>
              <span style={{fontSize:16}}>{flagFor(parentLang)}</span>
              <span>{parentLang}</span>
            </span>
            <span style={{fontSize:11,color:"#bbb"}}>{t("change ▸")}</span>
          </button>
          <p style={{fontFamily:"Nunito,sans-serif",fontWeight:700,fontSize:10,color:"#aaa",lineHeight:1.4,marginTop:6,marginBottom:0}}>
            {t("Used as the default language when adding a new child.")}
          </p>
        </div>
      </div>
      <div style={{padding:"12px 22px 22px",borderTop:"1px solid #f0f0f0"}}>
        <button onClick={onAddNew}
          style={{width:"100%",background:"#f5f5f5",border:"2px dashed #ccc",borderRadius:50,padding:"12px 22px",cursor:"pointer",fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:14,color:"#555"}}>
          {t("+ add another child")}
        </button>
        <button onClick={onShare}
          style={{width:"100%",marginTop:8,background:"#FFF0F1",border:`2px solid ${RED}`,borderRadius:50,padding:"12px 22px",cursor:"pointer",fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:14,color:RED,display:"flex",alignItems:"center",justifyContent:"center",gap:6}}>
          {t("👨‍👩‍👧 Share with another caregiver")}
        </button>
        <button onClick={onSignOut}
          style={{width:"100%",marginTop:20,background:"#fff",border:"2px solid #eee",borderRadius:50,padding:"11px 22px",cursor:"pointer",fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:13,color:"#999",display:"flex",alignItems:"center",justifyContent:"center",gap:6}}>
          {t("⟲ Sign out")}
        </button>
      </div>

      {/* Parent's UI language picker — search + select */}
      {showParentLangPicker && (
        <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,.5)",zIndex:1000,display:"flex",alignItems:"flex-end",justifyContent:"center"}}
          onClick={()=>setShowParentLangPicker(false)}>
          <div onClick={e=>e.stopPropagation()}
            style={{width:"100%",maxWidth:480,maxHeight:"75vh",background:"#fff",borderTopLeftRadius:24,borderTopRightRadius:24,display:"flex",flexDirection:"column"}}>
            <div style={{padding:"22px 22px 12px",borderBottom:"1px solid #f0f0f0"}}>
              <h3 style={{fontFamily:"'Fredoka One','Baloo 2',system-ui,sans-serif",fontSize:20,color:"#111",margin:"0 0 4px"}}>
                What language do you speak?
              </h3>
              <p style={{fontFamily:"Nunito,sans-serif",fontWeight:700,fontSize:11,color:"#aaa",marginBottom:10}}>
                Used as the default for new children.
              </p>
              <input value={parentLangQuery} onChange={e=>setParentLangQuery(e.target.value)} placeholder="Search…"
                style={{width:"100%",padding:"10px 14px",borderRadius:12,border:"2px solid #eee",fontSize:14,fontFamily:"Nunito,sans-serif",fontWeight:700,outline:"none",boxSizing:"border-box"}}
                onFocus={e=>e.target.style.borderColor=RED} onBlur={e=>e.target.style.borderColor="#eee"}/>
            </div>
            <div style={{overflowY:"auto",flex:1,paddingBottom:10}}>
              {LANGUAGES
                .filter(l => l.toLowerCase().includes(parentLangQuery.toLowerCase()))
                .map(l => (
                  <button key={l} onClick={()=>{
                    setParentLangLocal(l);
                    setParentLanguage(l);
                    setShowParentLangPicker(false);
                  }}
                    style={{display:"flex",alignItems:"center",justifyContent:"space-between",width:"100%",textAlign:"left",padding:"11px 22px",border:"none",background:parentLang===l?"#FFF0F1":"transparent",color:parentLang===l?RED:"#333",fontFamily:"Nunito,sans-serif",fontWeight:700,fontSize:14,cursor:"pointer",borderLeft:parentLang===l?`4px solid ${RED}`:"4px solid transparent"}}>
                    <span style={{display:"flex",alignItems:"center",gap:10}}>
                      <span style={{fontSize:15}}>{flagFor(l)}</span>
                      <span>{l}</span>
                    </span>
                    {parentLang===l && <span style={{fontSize:14}}>✓</span>}
                  </button>
                ))}
            </div>
          </div>
        </div>
      )}
    </Sheet>
  );
}

// ── FAMILY SHARING SHEET ─────────────────────────────────────────────────────
// Export a family code (copy / share) so another caregiver can import it.

function FamilySharingSheet({ onImported, onClose }) {
  const [mode, setMode] = useState("menu"); // "menu" | "export" | "import"
  const [copied, setCopied] = useState(false);
  const [importText, setImportText] = useState("");
  const [importError, setImportError] = useState(null);
  const code = useMemo(()=>encodeFamilyCode(), [mode === "export"]);
  const shortCode = code.slice(0, 80) + (code.length > 80 ? "…" : "");

  const handleCopy = async () => {
    try {
      await navigator.clipboard.writeText(code);
      setCopied(true);
      setTimeout(()=>setCopied(false), 2000);
    } catch {
      // Fallback: select the text
      const ta = document.createElement("textarea");
      ta.value = code;
      document.body.appendChild(ta);
      ta.select();
      try { document.execCommand("copy"); setCopied(true); setTimeout(()=>setCopied(false), 2000); } catch {}
      document.body.removeChild(ta);
    }
  };

  const handleShare = async () => {
    const text = `Join our Limitless Babies family:\n\n${code}\n\nPaste this code in the app under "Share with another caregiver" → "I have a code".`;
    try {
      if (navigator.share) {
        await navigator.share({ text, title: "Limitless Babies family code" });
      } else {
        handleCopy();
      }
    } catch {}
  };

  const handleImport = () => {
    setImportError(null);
    const payload = decodeFamilyCode(importText);
    if (!payload) {
      setImportError("Code is invalid or corrupted. Check that you pasted the whole thing, including 'LB1-' at the start.");
      return;
    }
    applyFamilyPayload(payload);
    onImported(payload.kids.length);
  };

  return (
    <Sheet onClose={onClose}>
      <div style={{padding:"22px 22px 14px",borderBottom:"1px solid #f0f0f0"}}>
        <h2 style={{fontFamily:"'Fredoka One','Baloo 2',cursive",fontSize:24,color:"#111",margin:0}}>
          {mode==="menu" ? "👨‍👩‍👧 Family Sharing" : mode==="export" ? "Your family code" : "Paste a family code"}
        </h2>
        {mode==="menu" && (
          <p style={{fontFamily:"Nunito,sans-serif",fontWeight:700,fontSize:12,color:"#aaa",marginTop:6,lineHeight:1.5}}>
            Share profiles + progress with another caregiver (partner, au pair, grandparent).
          </p>
        )}
      </div>

      {mode === "menu" && (
        <div style={{overflowY:"auto",flex:1,padding:"12px 20px 28px"}}>
          <button onClick={()=>setMode("export")}
            style={{width:"100%",background:"#fff",border:"2px solid #f0f0f0",borderRadius:18,padding:"18px 18px",marginBottom:10,display:"flex",alignItems:"center",gap:14,cursor:"pointer",textAlign:"left"}}>
            <span style={{fontSize:28}}>📤</span>
            <div style={{flex:1}}>
              <div style={{fontFamily:"'Fredoka One','Baloo 2',cursive",fontSize:17,color:"#111"}}>{t("Share my family")}</div>
              <div style={{fontFamily:"Nunito,sans-serif",fontWeight:700,fontSize:12,color:"#aaa",marginTop:2}}>{t("Generate a code for another caregiver")}</div>
            </div>
            <span style={{fontSize:18,color:"#ddd"}}>›</span>
          </button>
          <button onClick={()=>setMode("import")}
            style={{width:"100%",background:"#fff",border:"2px solid #f0f0f0",borderRadius:18,padding:"18px 18px",display:"flex",alignItems:"center",gap:14,cursor:"pointer",textAlign:"left"}}>
            <span style={{fontSize:28}}>📥</span>
            <div style={{flex:1}}>
              <div style={{fontFamily:"'Fredoka One','Baloo 2',cursive",fontSize:17,color:"#111"}}>{t("I have a code")}</div>
              <div style={{fontFamily:"Nunito,sans-serif",fontWeight:700,fontSize:12,color:"#aaa",marginTop:2}}>Paste a code to load someone's family</div>
            </div>
            <span style={{fontSize:18,color:"#ddd"}}>›</span>
          </button>

          <div style={{marginTop:20,padding:"14px 16px",background:"#fafafa",borderRadius:14,fontFamily:"Nunito,sans-serif",fontWeight:700,fontSize:12,color:"#888",lineHeight:1.5}}>
            💡 Each caregiver's sessions sync when they import the latest code. For real-time sync across devices, a free account will be coming soon.
          </div>
        </div>
      )}

      {mode === "export" && (
        <div style={{overflowY:"auto",flex:1,padding:"16px 20px 24px"}}>
          <p style={{fontFamily:"Nunito,sans-serif",fontWeight:700,fontSize:13,color:"#666",lineHeight:1.5,marginBottom:12}}>
            Send this code to another caregiver. They'll open the app, tap "I have a code," and paste it in.
          </p>

          <div style={{background:"#fafafa",border:"2px solid #eee",borderRadius:14,padding:"12px 14px",marginBottom:12,wordBreak:"break-all",fontFamily:"ui-monospace,SFMono-Regular,monospace",fontSize:11,color:"#666",lineHeight:1.5,maxHeight:180,overflowY:"auto"}}>
            {code || "(unable to generate — try again)"}
          </div>

          <div style={{display:"flex",gap:8}}>
            <button onClick={handleCopy} disabled={!code}
              style={{flex:1,background:copied?"#2DC653":RED,border:"none",borderRadius:50,padding:"12px 18px",cursor:code?"pointer":"not-allowed",fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:14,color:"#fff",transition:"background .2s"}}>
              {copied ? "✓ Copied!" : "📋 Copy"}
            </button>
            <button onClick={handleShare} disabled={!code}
              style={{flex:1,background:"#f5f5f5",border:"2px solid #e8e8e8",borderRadius:50,padding:"12px 18px",cursor:code?"pointer":"not-allowed",fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:14,color:"#555"}}>
              📤 Share
            </button>
          </div>

          <button onClick={()=>setMode("menu")}
            style={{marginTop:14,width:"100%",background:"none",border:"none",cursor:"pointer",fontFamily:"Nunito,sans-serif",fontWeight:700,fontSize:13,color:"#aaa"}}>
            ← back
          </button>
        </div>
      )}

      {mode === "import" && (
        <div style={{overflowY:"auto",flex:1,padding:"16px 20px 24px"}}>
          <p style={{fontFamily:"Nunito,sans-serif",fontWeight:700,fontSize:13,color:"#666",lineHeight:1.5,marginBottom:12}}>
            Paste the family code you received. It starts with <strong>LB1-</strong>.
          </p>

          <textarea value={importText} onChange={e=>{setImportText(e.target.value); setImportError(null);}}
            placeholder="LB1-eyJ2..."
            style={{width:"100%",minHeight:120,padding:"12px 14px",borderRadius:14,border:`2px solid ${importError?RED:"#eee"}`,fontSize:12,fontFamily:"ui-monospace,SFMono-Regular,monospace",outline:"none",boxSizing:"border-box",resize:"vertical",lineHeight:1.5}}/>

          {importError && (
            <div style={{marginTop:10,padding:"10px 12px",background:"#FFF0F1",borderRadius:10,fontFamily:"Nunito,sans-serif",fontWeight:700,fontSize:12,color:RED,lineHeight:1.5}}>
              {importError}
            </div>
          )}

          <button onClick={handleImport} disabled={!importText.trim()}
            style={{marginTop:14,width:"100%",background:importText.trim()?RED:"#ddd",border:"none",borderRadius:50,padding:"13px 22px",cursor:importText.trim()?"pointer":"not-allowed",fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:14,color:"#fff"}}>
            Import family
          </button>

          <button onClick={()=>setMode("menu")}
            style={{marginTop:14,width:"100%",background:"none",border:"none",cursor:"pointer",fontFamily:"Nunito,sans-serif",fontWeight:700,fontSize:13,color:"#aaa"}}>
            ← back
          </button>
        </div>
      )}
    </Sheet>
  );
}

// ── CHILD EDITOR SHEET (add new or edit existing) ────────────────────────────

// ── POST-SESSION AD ──────────────────────────────────────────────────────────
// JIT (just-in-time) photo upload sheet shown right before the Locations
// set (M2 Set 28: kitchen/bedroom/bathroom/livingroom/garden) is presented
// to the child. Lets the parent quickly upload photos of their actual
// home — much more meaningful for word-association than stock photos.
//
// Skipping is fine: stock photos are used as a fallback. The prompt is
// shown once per child; after that the parent can manage these photos
// from ChildEditor (same UI as family photos).
//
// Includes a "copy to other children" step for families with siblings —
// upload once, push to all kids in the family.
function LocationPhotoPrompt({ child, otherChildren, onClose }) {
  const [photos, setPhotos] = useState(() => {
    const all = getFamilyPhotos(child.id);
    return Object.fromEntries(LOCATION_PHOTO_WORDS.map(w => [w, all[w] || null]));
  });
  const [error, setError] = useState("");
  const [showCopyStep, setShowCopyStep] = useState(false);
  const [copyTargets, setCopyTargets] = useState({}); // childId -> bool

  const handleUpload = async (word, file) => {
    if (!file) return;
    if (file.size > 4 * 1024 * 1024) {
      setError("Photo too large — please use one under 4 MB.");
      return;
    }
    try {
      const reader = new FileReader();
      reader.onload = e => {
        const dataUrl = e.target?.result;
        if (typeof dataUrl !== "string") return;
        const ok = setFamilyPhoto(child.id, word, dataUrl);
        if (!ok) {
          setError("Storage is full — try removing photos in another profile first.");
          return;
        }
        setPhotos(p => ({ ...p, [word]: dataUrl }));
        setError("");
      };
      reader.readAsDataURL(file);
    } catch {
      setError("Couldn't read that file — try a different photo.");
    }
  };

  const handleRemove = (word) => {
    try {
      const all = getFamilyPhotos(child.id);
      delete all[word];
      localStorage.setItem(`lb-photos-${child.id}`, JSON.stringify(all));
      setPhotos(p => ({ ...p, [word]: null }));
    } catch {}
  };

  const uploadedCount = LOCATION_PHOTO_WORDS.filter(w => photos[w]).length;
  const hasOtherChildren = otherChildren && otherChildren.length > 0;

  const handleDoneOrCopy = () => {
    if (uploadedCount > 0 && hasOtherChildren && !showCopyStep) {
      // Step 2: offer to copy to siblings
      setShowCopyStep(true);
    } else {
      onClose();
    }
  };

  const handleCopyAndClose = () => {
    // Copy uploaded location photos to selected siblings
    try {
      const targetIds = Object.keys(copyTargets).filter(id => copyTargets[id]);
      let copied = 0;
      targetIds.forEach(otherId => {
        const otherCurrent = getFamilyPhotos(otherId);
        let changed = false;
        LOCATION_PHOTO_WORDS.forEach(w => {
          if (photos[w] && !otherCurrent[w]) {
            otherCurrent[w] = photos[w];
            changed = true;
          }
        });
        if (changed) {
          localStorage.setItem(`lb-photos-${otherId}`, JSON.stringify(otherCurrent));
          copied++;
        }
      });
    } catch {}
    onClose();
  };

  return (
    <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,.55)",zIndex:310,display:"flex",alignItems:"center",justifyContent:"center",padding:20}}>
      <div style={{background:"#fff",borderRadius:24,padding:"24px 22px",maxWidth:420,width:"100%",maxHeight:"90vh",overflowY:"auto",boxShadow:"0 16px 48px rgba(0,0,0,.3)",position:"relative"}}>
        {!showCopyStep && (
          <>
            <div style={{position:"absolute",top:10,right:14,fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:9,color:"#bbb",letterSpacing:.5,textTransform:"uppercase"}}>{t("Optional")}</div>
            <div style={{fontSize:42,textAlign:"center",marginBottom:6}}>🏠</div>
            <h3 style={{fontFamily:"'Fredoka One','Baloo 2',cursive",fontSize:21,color:"#111",margin:"0 0 8px",textAlign:"center",lineHeight:1.2}}>
              {t("Show your home")}
            </h3>
            <p style={{fontFamily:"Nunito,sans-serif",fontWeight:700,fontSize:12,color:"#666",lineHeight:1.5,textAlign:"center",margin:"0 0 16px"}}>
              {t("Today's set is Locations. Upload photos of your actual rooms so {childName} learns the words with your home as the anchor — much more meaningful than stock photos.").replace("{childName}", child.name || "your child")}
            </p>

            <div style={{display:"grid",gridTemplateColumns:"repeat(3, 1fr)",gap:8,marginBottom:14}}>
              {LOCATION_PHOTO_WORDS.map(word => {
                const photo = photos[word];
                const labelMap = { livingroom: "living room", kitchen: "kitchen", bedroom: "bedroom", bathroom: "bathroom", garden: "garden" };
                return (
                  <div key={word} style={{display:"flex",flexDirection:"column",alignItems:"center",gap:4}}>
                    <label style={{cursor:"pointer",position:"relative",width:"100%",aspectRatio:"1/1",borderRadius:12,overflow:"hidden",background:"#fff",border:photo?`2px solid ${RED}`:"2px dashed #ddd",display:"flex",alignItems:"center",justifyContent:"center"}}>
                      {photo ? (
                        <img src={photo} alt={word} style={{width:"100%",height:"100%",objectFit:"cover"}}/>
                      ) : (
                        <span style={{fontSize:22,color:"#ccc"}}>+</span>
                      )}
                      <input type="file" accept="image/*"
                        onChange={e => { const f = e.target.files?.[0]; if (f) handleUpload(word, f); e.target.value = ""; }}
                        style={{position:"absolute",inset:0,opacity:0,cursor:"pointer"}}/>
                    </label>
                    <div style={{display:"flex",alignItems:"center",gap:4,fontSize:10,fontFamily:"Nunito,sans-serif",fontWeight:800,color:"#666"}}>
                      <span>{labelMap[word] || word}</span>
                      {photo && (
                        <button onClick={()=>handleRemove(word)}
                          style={{background:"none",border:"none",padding:0,cursor:"pointer",color:"#c44",fontSize:12,lineHeight:1}}>×</button>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>

            {error && (
              <div style={{padding:"6px 10px",background:"#FFF0F0",borderRadius:8,fontFamily:"Nunito,sans-serif",fontWeight:700,fontSize:11,color:"#c44",marginBottom:10}}>
                {error}
              </div>
            )}

            <button onClick={handleDoneOrCopy}
              style={{width:"100%",background:RED,border:"none",borderRadius:50,padding:"12px",cursor:"pointer",fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:14,color:"#fff",boxShadow:"0 4px 14px rgba(232,25,44,.25)"}}>
              {uploadedCount > 0
                ? (hasOtherChildren ? t("next: copy to other kids →") : t("done →"))
                : t("skip — use stock photos")}
            </button>

            <p style={{fontFamily:"Nunito,sans-serif",fontWeight:700,fontSize:10,color:"#aaa",lineHeight:1.4,textAlign:"center",margin:"10px 0 0"}}>
              {t("You can manage these later from your child's profile.")}
            </p>
          </>
        )}

        {showCopyStep && (
          <>
            <div style={{position:"absolute",top:10,right:14,fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:9,color:"#bbb",letterSpacing:.5,textTransform:"uppercase"}}>{t("Step 2 of 2")}</div>
            <div style={{fontSize:42,textAlign:"center",marginBottom:6}}>👨‍👩‍👧‍👦</div>
            <h3 style={{fontFamily:"'Fredoka One','Baloo 2',cursive",fontSize:20,color:"#111",margin:"0 0 8px",textAlign:"center",lineHeight:1.2}}>
              {t("Copy to siblings?")}
            </h3>
            <p style={{fontFamily:"Nunito,sans-serif",fontWeight:700,fontSize:12,color:"#666",lineHeight:1.5,textAlign:"center",margin:"0 0 14px"}}>
              {t("Save time by copying these home photos to your other children's profiles. They share the same home, after all.")}
            </p>

            <div style={{display:"flex",flexDirection:"column",gap:6,marginBottom:14}}>
              {otherChildren.map(other => {
                const checked = !!copyTargets[other.id];
                return (
                  <label key={other.id}
                    style={{display:"flex",alignItems:"center",gap:10,padding:"10px 12px",background:checked?"#FFF6F7":"#f8f8f8",border:`2px solid ${checked?RED:"#eee"}`,borderRadius:10,cursor:"pointer"}}>
                    <input type="checkbox" checked={checked}
                      onChange={()=>setCopyTargets(t=>({...t, [other.id]: !t[other.id]}))}
                      style={{accentColor:RED, width:16, height:16}}/>
                    <span style={{fontSize:20}}>{other.emoji || "👶"}</span>
                    <span style={{fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:14,color:"#111"}}>{other.name}</span>
                  </label>
                );
              })}
            </div>

            <button onClick={handleCopyAndClose}
              style={{width:"100%",background:RED,border:"none",borderRadius:50,padding:"12px",cursor:"pointer",fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:14,color:"#fff",boxShadow:"0 4px 14px rgba(232,25,44,.25)"}}>
              {Object.values(copyTargets).some(v => v) ? t("copy & continue →") : t("skip — continue →")}
            </button>
          </>
        )}
      </div>
    </div>
  );
}


// One-shot prompt shown after the parent completes their first full Day 1
// (3 sessions in any category). Reminds them to upload extended-family
// photos because grandma/grandpa/aunt/uncle appear in the curriculum
// around Day 30 — about a month away. Pre-uploading means those photos
// are ready to go when the curriculum reaches them.
// JIT prompt shown right before M3 sentences set 12 ("I love sentences")
// begins, asking the parent to upload a single group photo of the family.
// Same storage model as other family photos (setFamilyPhoto under slot
// "family"), same one-shot-flag pattern (`lb-family-group-prompt-shown-{id}`).
//
// Why this exists: the sentence "I love my family." doesn't map to any
// individual person, so without a dedicated group photo it falls through
// to a generic family emoji. A real photo of the whole family — even a
// candid phone shot — turns the card into something the baby actually
// recognizes and bonds with.
function FamilyGroupPhotoPrompt({ child, onClose }) {
  const [photo, setPhoto] = useState(() => {
    const all = getFamilyPhotos(child.id);
    return all.family || null;
  });
  const [error, setError] = useState("");

  const handleUpload = async (file) => {
    if (!file) return;
    if (file.size > 4 * 1024 * 1024) {
      setError("Photo too large — please use one under 4 MB.");
      return;
    }
    try {
      const reader = new FileReader();
      reader.onload = e => {
        const dataUrl = e.target?.result;
        if (typeof dataUrl !== "string") return;
        const ok = setFamilyPhoto(child.id, "family", dataUrl);
        if (!ok) {
          setError("Storage is full — try removing photos in another profile first.");
          return;
        }
        setPhoto(dataUrl);
        setError("");
      };
      reader.readAsDataURL(file);
    } catch {
      setError("Couldn't read that file — try a different photo.");
    }
  };

  const handleRemove = () => {
    try {
      const all = getFamilyPhotos(child.id);
      delete all.family;
      localStorage.setItem(`lb-photos-${child.id}`, JSON.stringify(all));
      setPhoto(null);
    } catch {}
  };

  return (
    <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,.55)",zIndex:340,display:"flex",alignItems:"center",justifyContent:"center",padding:14}}>
      <div style={{background:"#fff",borderRadius:24,maxWidth:440,width:"100%",maxHeight:"92vh",display:"flex",flexDirection:"column",overflow:"hidden",boxShadow:"0 20px 50px rgba(0,0,0,.35)"}}>

        <div style={{padding:"24px 22px 14px",background:"linear-gradient(180deg,#FFF6E5 0%,#fff 100%)"}}>
          <div style={{fontSize:42,textAlign:"center",marginBottom:6}}>👨‍👩‍👧‍👦</div>
          <h2 style={{fontFamily:"'Fredoka One','Baloo 2',cursive",fontSize:21,color:"#111",margin:"0 0 6px",textAlign:"center",lineHeight:1.15}}>
            A photo of your whole family
          </h2>
          <p style={{fontFamily:"Nunito,sans-serif",fontWeight:700,fontSize:12,color:"#666",textAlign:"center",margin:0,lineHeight:1.5}}>
            {child.name}'s next set has the sentence <strong>"I love my family."</strong> — a real photo of everyone together makes this card click. Even a candid phone shot works.
          </p>
        </div>

        <div style={{flex:1,overflowY:"auto",padding:"4px 22px 18px",display:"flex",flexDirection:"column",alignItems:"center"}}>
          <label style={{cursor:"pointer",position:"relative",width:200,height:200,borderRadius:20,overflow:"hidden",background:"#fff",border:photo?`3px solid ${RED}`:"3px dashed #ddd",display:"flex",alignItems:"center",justifyContent:"center",margin:"14px 0 10px"}}>
            {photo ? (
              <img src={photo} alt="" style={{width:"100%",height:"100%",objectFit:"cover"}}/>
            ) : (
              <div style={{textAlign:"center",padding:14}}>
                <div style={{fontSize:36,marginBottom:6}}>📸</div>
                <div style={{fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:12,color:"#888",lineHeight:1.4}}>tap to upload</div>
              </div>
            )}
            <input type="file" accept="image/*" style={{display:"none"}}
              onChange={e => handleUpload(e.target.files?.[0])}/>
          </label>

          {photo && (
            <button onClick={handleRemove}
              style={{background:"transparent",border:"none",cursor:"pointer",fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:11,color:"#888",textDecoration:"underline",padding:"4px 8px",marginBottom:6}}>
              remove photo
            </button>
          )}

          {error && (
            <div style={{padding:"8px 12px",background:"#FFF0F0",borderRadius:8,fontFamily:"Nunito,sans-serif",fontWeight:700,fontSize:11,color:"#c44",lineHeight:1.4,marginBottom:10,textAlign:"center"}}>
              {error}
            </div>
          )}

          <div style={{display:"flex",gap:8,width:"100%",marginTop:6}}>
            <button onClick={onClose}
              style={{flex:1,background:"#f5f5f5",border:"none",borderRadius:50,padding:"12px",cursor:"pointer",fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:12,color:"#666"}}>
              {photo ? "skip rest" : "skip for now"}
            </button>
            <button onClick={onClose}
              style={{flex:2,background:photo?"#10b981":RED,border:"none",borderRadius:50,padding:"12px",cursor:"pointer",fontFamily:"Nunito,sans-serif",fontWeight:800,fontSize:13,color:"#fff",boxShadow:photo?"0 4px 14px rgba(16,185,129,.25)":"0 4px 14px rgba(232,25,44,.25)"}}>
              {photo ? "✓ done — start session" : "start session"}
            </button>
          </div>

          <p style={{fontFamily:"Nunito,sans-serif",fontWeight:700,fontSize:10,color:"#aaa",lineHeight:1.45,textAlign:"center",margin:"12px 0 0",fontStyle:"italic"}}>
            You can always add this later from Parent Profile if you skip now.
          </p>
        </div>
      </div>
    </div>
  );
}

